INSERT INTO public.questions (id, exercise_id, prompt, options, correct_option, explanation, display_order) VALUES
  ('0f463adf-346b-56d6-9071-457cd9bd6c0a', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'أيّ من الأعداد التالية عددٌ صمّاء (غير ناطق)؟', '[{"id":"a","text":"√16"},{"id":"b","text":"√7"},{"id":"c","text":"0.25"},{"id":"d","text":"−4/3"}]'::jsonb, 'b', '√16 = 4 عدد ناطق، و0.25 = 1/4 ناطق، و−4/3 كسر ناطق. أمّا √7 فجذر عدد ليس مربّعًا كاملًا، إذن هو عدد صمّاء.', 1),
  ('6fbcfc1b-1b2d-58d7-b16b-bdf0c6069898', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما ناتج العملية: (−2)³ + (−5) × (−3) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"23"},{"id":"c","text":"−23"},{"id":"d","text":"1"}]'::jsonb, 'a', 'نحسب القوّة أوّلًا: (−2)³ = −8، ثمّ الضرب: (−5) × (−3) = 15. أخيرًا الجمع: −8 + 15 = 7. التحقّق: −8 + 15 = 7 ✓.', 2),
  ('35e76788-e657-5be4-b93d-43064799b43d', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'ما قيمة |2 − 9| + |−3| ؟', '[{"id":"a","text":"10"},{"id":"b","text":"4"},{"id":"c","text":"−4"},{"id":"d","text":"−10"}]'::jsonb, 'a', '2 − 9 = −7 إذن |2 − 9| = 7، و|−3| = 3. المجموع = 7 + 3 = 10. القيمة المطلقة دائمًا موجبة أو معدومة.', 3),
  ('d51ef99d-e6b4-5655-b4fc-8c69e0cd2e97', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'أيّ عدد ينتمي إلى المجال ]−2 ، 5] ؟', '[{"id":"a","text":"5"},{"id":"b","text":"−2"},{"id":"c","text":"6"},{"id":"d","text":"−3"}]'::jsonb, 'a', 'المجال ]−2 ، 5] يعني −2 < x ≤ 5: الحدّ −2 غير مشمول (قوس متّجه للخارج) و5 مشمول. إذن 5 ينتمي، بينما −2 لا (مستثنى)، و6 و−3 خارج المجال.', 4),
  ('0b9aed72-616e-58c5-abc9-9a362e2cff71', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'رتّب الأعداد التالية تصاعديًّا: √2 ، 1 ، 1.5 ، √3 . ما الترتيب الصحيح؟', '[{"id":"a","text":"1 < √2 < 1.5 < √3"},{"id":"b","text":"1 < 1.5 < √2 < √3"},{"id":"c","text":"√2 < 1 < √3 < 1.5"},{"id":"d","text":"1 < √3 < √2 < 1.5"}]'::jsonb, 'a', '√2 ≈ 1.414 و√3 ≈ 1.732. إذن الترتيب التصاعدي: 1 < 1.414 < 1.5 < 1.732، أي 1 < √2 < 1.5 < √3.', 5),
  ('a930d86d-1fb6-548b-a1ad-81bbae7bb2b8', '5a3f4734-6b04-5f4d-b50e-a9e60566ce77', 'إذا كان a < b وc عدد سالب (c < 0)، فأيّ عبارة صحيحة دائمًا؟', '[{"id":"a","text":"a × c > b × c"},{"id":"b","text":"a × c < b × c"},{"id":"c","text":"a + c > b + c"},{"id":"d","text":"a × c = b × c"}]'::jsonb, 'a', 'الضرب في عدد سالب يقلب اتّجاه المتراجحة: من a < b نحصل على a × c > b × c. مثال: 2 < 3 و c = −1 تعطي −2 > −3 ✓. أمّا الجمع (الخيار c) فيحفظ الترتيب فيكون a + c < b + c.', 6),
  ('c4908721-72aa-51ae-8b71-e22a8b633ea4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'أبسّط √98 :', '[{"id":"a","text":"7√2"},{"id":"b","text":"49√2"},{"id":"c","text":"2√7"},{"id":"d","text":"14√2"}]'::jsonb, 'a', 'نحلّل 98 إلى جداء مربّع كامل: 98 = 49 × 2. إذن √98 = √(49 × 2) = √49 × √2 = 7√2. التحقّق: (7√2)² = 49 × 2 = 98 ✓.', 1),
  ('c26c3dc4-2755-56a0-9961-ea04bd7ee7c4', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة √50 − √18 ؟', '[{"id":"a","text":"2√2"},{"id":"b","text":"√32"},{"id":"c","text":"8√2"},{"id":"d","text":"√2"}]'::jsonb, 'a', 'نبسّط: √50 = √(25×2) = 5√2 و√18 = √(9×2) = 3√2. إذن √50 − √18 = 5√2 − 3√2 = 2√2. الخيار (b) خطأ لأنّ √a − √b ≠ √(a−b).', 2),
  ('32c26bd5-1576-575b-ae80-09b2672b01e1', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'اُنطق مقام الكسر 10/√5 (اكتبه بدون جذر في المقام):', '[{"id":"a","text":"2√5"},{"id":"b","text":"10√5"},{"id":"c","text":"√5"},{"id":"d","text":"√5/2"}]'::jsonb, 'a', 'نضرب البسط والمقام في √5: (10 × √5) / (√5 × √5) = 10√5 / 5 = 2√5. التحقّق: 2√5 = 2√5، ومربّعه (2√5)²=20 و(10/√5)²=100/5=20 ✓.', 3),
  ('1549de7d-0f12-56b6-9248-0b5c3af6058d', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة √((−7)²) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"−7"},{"id":"c","text":"49"},{"id":"d","text":"−49"}]'::jsonb, 'a', '(−7)² = 49 ثمّ √49 = 7. وبصفة عامّة √(a²) = |a|، و|−7| = 7. الجذر التربيعي لا يُعطي أبدًا قيمة سالبة.', 4),
  ('e6a56b2b-f341-5e7c-aab5-a7874fe60fdf', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'ما قيمة (3 + √5)(3 − √5) ؟', '[{"id":"a","text":"4"},{"id":"b","text":"9 + √5"},{"id":"c","text":"14"},{"id":"d","text":"6"}]'::jsonb, 'a', 'هذا فرق مربّعين: (a+b)(a−b) = a² − b² مع a = 3 وb = √5. إذن = 3² − (√5)² = 9 − 5 = 4.', 5),
  ('f9527c06-59ec-5c8d-9092-411f79da8814', '35382d30-ed80-5e0e-b5ce-46da877152cf', 'مربّع مساحته 72 cm². ما طول ضلعه بالصورة المبسّطة؟', '[{"id":"a","text":"6√2 cm"},{"id":"b","text":"36 cm"},{"id":"c","text":"8√2 cm"},{"id":"d","text":"2√6 cm"}]'::jsonb, 'a', 'ضلع المربّع = √(المساحة) = √72. نبسّط: √72 = √(36×2) = 6√2 cm. التحقّق: (6√2)² = 36×2 = 72 ✓. أمّا 8√2 فمربّعه 128، و2√6 فمربّعه 24، وكلاهما خطأ.', 6),
  ('37fc9894-1858-5cf0-b712-b7ad9b3b4aab', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'انشر وبسّط العبارة: (x − 4)(x + 4) ؟', '[{"id":"a","text":"x² − 16"},{"id":"b","text":"x² + 16"},{"id":"c","text":"x² − 8x − 16"},{"id":"d","text":"x² − 8"}]'::jsonb, 'a', 'هذا فرق مربّعين: (a − b)(a + b) = a² − b² مع a = x وb = 4. إذن (x − 4)(x + 4) = x² − 4² = x² − 16.', 1),
  ('2df687dd-026a-5241-a911-ef698f832390', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'انشر العبارة: (2x − 3)² ؟', '[{"id":"a","text":"4x² − 12x + 9"},{"id":"b","text":"4x² + 9"},{"id":"c","text":"2x² − 12x + 9"},{"id":"d","text":"4x² − 6x + 9"}]'::jsonb, 'a', 'مربّع الفرق: (a − b)² = a² − 2ab + b² مع a = 2x وb = 3. إذن (2x)² − 2(2x)(3) + 3² = 4x² − 12x + 9. الخيار (b) نسي الحدّ الأوسط −12x.', 2),
  ('d7817946-d5ac-52f9-bf22-b14019574756', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل العبارة: 3x² − 12 ؟', '[{"id":"a","text":"3(x − 2)(x + 2)"},{"id":"b","text":"3(x² − 12)"},{"id":"c","text":"(3x − 12)(x + 1)"},{"id":"d","text":"3(x − 4)(x + 4)"}]'::jsonb, 'a', 'نُخرج العامل المشترك 3 أوّلًا: 3x² − 12 = 3(x² − 4). ثمّ x² − 4 = x² − 2² فرق مربّعين = (x − 2)(x + 2). النتيجة: 3(x − 2)(x + 2).', 3),
  ('511c23a6-5988-581b-8e8b-93cd092ff15b', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'احسب 99² باستخدام المتطابقات الشهيرة:', '[{"id":"a","text":"9801"},{"id":"b","text":"9999"},{"id":"c","text":"9601"},{"id":"d","text":"9802"}]'::jsonb, 'a', '99² = (100 − 1)² = 100² − 2(100)(1) + 1² = 10000 − 200 + 1 = 9801.', 4),
  ('d4cb0049-893e-5942-a530-94978dcf447e', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'عمّل العبارة: x² + 6x + 9 − y² ؟', '[{"id":"a","text":"(x + 3 − y)(x + 3 + y)"},{"id":"b","text":"(x + 3)² − y"},{"id":"c","text":"(x + 3 − y)²"},{"id":"d","text":"(x − 3 − y)(x − 3 + y)"}]'::jsonb, 'a', 'نلاحظ x² + 6x + 9 = (x + 3)². إذن العبارة = (x + 3)² − y² وهي فرق مربّعين: = (x + 3 − y)(x + 3 + y).', 5),
  ('b79c3d7d-ad1b-51f3-9991-0921a0bcdb85', '8ff9339c-4dff-5e50-8d90-19f86c7e2709', 'ما قيمة العبارة 2(a + b)² − 2(a − b)² ؟', '[{"id":"a","text":"8ab"},{"id":"b","text":"4ab"},{"id":"c","text":"0"},{"id":"d","text":"4a² + 4b²"}]'::jsonb, 'a', '(a + b)² = a² + 2ab + b² و(a − b)² = a² − 2ab + b². الفرق (a+b)² − (a−b)² = 4ab. نضرب في 2: 2 × 4ab = 8ab.', 6),
  ('2e19be12-fd67-5acc-8f8f-2750647b9e20', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المعادلة: 3(x − 2) + 5 = 2x + 4 ؟', '[{"id":"a","text":"x = 5"},{"id":"b","text":"x = 3"},{"id":"c","text":"x = −5"},{"id":"d","text":"x = 1"}]'::jsonb, 'a', 'نوسّع: 3x − 6 + 5 = 2x + 4 → 3x − 1 = 2x + 4 → 3x − 2x = 4 + 1 → x = 5. التحقّق: 3(3) + 5 = 14 و2(5) + 4 = 14 ✓.', 1),
  ('aada6349-d934-5bf6-a045-ecf7ed9f2cf2', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما مجموعة حلول المعادلة: (x − 5)(2x + 6) = 0 ؟', '[{"id":"a","text":"{ 5 ، −3 }"},{"id":"b","text":"{ 5 ، 3 }"},{"id":"c","text":"{ −5 ، −3 }"},{"id":"d","text":"{ −5 ، 6 }"}]'::jsonb, 'a', 'جداء معدوم: إمّا x − 5 = 0 فـ x = 5، أو 2x + 6 = 0 أي 2x = −6 فـ x = −3. مجموعة الحلول {5 ، −3}.', 2),
  ('aee6b3c0-1493-5bf3-bca1-1abcffee50ba', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 3x − 7 < x + 5 ؟', '[{"id":"a","text":"x < 6"},{"id":"b","text":"x > 6"},{"id":"c","text":"x < 1"},{"id":"d","text":"x > −6"}]'::jsonb, 'a', '3x − 7 < x + 5 → 3x − x < 5 + 7 → 2x < 12 → نقسم على 2 (موجب) → x < 6. لا قلب للإشارة لأنّ المعامل موجب.', 3),
  ('2f101f79-1a67-5b75-8189-bfc10cd9385e', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ضعف عدد مزيدًا بـ 7 يساوي 23. ما هو العدد؟', '[{"id":"a","text":"8"},{"id":"b","text":"15"},{"id":"c","text":"30"},{"id":"d","text":"16"}]'::jsonb, 'a', 'نُسمّي العدد x. المعادلة: 2x + 7 = 23 → 2x = 16 → x = 8. التحقّق: 2(8) + 7 = 23 ✓.', 4),
  ('704d9e48-2a96-5829-9890-9ba9ac687b65', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما حلّ المتراجحة: 4 − 3x ≥ 19 ؟', '[{"id":"a","text":"x ≤ −5"},{"id":"b","text":"x ≥ −5"},{"id":"c","text":"x ≤ 5"},{"id":"d","text":"x ≥ 5"}]'::jsonb, 'a', '4 − 3x ≥ 19 → −3x ≥ 15 → نقسم على −3 مع قلب الإشارة → x ≤ −5. التحقّق بـ x = −5: 4 − 3(−5) = 19 ≥ 19 ✓.', 5),
  ('0bd527cf-ae89-582d-9e03-767d3ff59e49', '4ecb8934-3502-5adb-992e-c122da2e6fec', 'ما مجموعة الأعداد الصحيحة x التي تحقّق في آنٍ واحد: x > −2 و2x ≤ 6 ؟', '[{"id":"a","text":"{ −1 ، 0 ، 1 ، 2 ، 3 }"},{"id":"b","text":"{ −2 ، −1 ، 0 ، 1 ، 2 ، 3 }"},{"id":"c","text":"{ 0 ، 1 ، 2 ، 3 }"},{"id":"d","text":"{ −1 ، 0 ، 1 ، 2 }"}]'::jsonb, 'a', 'من x > −2 نأخذ x ابتداءً من −1 (لأنّ −2 غير مشمول). من 2x ≤ 6 نجد x ≤ 3. إذن −1 ≤ x ≤ 3، والأعداد الصحيحة هي {−1 ، 0 ، 1 ، 2 ، 3}.', 6),
  ('41b9a5da-4e9d-5d8d-ab7a-21ca292f7a7f', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} x + y = 10 \\ x - y = 4 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(7 ; 3)"},{"id":"b","text":"(3 ; 7)"},{"id":"c","text":"(6 ; 4)"},{"id":"d","text":"(5 ; 5)"}]'::jsonb, 'a', 'بجمع المعادلتَين: (x+y) + (x−y) = 10 + 4 → 2x = 14 → x = 7. نعوّض في الأولى: 7 + y = 10 → y = 3. الحلّ (7 ; 3). التحقّق: 7+3=10 ✓، 7−3=4 ✓.', 1),
  ('225fa409-a808-5f60-bb79-965b5551c2e1', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} 5x + 4y = 22 \\ 5x - 2y = 4 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(2 ; 3)"},{"id":"b","text":"(3 ; 2)"},{"id":"c","text":"(4 ; 1)"},{"id":"d","text":"(1 ; 4)"}]'::jsonb, 'a', 'نطرح الثانية من الأولى: (5x+4y) − (5x−2y) = 22 − 4 → 6y = 18 → y = 3. نعوّض في الثانية: 5x − 6 = 4 → 5x = 10 → x = 2. الحلّ (2 ; 3). التحقّق: 10+12=22 ✓، 10−6=4 ✓.', 2),
  ('3997fe38-e3c1-58e6-9b17-48df8325d664', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل بطريقة التعويض:
$$\begin{cases} y = 2x - 1 \\ 3x + y = 14 \end{cases}$$
ما هو الحلّ؟', '[{"id":"a","text":"(3 ; 5)"},{"id":"b","text":"(5 ; 9)"},{"id":"c","text":"(2 ; 3)"},{"id":"d","text":"(4 ; 7)"}]'::jsonb, 'a', 'نعوّض y = 2x − 1 في الثانية: 3x + (2x − 1) = 14 → 5x − 1 = 14 → 5x = 15 → x = 3. ثمّ y = 2(3) − 1 = 5. الحلّ (3 ; 5). التحقّق: y=5=2(3)−1 ✓، 3(3)+5=14 ✓.', 3),
  ('4efc2de5-4561-5d33-96c8-d0137259f75f', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'مجموع عددين 30 والفرق بينهما 8. ما هو العدد الأكبر؟', '[{"id":"a","text":"19"},{"id":"b","text":"11"},{"id":"c","text":"22"},{"id":"d","text":"15"}]'::jsonb, 'a', 'نُسمّي العددين x وy مع x > y. الجملة: x + y = 30 وx − y = 8. بالجمع: 2x = 38 → x = 19. إذن y = 11. العدد الأكبر 19. التحقّق: 19+11=30 ✓، 19−11=8 ✓.', 4),
  ('50b48c26-99a0-5c11-a7cf-e77b16b8ce0e', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'احلل الجملة:
$$\begin{cases} 2x + 3y = 12 \\ 4x + 6y = 18 \end{cases}$$
ماذا تستنتج؟', '[{"id":"a","text":"لا يوجد حلّ (الجملة مستحيلة)"},{"id":"b","text":"(3 ; 2)"},{"id":"c","text":"ما لا نهاية من الحلول"},{"id":"d","text":"(0 ; 4)"}]'::jsonb, 'a', 'المعادلة الثانية = ضِعف الطرف الأيسر للأولى: 4x + 6y = 2(2x + 3y) = 2 × 12 = 24، لكنّها تساوي 18. وبما أنّ 24 ≠ 18 فالجملة متناقضة ولا حلّ لها (مستقيمان متوازيان غير منطبقين).', 5),
  ('d664aae3-820f-56ec-90f6-9250aecfa545', 'b5beb3fa-026f-5855-b039-0a90b4473395', 'اشترى أحمد 3 دفاتر وقلمَين بـ 13 دينارًا، واشترى دفترًا واحدًا وقلمَين بـ 7 دنانير. ما ثمن الدفتر الواحد؟', '[{"id":"a","text":"3 دنانير"},{"id":"b","text":"2 دينار"},{"id":"c","text":"4 دنانير"},{"id":"d","text":"1 دينار"}]'::jsonb, 'a', 'نُسمّي ثمن الدفتر x وثمن القلم y. الجملة: 3x + 2y = 13 وx + 2y = 7. بطرح الثانية من الأولى: 2x = 6 → x = 3. التحقّق: من x + 2y = 7 نجد 2y = 4 فـ y = 2، و3(3)+2(2)=13 ✓.', 6),
  ('470b2abb-e2d1-5315-b0af-5a59725ad1e9', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة التآلفية f تُعرَّف بـ f(x) = 3x − 5. ما قيمة f(4) ؟', '[{"id":"a","text":"7"},{"id":"b","text":"12"},{"id":"c","text":"−2"},{"id":"d","text":"17"}]'::jsonb, 'a', 'f(4) = 3 × 4 − 5 = 12 − 5 = 7. نعوّض x بـ 4 ثمّ نحسب.', 1),
  ('eb9ef195-275c-578d-8948-feb571f8b0f2', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة الخطية f تُعرَّف بـ f(x) = ax وتحقّق f(4) = 12. ما هو تعبير f؟', '[{"id":"a","text":"f(x) = 3x"},{"id":"b","text":"f(x) = 4x"},{"id":"c","text":"f(x) = 8x"},{"id":"d","text":"f(x) = 48x"}]'::jsonb, 'a', 'من f(4) = 12 نجد a = 12 ÷ 4 = 3. إذن f(x) = 3x. التحقّق: f(4) = 3 × 4 = 12 ✓.', 2),
  ('b51d59e1-2dd4-58e6-bfcb-0c018e325a4f', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'بيان دالة تآلفية يمرّ بالنقطتَين A(0 ; 3) وB(2 ; 7). ما هو تعبيرها؟', '[{"id":"a","text":"f(x) = 2x + 3"},{"id":"b","text":"f(x) = 3x + 2"},{"id":"c","text":"f(x) = 2x − 3"},{"id":"d","text":"f(x) = 4x + 3"}]'::jsonb, 'a', 'معامل التوجيه a = (7 − 3) ÷ (2 − 0) = 4 ÷ 2 = 2. الترتيب في المبدأ b = f(0) = 3. إذن f(x) = 2x + 3.', 3),
  ('d01578db-cdb6-5429-948d-0af4b218293a', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'الدالة f تُعرَّف بـ f(x) = −2x + 8. ما قيمة x حين f(x) = 0 (الصفر)؟', '[{"id":"a","text":"4"},{"id":"b","text":"−4"},{"id":"c","text":"8"},{"id":"d","text":"16"}]'::jsonb, 'a', 'نحلّ −2x + 8 = 0 → −2x = −8 → x = 4. هذه هي قيمة x التي ينقطع عندها البيان مع محور الفواصل.', 4),
  ('ac721d06-1e23-5b71-a645-d75539ffa1a3', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'أيّ مستقيم من المستقيمات التالية نازل (تناقصي)؟', '[{"id":"a","text":"f(x) = −0.5x + 1"},{"id":"b","text":"f(x) = 2x − 3"},{"id":"c","text":"f(x) = x"},{"id":"d","text":"f(x) = 4x + 2"}]'::jsonb, 'a', 'المستقيم نازل (تناقصي) إذا كان معامل التوجيه a سالبًا. الوحيد ذو المعامل السالب هو f(x) = −0.5x + 1 حيث a = −0.5 < 0.', 5),
  ('d210975c-8a82-5ce6-a253-c3d8df7a2dec', 'bdbdb5f5-a8f3-52dc-ad30-0447dfdd5382', 'مستقيمان: f(x) = 3x − 1 وg(x) = x + 5. ما إحداثيّا نقطة تقاطعهما؟', '[{"id":"a","text":"(3 ; 8)"},{"id":"b","text":"(2 ; 5)"},{"id":"c","text":"(3 ; 5)"},{"id":"d","text":"(1 ; 6)"}]'::jsonb, 'a', 'نحلّ 3x − 1 = x + 5 → 2x = 6 → x = 3. الصورة: f(3) = 3(3) − 1 = 8. نقطة التقاطع (3 ; 8). التحقّق: g(3) = 3 + 5 = 8 ✓.', 6),
  ('fd5e6dd8-ea99-5933-a9a1-bace14e89610', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'علامات 5 تلاميذ: 8 ، 12 ، 10 ، 14 ، 16. ما هو المعدّل الحسابي؟', '[{"id":"a","text":"12"},{"id":"b","text":"10"},{"id":"c","text":"60"},{"id":"d","text":"13"}]'::jsonb, 'a', 'المعدّل = مجموع القيم ÷ عددها = (8 + 12 + 10 + 14 + 16) ÷ 5 = 60 ÷ 5 = 12. التحقّق: 12 يقع ضمن المدى [8 ، 16] ✓.', 1),
  ('56c67eec-e7cc-51d9-b44b-d10607c08039', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في السلسلة المرتّبة: 4 ، 7 ، 9 ، 11 ، 15 (n = 5). ما هو الوسيط؟', '[{"id":"a","text":"9"},{"id":"b","text":"11"},{"id":"c","text":"9.2"},{"id":"d","text":"8"}]'::jsonb, 'a', 'n = 5 (فردي)، الوسيط هو القيمة ذات الرتبة الوسطى (الثالثة). القيمة الثالثة في السلسلة المرتّبة هي 9.', 2),
  ('3924deed-45ce-50c4-bd9c-f2c73b7fedca', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'حصل 4 تلاميذ على العلامة 15، و6 تلاميذ على العلامة 10. ما هو المعدّل الحسابي للمجموعة (n = 10)؟', '[{"id":"a","text":"12"},{"id":"b","text":"12.5"},{"id":"c","text":"11.5"},{"id":"d","text":"25"}]'::jsonb, 'a', 'المجموع = (4 × 15) + (6 × 10) = 60 + 60 = 120. المعدّل = 120 ÷ 10 = 12.', 3),
  ('9ed0f229-7973-510f-b0d7-2d34cecd6e1a', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في فصل من 40 تلميذًا، يمارس 10 منهم كرة القدم. ما هو التواتر بالمائة لفئة كرة القدم؟', '[{"id":"a","text":"25 %"},{"id":"b","text":"10 %"},{"id":"c","text":"40 %"},{"id":"d","text":"4 %"}]'::jsonb, 'a', 'التواتر = التكرار ÷ التكرار الكلّي = 10 ÷ 40 = 0.25. بالنسبة المئوية: 0.25 × 100 = 25 %.', 4),
  ('b8bf05e6-1c21-5ad3-b12f-3c2fda68efc0', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'في مخطّط دائري لـ 200 شخص، تقابل فئةٌ زاوية قطاع قيسها 72°. كم عدد أفراد هذه الفئة؟', '[{"id":"a","text":"40"},{"id":"b","text":"72"},{"id":"c","text":"36"},{"id":"d","text":"50"}]'::jsonb, 'a', 'التواتر = زاوية القطاع ÷ 360° = 72 ÷ 360 = 0.2. عدد الأفراد = التواتر × الكلّ = 0.2 × 200 = 40.', 5),
  ('31033c3d-18db-5262-a31c-24970a5413f3', '4e1dce9d-15f3-5bab-9e39-9ba5d748ff38', 'سلسلة من 6 قيم مرتّبة: 3 ، 5 ، 8 ، 8 ، 11 ، 13. أيّ عبارة صحيحة عن الوسيط والمعدّل؟', '[{"id":"a","text":"الوسيط = 8 والمعدّل = 8"},{"id":"b","text":"الوسيط = 8 والمعدّل = 9"},{"id":"c","text":"الوسيط = 9 والمعدّل = 8"},{"id":"d","text":"الوسيط = 6.5 والمعدّل = 8"}]'::jsonb, 'a', 'الوسيط (n = 6 زوجي): متوسّط القيمتَين الثالثة والرابعة = (8 + 8) ÷ 2 = 8. المعدّل = (3+5+8+8+11+13) ÷ 6 = 48 ÷ 6 = 8. إذن كلاهما = 8.', 6),
  ('56679dc7-5896-555f-a5e7-3f09eee7efdf', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 3 cm وAB = 9 cm وBC = 12 cm. ما طول MN؟', '[{"id":"a","text":"4 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"3 cm"},{"id":"d","text":"8 cm"}]'::jsonb, 'a', 'نسبة التشابه = AM/AB = 3/9 = 1/3. بنظرية طاليس: MN/BC = 1/3، إذن MN = 12 × (1/3) = 4 cm.', 1),
  ('b0151feb-0b03-5582-9fc3-4e405ee7c7cf', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في وضعية الفراشة، يتقاطع مستقيمان في O مع (AB) ∥ (CD). إذا كان OA = 3 cm وOB = 4 cm وOC = 9 cm، فما طول OD؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"6.75 cm"},{"id":"c","text":"10 cm"},{"id":"d","text":"16 cm"}]'::jsonb, 'a', 'في وضعية الفراشة بنظرية طاليس: OA/OC = OB/OD. إذن 3/9 = 4/OD، بالتقاطع 3 × OD = 9 × 4 = 36، فـ OD = 12 cm.', 2),
  ('348408ff-9c0e-5c62-b105-75c53a036b85', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، M على [AB] وN على [AC] مع AM = 2 cm، AB = 5 cm، AN = 3 cm، AC = 8 cm. هل (MN) ∥ (BC)؟', '[{"id":"a","text":"لا، لأنّ AM/AB = 2/5 ≠ AN/AC = 3/8"},{"id":"b","text":"نعم، لأنّ AM/AB = AN/AC"},{"id":"c","text":"نعم، لأنّ AM + AN = 5"},{"id":"d","text":"لا يمكن التحديد"}]'::jsonb, 'a', 'نقارن النسبتَين: AM/AB = 2/5 = 0.4، وAN/AC = 3/8 = 0.375. بما أنّهما غير متساويتين فحسب النظرية العكسية (MN) ليست موازية لـ (BC).', 3),
  ('39ba41a1-3361-50af-a1f6-7821ad43d8de', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 4 cm وMB = 6 cm وAN = 5 cm. ما طول NC؟', '[{"id":"a","text":"7.5 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"5 cm"},{"id":"d","text":"3.33 cm"}]'::jsonb, 'a', 'بنظرية طاليس: AM/MB = AN/NC، أي 4/6 = 5/NC. بالتقاطع: 4 × NC = 6 × 5 = 30، إذن NC = 30 ÷ 4 = 7.5 cm.', 4),
  ('82996a2b-263d-5605-871c-c58f97ccf090', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث ABC، (MN) ∥ (BC) مع AM = 4 cm، AN = 6 cm، NC = 9 cm. ما طول AB؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"6 cm"},{"id":"c","text":"13 cm"},{"id":"d","text":"8 cm"}]'::jsonb, 'a', 'AC = AN + NC = 6 + 9 = 15 cm. بنظرية طاليس: AM/AB = AN/AC، أي 4/AB = 6/15 = 2/5. بالتقاطع: 2 × AB = 4 × 5 = 20، إذن AB = 10 cm.', 5),
  ('1ef82e17-97db-5707-9533-d74dc3d11af9', 'bb04c882-d576-55ca-a4bc-95e36b356ece', 'في مثلّث PQR، (ST) ∥ (QR) مع PS = 2x وPQ = 12 cm وPT = x + 1 وPR = 8 cm. ما قيمة x؟', '[{"id":"a","text":"x = 3"},{"id":"b","text":"x = 2"},{"id":"c","text":"x = 4"},{"id":"d","text":"x = 1.5"}]'::jsonb, 'a', 'بنظرية طاليس: PS/PQ = PT/PR، أي 2x/12 = (x+1)/8. بالتقاطع: 8 × 2x = 12 × (x+1) → 16x = 12x + 12 → 4x = 12 → x = 3. التحقّق: PS=6، PT=4؛ 6/12 = 1/2 و4/8 = 1/2 ✓.', 6),
  ('dfde8594-7f9d-5279-9ae7-07c51d52d0a6', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AB = 8 cm وBC = 6 cm. ما طول الوتر AC؟', '[{"id":"a","text":"10 cm"},{"id":"b","text":"14 cm"},{"id":"c","text":"√14 cm"},{"id":"d","text":"100 cm"}]'::jsonb, 'a', 'بنظرية فيثاغورس: AC² = AB² + BC² = 64 + 36 = 100، إذن AC = √100 = 10 cm. هذه الثلاثية المشهورة (6، 8، 10) من مضاعفات (3، 4، 5).', 1),
  ('9889a97c-458b-557a-95f0-512fc6ded20b', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، AC = 13 cm وAB = 5 cm. ما طول BC؟', '[{"id":"a","text":"12 cm"},{"id":"b","text":"8 cm"},{"id":"c","text":"√194 cm"},{"id":"d","text":"18 cm"}]'::jsonb, 'a', 'AC هو الوتر. بفيثاغورس: AC² = AB² + BC² → 13² = 5² + BC² → 169 = 25 + BC² → BC² = 144 → BC = 12 cm. الثلاثية (5، 12، 13).', 2),
  ('c986e021-1f47-5951-a459-a127caba0567', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'مثلث أضلاعه 9 cm و12 cm و15 cm. هل هو قائم الزاوية؟', '[{"id":"a","text":"نعم، لأنّ 9² + 12² = 15²"},{"id":"b","text":"لا، لأنّ 9 + 12 ≠ 15"},{"id":"c","text":"نعم، لأنّ 9 + 12 > 15"},{"id":"d","text":"لا، لأنّ 9² + 12² ≠ 15²"}]'::jsonb, 'a', 'نحسب: 9² + 12² = 81 + 144 = 225 = 15². بما أنّ مجموع مربّعي الضلعين الأصغرين يساوي مربّع الأكبر، فالمثلث قائم بعكس فيثاغورس.', 3),
  ('68dd2292-5551-5e45-8852-262481a36870', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة A تحقّق جا(A) = 1/2. ما قيمة A؟', '[{"id":"a","text":"30°"},{"id":"b","text":"45°"},{"id":"c","text":"60°"},{"id":"d","text":"90°"}]'::jsonb, 'a', 'من جدول القيم المشهورة: جا(30°) = 1/2. إذن A = 30°. تذكّر: جا(45°) = √2/2 وجا(60°) = √3/2.', 4),
  ('1ea0a760-4e4a-5e7d-b9d5-17a7ac759091', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في المثلث ABC القائم في B، الزاوية A = 30° والوتر AC = 12 cm. ما طول الضلع BC (المقابل للزاوية A)؟', '[{"id":"a","text":"6 cm"},{"id":"b","text":"6√3 cm"},{"id":"c","text":"12√3 cm"},{"id":"d","text":"4 cm"}]'::jsonb, 'a', 'جا(A) = المقابل/الوتر = BC/AC. إذن جا(30°) = BC/12، أي 1/2 = BC/12، فينتج BC = 12 × 1/2 = 6 cm.', 5),
  ('5ed6a19c-2f76-549e-829a-3e952ee94469', '8fcc50fd-f426-5868-b797-35a0bdc92829', 'في مثلث قائم، الزاوية الحادّة x تحقّق جتا(x) = √2/2. ما قيمة جا(x) ؟', '[{"id":"a","text":"√2/2"},{"id":"b","text":"1/2"},{"id":"c","text":"√3/2"},{"id":"d","text":"1"}]'::jsonb, 'a', 'جتا(x) = √2/2 يعني x = 45°. إذن جا(45°) = √2/2. التحقّق بالعلاقة الأساسية: جا²(x) + جتا²(x) = 1/2 + 1/2 = 1 ✓.', 6),
  ('347c6beb-2894-5fa6-9855-1658fff2add1', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 110°، وC نقطة على القوس الكبير. ما قيمة الزاوية المحيطية ACB؟', '[{"id":"a","text":"55°"},{"id":"b","text":"110°"},{"id":"c","text":"220°"},{"id":"d","text":"70°"}]'::jsonb, 'a', 'الزاوية المحيطية = نصف الزاوية المركزية المقابلة لنفس القوس. ACB = 110° ÷ 2 = 55°.', 1),
  ('ac6fd8cf-2009-5ca5-a70d-28bcebcf296b', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاوية المحيطية MPN = 35°. ما قيمة الزاوية المركزية MON المقابلة لنفس القوس؟', '[{"id":"a","text":"70°"},{"id":"b","text":"35°"},{"id":"c","text":"17.5°"},{"id":"d","text":"145°"}]'::jsonb, 'a', 'الزاوية المركزية = ضعف الزاوية المحيطية المقابلة لنفس القوس. MON = 2 × 35° = 70°.', 2),
  ('253fac3f-1b6c-57d8-83fc-3ea1177d0df2', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، [AB] قطر وC نقطة على الدائرة. إذا كانت الزاوية CAB = 40°، ما قيمة الزاوية ABC؟', '[{"id":"a","text":"50°"},{"id":"b","text":"40°"},{"id":"c","text":"90°"},{"id":"d","text":"140°"}]'::jsonb, 'a', 'بما أنّ [AB] قطر، فالزاوية ACB = 90° (زاوية محيطية تحصر نصف دائرة). في المثلث ABC: ABC = 180° − 90° − 40° = 50°.', 3),
  ('4b903fee-9e5b-5af1-a92d-255687213b58', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، زاويتان محيطيتان ACB وADB تحصران القوس نفسه AB من الجهة نفسها. إذا كانت ACB = 47°، فما قيمة ADB؟', '[{"id":"a","text":"47°"},{"id":"b","text":"94°"},{"id":"c","text":"23.5°"},{"id":"d","text":"133°"}]'::jsonb, 'a', 'كلّ زاويتَين محيطيتَين تحصران القوس نفسه من الجهة نفسها متساويتان. إذن ADB = ACB = 47°.', 4),
  ('3a26d1a7-cbef-59b4-9541-8d3f57bb2cfa', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة مركزها O، الزاوية المركزية AOB = 120°. ما قيس القوس الصغير AB؟', '[{"id":"a","text":"120°"},{"id":"b","text":"60°"},{"id":"c","text":"240°"},{"id":"d","text":"30°"}]'::jsonb, 'a', 'قيس الزاوية المركزية يساوي قيس قوسها المقابل. إذن قيس القوس الصغير AB = 120°.', 5),
  ('4b6092af-fe1c-59f9-92fa-22d6183c0df4', '68279374-18d2-571b-b3c5-112daf3c592e', 'في دائرة، الزاوية المحيطية ACB = 54°. ما قيس القوس الكبير AB (الذي لا يحوي C)؟', '[{"id":"a","text":"252°"},{"id":"b","text":"108°"},{"id":"c","text":"126°"},{"id":"d","text":"306°"}]'::jsonb, 'a', 'القوس الصغير AB المقابل للزاوية المحيطية = 2 × 54° = 108°. القوس الكبير = 360° − 108° = 252°.', 6),
  ('56c73ae6-21ea-50a7-ae5f-36e41527d3e8', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط بتطبيق علاقة شال: $\overrightarrow{AB} + \overrightarrow{BC}$', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$\\overrightarrow{CA}$"},{"id":"c","text":"$\\overrightarrow{BA}$"},{"id":"d","text":"$\\overrightarrow{0}$"}]'::jsonb, 'a', 'علاقة شال: $\overrightarrow{AB} + \overrightarrow{BC} = \overrightarrow{AC}$ (النقطة الوسطى B تختفي).', 1),
  ('7bfdffd3-9742-582c-b215-fb9538e3e4b4', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط: $\overrightarrow{AB} + \overrightarrow{BC} + \overrightarrow{CA}$', '[{"id":"a","text":"$\\overrightarrow{0}$"},{"id":"b","text":"$\\overrightarrow{AC}$"},{"id":"c","text":"$\\overrightarrow{AA}$ يساوي $\\overrightarrow{AB}$"},{"id":"d","text":"$\\overrightarrow{CA}$"}]'::jsonb, 'a', 'بشال تدريجيًا: $\overrightarrow{AB} + \overrightarrow{BC} = \overrightarrow{AC}$، ثمّ $\overrightarrow{AC} + \overrightarrow{CA} = \overrightarrow{AA} = \overrightarrow{0}$. مجموع أشعّة دورة مغلقة دائمًا الشعاع المعدوم.', 2),
  ('2b458517-ac01-509a-8c23-f0dda8c64a2f', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'ABCD متوازي أضلاع. أيّ مساواة صحيحة دائمًا؟', '[{"id":"a","text":"$\\overrightarrow{AB} = \\overrightarrow{DC}$"},{"id":"b","text":"$\\overrightarrow{AB} = \\overrightarrow{CD}$"},{"id":"c","text":"$\\overrightarrow{AB} = \\overrightarrow{BC}$"},{"id":"d","text":"$\\overrightarrow{AC} = \\overrightarrow{BD}$"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD يكون الضلعان [AB] و[DC] متوازيَين ومتساويَين وبالاتّجاه نفسه، إذن $\overrightarrow{AB} = \overrightarrow{DC}$. أمّا $\overrightarrow{CD}$ فهو الشعاع المعاكس.', 3),
  ('bc6fd815-3864-588a-afcc-0bcbfccd1ce3', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'في الانسحاب الذي شعاعه $\overrightarrow{u}$، صورة النقطة A هي A''. ما العلاقة بين النقاط؟', '[{"id":"a","text":"$\\overrightarrow{AA''} = \\overrightarrow{u}$"},{"id":"b","text":"$\\overrightarrow{A''A} = \\overrightarrow{u}$"},{"id":"c","text":"$\\overrightarrow{AA''} = \\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{AA''} = 2\\overrightarrow{u}$"}]'::jsonb, 'a', 'تعريف الانسحاب ذي الشعاع $\overrightarrow{u}$: كلّ نقطة M وصورتها M'' تحقّقان $\overrightarrow{MM''} = \overrightarrow{u}$. إذن للنقطة A: $\overrightarrow{AA''} = \overrightarrow{u}$.', 4),
  ('21ca47be-6794-51f0-8fea-5408c9214d64', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'I منتصف القطعة [AB]. أيّ مساواة صحيحة؟', '[{"id":"a","text":"$\\overrightarrow{IA} + \\overrightarrow{IB} = \\overrightarrow{0}$"},{"id":"b","text":"$\\overrightarrow{IA} = \\overrightarrow{IB}$"},{"id":"c","text":"$\\overrightarrow{AI} = \\overrightarrow{BI}$"},{"id":"d","text":"$\\overrightarrow{IA} + \\overrightarrow{IB} = \\overrightarrow{AB}$"}]'::jsonb, 'a', 'بما أنّ I منتصف [AB] فإنّ $\overrightarrow{IA}$ و$\overrightarrow{IB}$ متساويان في الطول ومتعاكسان في الاتّجاه، أي $\overrightarrow{IB} = -\overrightarrow{IA}$، ومجموعهما $\overrightarrow{0}$.', 5),
  ('2aa4dc51-0b7d-53b4-bdb6-2cf08ff2336b', '3497cf16-c3a6-509e-95ad-376ce8a5e5af', 'بسّط: $\overrightarrow{AB} - \overrightarrow{CB}$', '[{"id":"a","text":"$\\overrightarrow{AC}$"},{"id":"b","text":"$\\overrightarrow{CA}$"},{"id":"c","text":"$\\overrightarrow{AB} + \\overrightarrow{BC}$ يساوي $\\overrightarrow{0}$"},{"id":"d","text":"$\\overrightarrow{BA}$"}]'::jsonb, 'a', 'نحوّل الطرح إلى جمع بالشعاع المعاكس: $\overrightarrow{AB} - \overrightarrow{CB} = \overrightarrow{AB} + \overrightarrow{BC}$ (لأنّ $-\overrightarrow{CB} = \overrightarrow{BC}$). بشال: $= \overrightarrow{AC}$.', 6),
  ('921d1b5c-4236-5b2b-b91b-0d8f42878f2f', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(1 ; 2) وB(5 ; 8). ما إحداثيّات منتصف القطعة [AB]؟', '[{"id":"a","text":"(3 ; 5)"},{"id":"b","text":"(4 ; 6)"},{"id":"c","text":"(6 ; 10)"},{"id":"d","text":"(2 ; 3)"}]'::jsonb, 'a', 'المنتصف $I = \left(\frac{1+5}{2} ; \frac{2+8}{2}\right) = \left(\frac{6}{2} ; \frac{10}{2}\right) = (3 ; 5)$.', 1),
  ('7480e0a4-f226-58b8-b9d5-759d07fafb6c', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(1 ; 1) وB(4 ; 5). ما المسافة AB؟', '[{"id":"a","text":"5"},{"id":"b","text":"7"},{"id":"c","text":"√7"},{"id":"d","text":"√41"}]'::jsonb, 'a', '$AB = \sqrt{(4-1)^2 + (5-1)^2} = \sqrt{3^2 + 4^2} = \sqrt{9 + 16} = \sqrt{25} = 5$.', 2),
  ('54e80fdb-1f52-55db-b4f4-77bf29f98fb4', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(−1 ; 2) وB(3 ; 2). ما إحداثيّات الشعاع $\overrightarrow{AB}$؟', '[{"id":"a","text":"(4 ; 0)"},{"id":"b","text":"(2 ; 4)"},{"id":"c","text":"(−4 ; 0)"},{"id":"d","text":"(2 ; 0)"}]'::jsonb, 'a', '$\overrightarrow{AB} = (x_B - x_A ; y_B - y_A) = (3 - (-1) ; 2 - 2) = (4 ; 0)$.', 3),
  ('2eeb1f26-7df6-5d41-a80e-ed3e39328bd1', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'ABCD متوازي أضلاع بـ A(0 ; 0) وB(4 ; 1) وD(1 ; 3). ما إحداثيّات C؟', '[{"id":"a","text":"C(5 ; 4)"},{"id":"b","text":"C(3 ; 2)"},{"id":"c","text":"C(5 ; 1)"},{"id":"d","text":"C(4 ; 4)"}]'::jsonb, 'a', 'في متوازي الأضلاع ABCD: $\overrightarrow{AB} = \overrightarrow{DC}$. $\overrightarrow{AB} = (4 ; 1)$، إذن $C = D + (4 ; 1) = (1+4 ; 3+1) = (5 ; 4)$. التحقّق: $\overrightarrow{AD} = (1;3)$ و$\overrightarrow{BC} = (1;3)$ ✓.', 4),
  ('f5474864-0c4c-5a96-a6ce-e7028ab46829', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(2 ; 1) وB(6 ; 1) وC(2 ; 4). هل المثلّث ABC قائم الزاوية؟ وأين القائمة؟', '[{"id":"a","text":"نعم، القائمة في A"},{"id":"b","text":"نعم، القائمة في B"},{"id":"c","text":"نعم، القائمة في C"},{"id":"d","text":"لا، ليس قائمًا"}]'::jsonb, 'a', '$AB = \sqrt{(6-2)^2+0^2} = 4$، $AC = \sqrt{0^2+(4-1)^2} = 3$، $BC = \sqrt{(2-6)^2+(4-1)^2} = \sqrt{16+9} = 5$. نتحقّق: $AB^2 + AC^2 = 16+9 = 25 = BC^2$ ✓. إذن القائمة في A.', 5),
  ('89fd3865-98f6-5a03-9663-21869c46aa69', '6ff1a99c-0aad-5f5d-80bf-603c9b4d05bc', 'A(−2 ; 0) وB(2 ; 3). ما إحداثيّات النقطة C بحيث $\overrightarrow{AC} = 3\overrightarrow{AB}$؟', '[{"id":"a","text":"C(10 ; 9)"},{"id":"b","text":"C(6 ; 9)"},{"id":"c","text":"C(12 ; 9)"},{"id":"d","text":"C(4 ; 9)"}]'::jsonb, 'a', '$\overrightarrow{AB} = (2-(-2) ; 3-0) = (4 ; 3)$. إذن $3\overrightarrow{AB} = (12 ; 9)$. $C = A + (12 ; 9) = (-2+12 ; 0+9) = (10 ; 9)$.', 6),
  ('db5b1cf9-ba85-585d-998f-e17a1ccbb96a', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 3 cm وارتفاعها 10 cm. ما حجمها؟ (π ≈ 3.14)', '[{"id":"a","text":"282.6 cm³"},{"id":"b","text":"94.2 cm³"},{"id":"c","text":"188.4 cm³"},{"id":"d","text":"565.2 cm³"}]'::jsonb, 'a', 'حجم الأسطوانة $V = \pi r^2 h$. نربّع نصف القطر: $r^2 = 3^2 = 9$. إذن $V = 3.14 \times 9 \times 10 = 3.14 \times 90 = 282.6 \text{ cm}^3$.', 1),
  ('ddbdd453-8143-53da-9bbe-497286ee59a3', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'مخروط نصف قطر قاعدته 3 cm وارتفاعه 4 cm. ما طوله المائل l؟', '[{"id":"a","text":"5 cm"},{"id":"b","text":"7 cm"},{"id":"c","text":"√7 cm"},{"id":"d","text":"12 cm"}]'::jsonb, 'a', 'الطول المائل $l = \sqrt{r^2 + h^2} = \sqrt{3^2 + 4^2} = \sqrt{9 + 16} = \sqrt{25} = 5 \text{ cm}$ (الثلاثية 3-4-5).', 2),
  ('778771b1-984e-5b3f-b318-5f9ed781b359', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'هرم قاعدته مربّع ضلعه 6 cm وارتفاعه 10 cm. ما حجمه؟', '[{"id":"a","text":"120 cm³"},{"id":"b","text":"360 cm³"},{"id":"c","text":"60 cm³"},{"id":"d","text":"100 cm³"}]'::jsonb, 'a', 'مساحة القاعدة المربّعة $S = 6^2 = 36 \text{ cm}^2$. حجم الهرم $V = \frac{1}{3} \times S \times h = \frac{1}{3} \times 36 \times 10 = \frac{360}{3} = 120 \text{ cm}^3$.', 3),
  ('c1410b5e-9143-5d13-91f1-297686628498', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'كرة نصف قطرها 6 cm. ما حجمها بدلالة π؟', '[{"id":"a","text":"288π cm³"},{"id":"b","text":"144π cm³"},{"id":"c","text":"72π cm³"},{"id":"d","text":"216π cm³"}]'::jsonb, 'a', 'حجم الكرة $V = \frac{4}{3}\pi r^3 = \frac{4}{3}\pi \times 6^3 = \frac{4}{3}\pi \times 216 = \frac{864}{3}\pi = 288\pi \text{ cm}^3$.', 4),
  ('ba409a8e-709a-569b-8161-5bab65afffce', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'أسطوانة نصف قطرها 4 cm وارتفاعها 7 cm. ما مساحتها الجانبية؟ (π ≈ 3.14)', '[{"id":"a","text":"175.84 cm²"},{"id":"b","text":"87.92 cm²"},{"id":"c","text":"351.68 cm²"},{"id":"d","text":"100.48 cm²"}]'::jsonb, 'a', 'المساحة الجانبية للأسطوانة = محيط القاعدة × الارتفاع = $2\pi r h = 2 \times 3.14 \times 4 \times 7 = 6.28 \times 28 = 175.84 \text{ cm}^2$.', 5),
  ('af07c682-e2b7-5bf7-9de1-e4933dafb486', '32f52713-76e8-5bb9-a681-87b1aa9d031a', 'إذا ضاعفنا نصف قطر كرة (ليصبح 2r بدل r)، فبكم يتضاعف حجمها؟', '[{"id":"a","text":"8 مرّات (×8)"},{"id":"b","text":"مرّتين (×2)"},{"id":"c","text":"4 مرّات (×4)"},{"id":"d","text":"6 مرّات (×6)"}]'::jsonb, 'a', 'حجم الكرة $V = \frac{4}{3}\pi r^3$ متناسب مع مكعّب نصف القطر. عند مضاعفة r إلى 2r: $(2r)^3 = 8r^3$، إذن الحجم يتضاعف 8 مرّات.', 6),
  ('88975673-9739-5d79-8e8d-d2d7134aa3db', 'fdef87db-3a52-50ab-8803-b009147266cb', 'À quel type appartient la phrase : « Quel courage tu as montré ! » ?', '[{"id":"a","text":"Type déclaratif"},{"id":"b","text":"Type interrogatif"},{"id":"c","text":"Type exclamatif"},{"id":"d","text":"Type injonctif"}]'::jsonb, 'c', 'Le point d''exclamation et la tournure « Quel… » expriment un sentiment fort : c''est une phrase exclamative. Le type déclaratif (a) se termine par un point et énonce un fait ; l''interrogatif (b) pose une question ; l''injonctif (d) donne un ordre.', 1),
  ('e2146fe9-522d-579e-8126-78cb344ed44d', 'fdef87db-3a52-50ab-8803-b009147266cb', 'Quelle phrase est une phrase emphatique (de forme emphatique) ?', '[{"id":"a","text":"Le héros a vaincu le dragon."},{"id":"b","text":"C''est le héros qui a vaincu le dragon."},{"id":"c","text":"Le héros a-t-il vaincu le dragon ?"},{"id":"d","text":"Le dragon a été vaincu par le héros."}]'::jsonb, 'b', 'La forme emphatique met un élément en relief, ici grâce au présentatif « c''est… qui ». L''option a est neutre, c est interrogative, d est passive (donc une voix, non une forme emphatique).', 2),
  ('593810f6-c884-519f-9a58-a9c23081bbd4', 'fdef87db-3a52-50ab-8803-b009147266cb', 'Transforme en interrogation totale par inversion : « Vous partez demain. »', '[{"id":"a","text":"Quand partez-vous ?"},{"id":"b","text":"Est-ce que vous partez demain."},{"id":"c","text":"Partez-vous demain ?"},{"id":"d","text":"Vous partez demain ?"}]'::jsonb, 'c', 'L''interrogation totale appelle une réponse oui/non et l''inversion place le sujet après le verbe avec un trait d''union : « Partez-vous demain ? ». L''option a est partielle (mot interrogatif « quand ») ; b emploie « est-ce que » et finit par un point ; d garde l''ordre déclaratif (interrogation par intonation, sans inversion).', 3),
  ('e3833318-8711-50e7-ab12-5d09fc7a0c34', 'fdef87db-3a52-50ab-8803-b009147266cb', 'Quelle phrase est de type injonctif ?', '[{"id":"a","text":"Tu fermes la porte."},{"id":"b","text":"Ferme la porte."},{"id":"c","text":"As-tu fermé la porte ?"},{"id":"d","text":"La porte est fermée."}]'::jsonb, 'b', 'La phrase injonctive donne un ordre ou un conseil, souvent à l''impératif : « Ferme la porte. ». L''option a est déclarative (verbe à l''indicatif présent), c est interrogative, d est déclarative.', 4),
  ('c43ebd4e-b373-5147-8a23-30bd9aed1145', 'fdef87db-3a52-50ab-8803-b009147266cb', 'Mets à la forme négative : « Tout le monde est venu. »', '[{"id":"a","text":"Tout le monde n''est pas venu."},{"id":"b","text":"Personne n''est venu."},{"id":"c","text":"Tout le monde est venu pas."},{"id":"d","text":"Rien n''est venu."}]'::jsonb, 'b', 'Le contraire de « tout le monde » (toutes les personnes) est « personne n''… » : « Personne n''est venu. » L''option a signifie « pas tous », ce qui n''est pas la négation totale attendue ; c est agrammaticale ; « rien » (d) désigne une chose, pas une personne.', 5),
  ('fc9408ca-e18d-50e5-b964-ffc8acadf596', 'fdef87db-3a52-50ab-8803-b009147266cb', 'Identifie le type ET la forme de : « N''as-tu jamais lu ce livre ? »', '[{"id":"a","text":"Interrogative et négative"},{"id":"b","text":"Déclarative et négative"},{"id":"c","text":"Interrogative et affirmative"},{"id":"d","text":"Exclamative et négative"}]'::jsonb, 'a', 'Le point d''interrogation et l''inversion (« as-tu ») marquent le type interrogatif ; « ne… jamais » marque la forme négative : la phrase est interrogative et négative. Elle n''est ni déclarative (b), ni affirmative (c, contredit par « ne… jamais »), ni exclamative (d, pas de point d''exclamation).', 6),
  ('52a2766e-fcf5-56ae-8559-494d2b9907ec', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Dans « Je connais l''élève qui a gagné le concours. », la proposition subordonnée est :', '[{"id":"a","text":"Une subordonnée relative"},{"id":"b","text":"Une subordonnée complétive"},{"id":"c","text":"Une subordonnée circonstancielle de temps"},{"id":"d","text":"Une proposition indépendante"}]'::jsonb, 'a', '« qui a gagné le concours » est introduite par le pronom relatif « qui » et complète le nom « élève » (son antécédent) : c''est une subordonnée relative. Une complétive (b) est introduite par « que » et complète un verbe ; une circonstancielle de temps (c) répond à « quand ? » ; ce n''est pas une indépendante (d) car elle dépend de la principale.', 1),
  ('7b544c55-62e7-53a6-8c54-030638b09322', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Quelle phrase contient une subordonnée complétive (conjonctive par « que ») ?', '[{"id":"a","text":"Le livre que tu lis est passionnant."},{"id":"b","text":"Je pense que tu as raison."},{"id":"c","text":"Il viendra quand il pourra."},{"id":"d","text":"C''est la maison où je suis né."}]'::jsonb, 'b', '« que tu as raison » complète le verbe « pense » et joue le rôle de COD : c''est une complétive. Dans a, « que » est pronom relatif (antécédent « livre ») ; dans c, « quand » introduit une circonstancielle de temps ; dans d, « où » est un pronom relatif (subordonnée relative).', 2),
  ('b0d6bad5-c558-5387-b3c9-4a8b167cc412', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Quel subordonnant introduit une subordonnée circonstancielle de but ?', '[{"id":"a","text":"parce que"},{"id":"b","text":"afin que"},{"id":"c","text":"lorsque"},{"id":"d","text":"si bien que"}]'::jsonb, 'b', '« afin que » (suivi du subjonctif) exprime le but, l''objectif visé. « parce que » introduit la cause (a), « lorsque » le temps (c), « si bien que » la conséquence (d).', 3),
  ('348dc8e4-92e9-52f8-a85a-8fc5dfb3dfdb', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Dans « Bien qu''il soit fatigué, il continue de courir. », quelle est la nature de la subordonnée ?', '[{"id":"a","text":"Subordonnée circonstancielle de cause"},{"id":"b","text":"Subordonnée circonstancielle de but"},{"id":"c","text":"Subordonnée circonstancielle de concession (opposition)"},{"id":"d","text":"Subordonnée relative"}]'::jsonb, 'c', '« Bien que » introduit une concession : on exprime un obstacle qui n''empêche pourtant pas l''action (il court malgré la fatigue). « Parce que » marquerait la cause (a), « pour que » le but (b), un pronom relatif une relative (d).', 4),
  ('b356e2bc-7641-5bd1-973a-cf751b424915', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Dans « La ville où je vis est ancienne. », quelle est la fonction du pronom relatif « où » ?', '[{"id":"a","text":"Complément circonstanciel de lieu (dans la subordonnée)"},{"id":"b","text":"Sujet de « vis »"},{"id":"c","text":"COD de « vis »"},{"id":"d","text":"Attribut du sujet"}]'::jsonb, 'a', '« où » remplace « dans la ville » et indique le lieu où se déroule l''action « je vis » : il est complément circonstanciel de lieu. Le sujet de « vis » est « je » (b) ; « vivre » ici est intransitif, donc pas de COD (c) ; « où » n''est pas un attribut (d).', 5),
  ('27b8f517-f017-58a8-a0a8-0e44ba9ca0cd', 'b0b98885-5cc3-53b6-bbf4-42a6fbd10edd', 'Quelle phrase ne contient AUCUNE proposition subordonnée ?', '[{"id":"a","text":"Il pleut, mais nous sortons quand même."},{"id":"b","text":"J''espère que tu réussiras."},{"id":"c","text":"Je lis le roman que tu m''as offert."},{"id":"d","text":"Comme il pleut, nous restons."}]'::jsonb, 'a', 'Dans a, « mais » coordonne deux propositions indépendantes : il n''y a pas de subordination. En b, « que tu réussiras » est une complétive ; en c, « que tu m''as offert » est une relative ; en d, « Comme il pleut » est une circonstancielle de cause.', 6),
  ('bf62eaa6-0c73-5b2a-8820-7237bce83c21', '239989ee-497a-589e-8483-558788dd504d', 'Mets à la voix passive : « Les élèves respectent leur professeur. »', '[{"id":"a","text":"Le professeur respecte ses élèves."},{"id":"b","text":"Le professeur est respecté par les élèves."},{"id":"c","text":"Le professeur a été respecté par les élèves."},{"id":"d","text":"Les élèves sont respectés par le professeur."}]'::jsonb, 'b', 'Le COD « leur professeur » devient sujet et le présent est conservé : « est respecté par les élèves ». L''option c change le temps (passé composé), a inverse le sens, d inverse les rôles.', 1),
  ('a7973a25-f7ad-54f7-889a-fb32afb22a8c', '239989ee-497a-589e-8483-558788dd504d', 'Mets à la voix active : « Ce roman a été écrit par un jeune auteur. »', '[{"id":"a","text":"Un jeune auteur écrit ce roman."},{"id":"b","text":"Un jeune auteur a écrit ce roman."},{"id":"c","text":"Ce roman écrit un jeune auteur."},{"id":"d","text":"Un jeune auteur écrivait ce roman."}]'::jsonb, 'b', 'Le complément d''agent « un jeune auteur » devient sujet et on conserve le temps de la voix passive : « a été écrit » (passé composé) donne « a écrit ». L''option a est au présent, d à l''imparfait, c inverse les rôles.', 2),
  ('c1c02ada-a91d-5c2a-9dcf-707291fa4620', '239989ee-497a-589e-8483-558788dd504d', 'Dans « La porte a été ouverte par le vent. », quel est le complément d''agent ?', '[{"id":"a","text":"La porte"},{"id":"b","text":"a été ouverte"},{"id":"c","text":"le vent"},{"id":"d","text":"par"}]'::jsonb, 'c', 'Le complément d''agent désigne celui qui fait l''action ; introduit par « par », c''est ici « le vent ». « La porte » est le sujet (a), « a été ouverte » le verbe passif (b), « par » la simple préposition (d).', 3),
  ('0cfc8ea9-1e3c-5004-8105-4860681f369f', '239989ee-497a-589e-8483-558788dd504d', 'Quelle phrase est correctement à la voix passive ?', '[{"id":"a","text":"Le voleur a arrêté par la police."},{"id":"b","text":"Le voleur a été arrêté par la police."},{"id":"c","text":"Le voleur est arrêté la police."},{"id":"d","text":"La police a été arrêté le voleur."}]'::jsonb, 'b', 'La voix passive se forme avec l''auxiliaire « être » conjugué + participe passé accordé : « a été arrêté par la police ». L''option a oublie « été », c oublie « par », d mélange sujet et complément.', 4),
  ('260c5f3f-a766-5a3e-a740-dd0f00f33d3d', '239989ee-497a-589e-8483-558788dd504d', 'Mets à la voix passive en respectant l''accord : « La directrice félicite les lauréates. »', '[{"id":"a","text":"Les lauréates sont félicité par la directrice."},{"id":"b","text":"Les lauréates sont félicitées par la directrice."},{"id":"c","text":"Les lauréates ont félicité la directrice."},{"id":"d","text":"La directrice est félicitée par les lauréates."}]'::jsonb, 'b', 'Le participe passé s''accorde avec le sujet « les lauréates » (féminin pluriel) : « félicitées ». L''option a oublie l''accord, c et d inversent les rôles.', 5),
  ('23cc5062-223d-5494-94eb-9830da75d3e0', '239989ee-497a-589e-8483-558788dd504d', 'Pourquoi emploie-t-on souvent la voix passive dans la phrase « Le coupable a été condamné. » ?', '[{"id":"a","text":"Pour poser une question."},{"id":"b","text":"Pour mettre en valeur l''objet de l''action quand l''agent est inconnu ou peu important."},{"id":"c","text":"Pour donner un ordre."},{"id":"d","text":"Parce que la voix passive est interdite à l''écrit."}]'::jsonb, 'b', 'La voix passive permet de mettre l''accent sur celui qui subit l''action (« le coupable ») et d''effacer l''agent quand il est inconnu ou secondaire. Elle ne sert ni à interroger (a), ni à ordonner (c), et elle est tout à fait correcte à l''écrit (d est faux).', 6),
  ('70cae8ac-91e9-5ebd-8a9e-99137922c50e', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Quelle est la ponctuation correcte du discours direct ?', '[{"id":"a","text":"Il dit que « je viens »."},{"id":"b","text":"Il dit : « Je viens. »"},{"id":"c","text":"Il dit, Je viens."},{"id":"d","text":"Il dit Je viens"}]'::jsonb, 'b', 'Le discours direct s''introduit par un deux-points puis des guillemets entourant les paroles exactes : « Je viens. ». L''option a mélange « que » (indirect) et guillemets ; c et d n''emploient ni deux-points ni guillemets.', 1),
  ('90a52a14-dddc-5c1f-9ae2-e046a6a3bf36', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Mets au discours indirect : Il dit : « Je suis fatigué. »', '[{"id":"a","text":"Il dit qu''il est fatigué."},{"id":"b","text":"Il dit que je suis fatigué."},{"id":"c","text":"Il dit : il est fatigué."},{"id":"d","text":"Il dit qu''il était fatigué."}]'::jsonb, 'a', 'Le verbe introducteur est au présent : on subordonne avec « que » et on change le pronom « je » en « il », sans changer le temps : « Il dit qu''il est fatigué. ». L''option b garde « je » (faux), c oublie « que », d change le temps alors que le verbe introducteur est au présent.', 2),
  ('89272a98-c361-59d6-9769-0f446eec2791', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Mets au discours indirect : Le maître ordonna : « Sortez ! »', '[{"id":"a","text":"Le maître ordonna que sortez."},{"id":"b","text":"Le maître ordonna de sortir."},{"id":"c","text":"Le maître ordonna sortez."},{"id":"d","text":"Le maître ordonna s''ils sortent."}]'::jsonb, 'b', 'Un ordre (impératif) au discours indirect se rend par « de + infinitif » : « ordonna de sortir ». L''option a garde l''impératif après « que », c oublie la subordination, d transforme l''ordre en interrogation.', 3),
  ('84cc4ad9-5b0a-5abf-94ac-0ef213a39e00', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Mets au discours indirect : Elle a demandé : « Est-ce que tu viens ? »', '[{"id":"a","text":"Elle a demandé que tu viens."},{"id":"b","text":"Elle a demandé si je venais."},{"id":"c","text":"Elle a demandé est-ce que je viens."},{"id":"d","text":"Elle a demandé que je venais."}]'::jsonb, 'b', 'L''interrogation totale au discours indirect est introduite par « si » (et non « que »), le pronom devient « je » et, le verbe introducteur étant au passé, le présent passe à l''imparfait : « si je venais ». L''option a et d utilisent « que » (faux), c garde « est-ce que ».', 4),
  ('7fed4144-3d84-5e12-9241-90c61b17bc16', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Mets au discours indirect : Il déclara : « J''ai fini mon travail hier. »', '[{"id":"a","text":"Il déclara qu''il a fini son travail hier."},{"id":"b","text":"Il déclara qu''il avait fini son travail la veille."},{"id":"c","text":"Il déclara qu''il avait fini mon travail hier."},{"id":"d","text":"Il déclara qu''il finit son travail la veille."}]'::jsonb, 'b', 'Verbe introducteur au passé : le passé composé devient plus-que-parfait (« avait fini »), le possessif « mon » devient « son » et l''indicateur de temps « hier » devient « la veille ». L''option a ne fait pas la concordance, c garde « mon », d change le sens du verbe.', 5),
  ('e6d69941-cc45-5d67-a596-939ffc03da9f', 'a79b3af3-ff27-5c55-9c31-e08d4da2b120', 'Mets au discours indirect : Elle demanda : « Où vas-tu ? »', '[{"id":"a","text":"Elle demanda où je vais."},{"id":"b","text":"Elle demanda que j''allais."},{"id":"c","text":"Elle demanda où j''allais."},{"id":"d","text":"Elle demanda si j''allais où."}]'::jsonb, 'c', 'L''interrogation partielle conserve son mot interrogatif (« où »), le pronom devient « je » et le présent passe à l''imparfait (verbe introducteur au passé) : « où j''allais ». L''option a ne fait pas la concordance, b remplace « où » par « que », d mal place le mot interrogatif.', 6),
  ('fa4da252-76b0-5bbe-8764-979312b45f75', '6935b49a-94bb-5e55-958b-077f8392251d', 'À quel mode et temps est le verbe dans « Il faut que tu finisses tes devoirs. » ?', '[{"id":"a","text":"Indicatif présent"},{"id":"b","text":"Subjonctif présent"},{"id":"c","text":"Conditionnel présent"},{"id":"d","text":"Impératif présent"}]'::jsonb, 'b', 'Après « il faut que », le verbe se met au subjonctif présent : « que tu finisses ». À l''indicatif on aurait « tu finis » (a) ; le conditionnel donnerait « tu finirais » (c) ; l''impératif (d) n''a pas de « que » ni de sujet exprimé.', 1),
  ('0a29a5f8-19d1-5d00-8acd-762144ca1245', '6935b49a-94bb-5e55-958b-077f8392251d', 'Quelle phrase emploie le conditionnel présent pour exprimer la politesse ?', '[{"id":"a","text":"Je veux un verre d''eau."},{"id":"b","text":"Je voudrais un verre d''eau."},{"id":"c","text":"Je voulais un verre d''eau."},{"id":"d","text":"Je voudrai un verre d''eau."}]'::jsonb, 'b', '« voudrais » est le conditionnel présent, employé ici pour atténuer la demande (politesse). « veux » est l''indicatif présent (a), « voulais » l''imparfait (c), « voudrai » le futur simple (d).', 2),
  ('76b6593e-ee1c-5a91-b24e-e0d073a5bebb', '6935b49a-94bb-5e55-958b-077f8392251d', 'Dans « Quand j''étais petit, je jouais dans le jardin. », quelle est la valeur de l''imparfait ?', '[{"id":"a","text":"Une action soudaine et ponctuelle"},{"id":"b","text":"Une habitude ou une action répétée dans le passé"},{"id":"c","text":"Un ordre"},{"id":"d","text":"Une action future"}]'::jsonb, 'b', 'L''imparfait exprime ici une action habituelle/répétée du passé (« je jouais » régulièrement). L''action soudaine relèverait du passé simple (a), l''ordre de l''impératif (c), le futur d''un temps du futur (d).', 3),
  ('1cfec379-8300-5b53-b683-971a9cb396c4', '6935b49a-94bb-5e55-958b-077f8392251d', 'Identifie le temps composé dans la liste suivante :', '[{"id":"a","text":"Je mangeais"},{"id":"b","text":"Je mangerai"},{"id":"c","text":"J''avais mangé"},{"id":"d","text":"Je mange"}]'::jsonb, 'c', 'Un temps composé se forme avec un auxiliaire (avoir/être) + participe passé : « j''avais mangé » (plus-que-parfait). « mangeais » (imparfait), « mangerai » (futur simple) et « mange » (présent) sont des temps simples.', 4),
  ('33967eca-c9b5-5f4f-84e3-9519064494aa', '6935b49a-94bb-5e55-958b-077f8392251d', 'Quel verbe est correctement conjugué au subjonctif présent ?', '[{"id":"a","text":"Je veux que tu fais attention."},{"id":"b","text":"Je veux que tu fasses attention."},{"id":"c","text":"Je veux que tu feras attention."},{"id":"d","text":"Je veux que tu ferais attention."}]'::jsonb, 'b', 'Après « je veux que », on emploie le subjonctif présent : « que tu fasses ». « tu fais » est l''indicatif (a), « tu feras » le futur (c), « tu ferais » le conditionnel (d).', 5),
  ('9c6a44dd-b158-5d39-8636-2da68a6b6d9c', '6935b49a-94bb-5e55-958b-077f8392251d', 'Dans « Si tu travailles, tu réussiras. », quel est le mode et le temps de « réussiras » ?', '[{"id":"a","text":"Conditionnel présent"},{"id":"b","text":"Indicatif futur simple"},{"id":"c","text":"Subjonctif présent"},{"id":"d","text":"Indicatif imparfait"}]'::jsonb, 'b', 'Avec « si + présent » dans la subordonnée, la principale se met à l''indicatif futur simple : « tu réussiras ». Le conditionnel (a, « réussirais ») irait avec « si + imparfait » ; ce n''est ni un subjonctif (c) ni un imparfait (d).', 6),
  ('bdad7adc-e019-5996-a87e-6409a86248d0', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Complète correctement : « Il dormait quand le téléphone … . »', '[{"id":"a","text":"sonnait"},{"id":"b","text":"sonna"},{"id":"c","text":"sonnera"},{"id":"d","text":"sonne"}]'::jsonb, 'b', 'Dans un récit au passé, l''imparfait (« dormait ») décrit l''action en cours et le passé simple (« sonna ») marque l''action soudaine qui s''y produit. « sonnait » (a) décrirait une action durable, « sonnera » (c) est au futur, « sonne » (d) au présent.', 1),
  ('dae86223-f3ac-578b-8d7c-9dcbb14108e1', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Complète : « Je voulais que tu … plus tôt. »', '[{"id":"a","text":"viens"},{"id":"b","text":"viennes"},{"id":"c","text":"viendras"},{"id":"d","text":"venais"}]'::jsonb, 'b', 'Après un verbe de volonté (« je voulais que »), la subordonnée se met au subjonctif : « que tu viennes ». « viens » est l''indicatif présent (a), « viendras » le futur (c), « venais » l''imparfait de l''indicatif (d) — aucun n''est le subjonctif attendu.', 2),
  ('070508f4-ab03-5873-a546-2d8e0bf52886', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Complète : « Quand il eut terminé son repas, il … la table. »', '[{"id":"a","text":"débarrasse"},{"id":"b","text":"débarrassera"},{"id":"c","text":"débarrassa"},{"id":"d","text":"débarrassait"}]'::jsonb, 'c', 'Le passé antérieur (« eut terminé ») exprime une action achevée juste avant une autre au passé simple : « il débarrassa la table ». Le présent (a) et le futur (b) rompent la concordance au passé ; l''imparfait (d) ne marque pas l''action ponctuelle qui suit.', 3),
  ('8442fd5f-a8a3-5bd8-a9cd-488177b76852', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Au discours indirect passé : « Il a dit qu''il … le lendemain. » (parole d''origine : « Je partirai demain. »)', '[{"id":"a","text":"partira"},{"id":"b","text":"partait"},{"id":"c","text":"partirait"},{"id":"d","text":"part"}]'::jsonb, 'c', 'Au discours indirect avec un verbe introducteur au passé, le futur de la parole d''origine devient conditionnel présent : « qu''il partirait ». « partira » garde le futur (a), « partait » est l''imparfait (b), « part » le présent (d).', 4),
  ('550725f1-73d7-513e-956b-cabad8c09180', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Complète : « J''avais déjà fini mes devoirs lorsque mes amis … . »', '[{"id":"a","text":"arrivent"},{"id":"b","text":"arriveront"},{"id":"c","text":"sont arrivés"},{"id":"d","text":"arrivèrent"}]'::jsonb, 'd', 'Le plus-que-parfait (« j''avais fini ») marque l''antériorité par rapport à une action au passé simple dans un récit : « lorsque mes amis arrivèrent ». Le présent (a) et le futur (b) brisent la concordance au passé ; le passé composé (c) appartient plutôt au récit oral, alors que le récit ici est au passé simple.', 5),
  ('1fc3ea14-1df5-5242-b3f3-b309c23e2746', 'c6f2e772-c6cf-51e0-aa37-472c24c0db05', 'Complète : « Il pensait qu''elle … déjà partie. »', '[{"id":"a","text":"est"},{"id":"b","text":"était"},{"id":"c","text":"sera"},{"id":"d","text":"soit"}]'::jsonb, 'b', 'Le verbe introducteur « pensait » est au passé : la subordonnée se met à l''imparfait pour exprimer la simultanéité dans le passé : « qu''elle était déjà partie ». « est » (présent, a) et « sera » (futur, c) ne respectent pas la concordance ; « soit » (d) est un subjonctif, non requis après « penser » à la forme affirmative.', 6),
  ('7c5c580c-f674-5b9e-a61a-fa3b441de12e', 'a915ce86-0073-5030-8656-f315f5857408', 'Quelle figure de style reconnaît-on dans « Cet homme est un lion au combat. » ?', '[{"id":"a","text":"Une comparaison"},{"id":"b","text":"Une métaphore"},{"id":"c","text":"Une hyperbole"},{"id":"d","text":"Une personnification"}]'::jsonb, 'b', 'On identifie l''homme à un lion SANS outil de comparaison (« comme », « tel ») : c''est une métaphore. Avec « comme un lion », ce serait une comparaison (a) ; l''hyperbole exagère (c) ; la personnification prête des traits humains à une chose (d).', 1),
  ('53bfe9eb-7729-5bb4-8122-c4019895f276', 'a915ce86-0073-5030-8656-f315f5857408', 'Quelle figure de style est employée dans « Le vent murmurait dans les arbres. » ?', '[{"id":"a","text":"Une métaphore"},{"id":"b","text":"Une comparaison"},{"id":"c","text":"Une personnification"},{"id":"d","text":"Une antithèse"}]'::jsonb, 'c', 'On attribue au vent une action humaine (« murmurer ») : c''est une personnification. Ce n''est pas une identification imagée (métaphore, a), il n''y a pas d''outil de comparaison (b), ni d''opposition de deux idées (antithèse, d).', 2),
  ('acd5d4f4-3238-5d8b-8c16-1ba4346feb72', 'a915ce86-0073-5030-8656-f315f5857408', 'Dans « Je t''ai dit mille fois de ranger ta chambre ! », quelle figure exprime l''exagération ?', '[{"id":"a","text":"L''hyperbole"},{"id":"b","text":"La litote"},{"id":"c","text":"La métaphore"},{"id":"d","text":"L''euphémisme"}]'::jsonb, 'a', '« mille fois » exagère volontairement le nombre : c''est une hyperbole. La litote dit moins pour suggérer plus (b), l''euphémisme atténue (d), la métaphore est une image (c).', 3),
  ('30e3f6ac-866e-5a8e-8102-b6096ae5e4e5', 'a915ce86-0073-5030-8656-f315f5857408', 'Quel est le sens du préfixe « in- / im- » dans « impossible », « invisible » ?', '[{"id":"a","text":"Il indique la répétition"},{"id":"b","text":"Il exprime la négation, le contraire"},{"id":"c","text":"Il indique le lieu"},{"id":"d","text":"Il exprime le superlatif"}]'::jsonb, 'b', 'Le préfixe « in-/im- » exprime la négation : impossible = qui n''est pas possible, invisible = qui n''est pas visible. La répétition est marquée par « re- » (a) ; ce préfixe n''indique ni un lieu (c) ni un degré superlatif (d).', 4),
  ('c2cd69bc-3db3-5827-8a83-57bcf033de86', 'a915ce86-0073-5030-8656-f315f5857408', 'Quelle phrase contient une antithèse ?', '[{"id":"a","text":"Il marche lentement vers la maison."},{"id":"b","text":"Cet enfant est vif comme l''éclair."},{"id":"c","text":"Ici tout n''est qu''ombre et lumière."},{"id":"d","text":"La rivière chantait doucement."}]'::jsonb, 'c', 'L''antithèse rapproche deux mots de sens opposés : « ombre » et « lumière ». L''option b est une comparaison, d une personnification, a une phrase ordinaire sans figure d''opposition.', 5),
  ('fe6bf775-0956-5d95-956d-e49d795a9617', 'a915ce86-0073-5030-8656-f315f5857408', 'Lisez la phrase : « Après l''examen, il n''était pas mécontent de sa note. »

Quelle figure de style et quel sens véhicule « n''était pas mécontent » ?', '[{"id":"a","text":"Une hyperbole : il était extrêmement déçu."},{"id":"b","text":"Une litote : il était en réalité plutôt satisfait."},{"id":"c","text":"Une métaphore : sa note était un trésor."},{"id":"d","text":"Une personnification : la note ressentait quelque chose."}]'::jsonb, 'b', '« n''était pas mécontent » est une litote : on dit moins (forme atténuée et négative) pour suggérer plus (il était en fait content). Ce n''est pas une exagération (a), il n''y a aucune image (c) ni objet humanisé (d).', 6),
  ('04989013-8b32-54af-9f7c-bfda1f5b94c3', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Lisez ce passage :

« La girafe est un mammifère herbivore. Elle possède un long cou qui lui permet d''atteindre les feuilles des arbres les plus hauts. On la trouve principalement dans les savanes d''Afrique. »

À quel type de texte appartient ce passage ?', '[{"id":"a","text":"Texte narratif"},{"id":"b","text":"Texte explicatif (informatif)"},{"id":"c","text":"Texte argumentatif"},{"id":"d","text":"Texte injonctif"}]'::jsonb, 'b', 'Le passage donne des informations objectives pour faire connaître un animal : c''est un texte explicatif/informatif. Il ne raconte pas d''histoire (a), ne défend pas d''opinion (c) et ne donne pas d''instructions (d).', 1),
  ('b78c3fb5-fcde-5273-a96f-d92327df9696', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Quel texte est de type injonctif ?', '[{"id":"a","text":"Il était une fois un roi qui vivait dans un grand château."},{"id":"b","text":"Mélangez la farine et les œufs, puis ajoutez le lait."},{"id":"c","text":"À mon avis, lire est le meilleur des loisirs."},{"id":"d","text":"Le ciel était gris et la mer agitée."}]'::jsonb, 'b', 'Le texte injonctif donne des consignes, souvent à l''impératif : « Mélangez… ajoutez… » (recette). L''option a est narrative, c argumentative, d descriptive.', 2),
  ('3cc97403-7633-5b14-a33a-bbaf609673fe', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Dans le schéma narratif, comment appelle-t-on l''événement qui rompt l''équilibre initial et lance l''action ?', '[{"id":"a","text":"La situation finale"},{"id":"b","text":"L''élément perturbateur (déclencheur)"},{"id":"c","text":"La situation initiale"},{"id":"d","text":"Le dénouement"}]'::jsonb, 'b', 'L''élément perturbateur (ou déclencheur) brise l''équilibre de la situation initiale et met l''histoire en mouvement. La situation initiale (c) présente l''équilibre de départ, les péripéties suivent, et le dénouement (d) puis la situation finale (a) closent le récit.', 3),
  ('1ef3f634-b2aa-5389-83a4-70599facfb28', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Quel connecteur logique exprime une CONSÉQUENCE ?', '[{"id":"a","text":"parce que"},{"id":"b","text":"par conséquent"},{"id":"c","text":"cependant"},{"id":"d","text":"d''abord"}]'::jsonb, 'b', '« par conséquent » introduit la conséquence d''un fait. « parce que » exprime la cause (a), « cependant » l''opposition (c), « d''abord » l''ordre/le temps (d).', 4),
  ('16c1a42e-8fb9-5626-bedc-2fe32244e119', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Lisez ce passage :

« Je pense que les jeux vidéo ne sont pas seulement une perte de temps. En effet, certains développent la réflexion et la rapidité. C''est pourquoi il faut savoir les utiliser avec mesure. »

À quel type de texte appartient ce passage ?', '[{"id":"a","text":"Texte descriptif"},{"id":"b","text":"Texte argumentatif"},{"id":"c","text":"Texte narratif"},{"id":"d","text":"Texte explicatif"}]'::jsonb, 'b', 'L''auteur défend une opinion (« Je pense que… ») avec un argument (« En effet… ») et une conclusion (« C''est pourquoi… ») : c''est un texte argumentatif. Il ne décrit pas (a), ne raconte pas (c) et ne se contente pas d''informer objectivement (d).', 5),
  ('6c9ed809-1bc2-594e-8afc-b4b3607537a4', '8ce9c4aa-e64f-5a76-9812-ada88908a485', 'Dans un paragraphe argumentatif, quel est le rôle de la phrase introduite par « Par exemple » ?', '[{"id":"a","text":"Annoncer l''idée principale de l''auteur."},{"id":"b","text":"Illustrer l''argument par un cas concret."},{"id":"c","text":"Réfuter l''opinion adverse."},{"id":"d","text":"Conclure le paragraphe."}]'::jsonb, 'b', '« Par exemple » introduit une illustration : un cas concret qui appuie l''argument. L''idée principale s''annonce sans connecteur d''exemple (a), la réfutation emploie « certes… mais » (c), et la conclusion utilise « ainsi », « donc » (d).', 6),
  ('533df0ee-78f7-57bc-8a57-dd9eab28fed3', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Lisez ce texte :

« Karim avait toujours détesté la mer. Pourtant, ce matin-là, debout sur la plage, il sentit son cœur s''apaiser au rythme des vagues. Pour la première fois, l''eau ne lui faisait plus peur. »

Quelle est l''idée essentielle du texte ?', '[{"id":"a","text":"Karim a toujours adoré la mer."},{"id":"b","text":"Karim, qui craignait la mer, commence à l''apprécier."},{"id":"c","text":"Karim se noie dans les vagues."},{"id":"d","text":"Karim part en voyage très loin."}]'::jsonb, 'b', 'Le « Pourtant » oppose son ancienne aversion (« avait toujours détesté ») à son apaisement présent (« ne lui faisait plus peur ») : Karim, qui craignait la mer, commence à l''apprécier. L''option a contredit « détesté », c et d ajoutent des faits absents du texte.', 1),
  ('3546773d-9c4c-56d2-8943-39401375c3fb', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Lisez ce texte :

« Les abeilles ne sont pas de simples insectes. En butinant les fleurs, elles transportent le pollen et permettent ainsi aux plantes de se reproduire. Sans elles, de nombreuses cultures disparaîtraient. »

À quel type de texte appartient ce passage ?', '[{"id":"a","text":"Texte narratif"},{"id":"b","text":"Texte explicatif"},{"id":"c","text":"Texte injonctif"},{"id":"d","text":"Texte poétique"}]'::jsonb, 'b', 'Le passage explique objectivement le rôle des abeilles (pollinisation, reproduction des plantes) pour informer le lecteur : c''est un texte explicatif. Il ne raconte pas d''histoire (a), ne donne pas d''ordres (c) et n''a pas de visée poétique (d).', 2),
  ('7870668f-8f7e-5437-9372-0c3b6dce796b', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Lisez cette phrase :

« Le voyageur, exténué, posa enfin son sac : il n''en pouvait plus. »

Dans ce contexte, que signifie le mot « exténué » ?', '[{"id":"a","text":"Très en colère"},{"id":"b","text":"Extrêmement fatigué, épuisé"},{"id":"c","text":"Très heureux"},{"id":"d","text":"Surpris"}]'::jsonb, 'b', 'La suite « il n''en pouvait plus » et le geste de poser son sac confirment qu''« exténué » signifie épuisé, extrêmement fatigué. La colère (a), la joie (c) et la surprise (d) ne correspondent pas à l''idée d''épuisement décrite.', 3),
  ('7d312960-34cc-5bc3-9b68-afcd570ad6e3', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Lisez cette phrase tirée d''un texte :

« Malgré ses nombreux échecs, elle refusait d''abandonner. »

Que suggère le connecteur « Malgré » sur le caractère du personnage ?', '[{"id":"a","text":"Le personnage est paresseux et renonce vite."},{"id":"b","text":"Le personnage est persévérant et déterminé."},{"id":"c","text":"Le personnage n''a jamais connu d''échec."},{"id":"d","text":"Le personnage est indifférent à tout."}]'::jsonb, 'b', '« Malgré ses nombreux échecs » introduit un obstacle qui n''empêche pas l''action « elle refusait d''abandonner » : on infère un personnage persévérant. L''option a est contredite par « refusait d''abandonner », c par « nombreux échecs », d ne correspond à aucun indice.', 4),
  ('a6f3d8bc-773e-5241-9dfc-c92258736bc4', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Vous rédigez l''introduction d''un texte argumentatif sur l''importance du sport. Quelle phrase constitue la meilleure phrase de thèse ?', '[{"id":"a","text":"Le sport, c''est quand on bouge."},{"id":"b","text":"Selon moi, pratiquer un sport régulièrement est essentiel pour la santé et le bien-être."},{"id":"c","text":"Est-ce que le sport est utile ?"},{"id":"d","text":"Un jour, je suis allé courir au parc."}]'::jsonb, 'b', 'Une phrase de thèse annonce clairement l''opinion que l''on va défendre : « pratiquer un sport… est essentiel pour la santé et le bien-être ». L''option a n''est qu''une définition vague, c une question (non une prise de position), d le début d''un récit.', 5),
  ('ee955f83-405f-51c7-8fca-9267645d771e', 'e2fae353-834e-5ce1-8da2-b79f02a9dfe0', 'Vous voulez enchaîner deux arguments dans un paragraphe. Vous avez ces phrases :

1) De plus, le sport apprend à respecter des règles et les autres joueurs.
2) Tout d''abord, le sport renforce le corps et protège de nombreuses maladies.

Quel est le bon ordre logique ?', '[{"id":"a","text":"1 puis 2"},{"id":"b","text":"2 puis 1"},{"id":"c","text":"Les deux ordres se valent."},{"id":"d","text":"Aucun des deux n''est correct."}]'::jsonb, 'b', 'Le connecteur « Tout d''abord » (2) ouvre la série d''arguments, et « De plus » (1) ajoute un argument supplémentaire : l''ordre logique est 2 puis 1. Placer « De plus » en premier (a) serait incohérent, car il suppose qu''un argument précède déjà ; les ordres ne se valent donc pas (c, d).', 6),
  ('2a483811-cc0a-5d76-a7cf-955674b98ddb', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'ما الفرق بين الكلمة المعربة والكلمة المبنيّة؟', '[{"id":"a","text":"المعربة يتغيّر آخرها بتغيّر موقعها، والمبنيّة يلزم آخرها حالة واحدة"},{"id":"b","text":"المعربة اسم دائمًا والمبنيّة فعل دائمًا"},{"id":"c","text":"المعربة تُنصب فقط والمبنيّة تُرفع فقط"},{"id":"d","text":"لا فرق بينهما في الاستعمال"}]'::jsonb, 'a', 'المعرب تتغيّر علامة آخره (رفع/نصب/جرّ/جزم) بحسب موقعه في الجملة، أمّا المبنيّ فيلزم آخره حركة واحدة لا تتغيّر مهما تغيّر موقعه. والقول إنّ المعرب اسم والمبنيّ فعل خطأ، فالماضي مبنيّ وهو فعل والمضارع معرب وهو فعل.', 1),
  ('dc240339-7154-5598-8bfc-8ad5062c796e', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'أيّ الكلمات التالية مبنيّ من الأسماء؟', '[{"id":"a","text":"الكتابُ"},{"id":"b","text":"هذا"},{"id":"c","text":"مدرسةٌ"},{"id":"d","text":"تلميذٌ"}]'::jsonb, 'b', '«هذا» اسم إشارة مبنيّ لا تتغيّر حركته بتغيّر موقعه، وكذلك الضمائر وأسماء الاستفهام والشرط من الأسماء المبنيّة. أمّا «الكتاب» و«مدرسة» و«تلميذ» فأسماء معربة تتغيّر علامتها بحسب الموقع.', 2),
  ('eaed1ca1-fb64-5d3c-860a-0f7145007bc3', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «سلّمتُ على المعلّمينَ»، ما علامة جرّ «المعلّمينَ»؟', '[{"id":"a","text":"الكسرة لأنّه اسم مفرد"},{"id":"b","text":"الياء لأنّه جمع مذكّر سالم"},{"id":"c","text":"الفتحة لأنّه ممنوع من الصرف"},{"id":"d","text":"الألف لأنّه مثنّى"}]'::jsonb, 'b', '«المعلّمين» جمع مذكّر سالم مجرور بحرف الجرّ «على»، وعلامة جرّه الياء نيابة عن الكسرة. والكسرة علامة جرّ الاسم المفرد لا الجمع السالم.', 3),
  ('f21d5168-79c5-5a2c-856f-9f018163d4dd', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «لن أتأخّرَ عن الموعدِ»، ما إعراب «أتأخّرَ»؟', '[{"id":"a","text":"فعل مضارع مرفوع بالضمّة"},{"id":"b","text":"فعل مضارع مجزوم بالسكون"},{"id":"c","text":"فعل مضارع منصوب بالفتحة لأنّ «لن» أداة نصب"},{"id":"d","text":"فعل ماضٍ مبنيّ على الفتح"}]'::jsonb, 'c', '«لن» حرف نصب ونفي واستقبال ينصب المضارع، فـ«أتأخّرَ» منصوب وعلامة نصبه الفتحة. ولا يُجزم لأنّ الجزم يكون بأدوات الجزم كـ«لم» لا بـ«لن».', 4),
  ('755ca542-4943-570f-9d6a-ff928c134626', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «جاء القاضي»، لماذا قُدّرت الضمّة على «القاضي» ولم تظهر؟', '[{"id":"a","text":"لأنّه مبنيّ لا يُعرب"},{"id":"b","text":"لأنّه اسم منقوص آخره ياء فتُقدَّر عليه الضمّة للثقل"},{"id":"c","text":"لأنّه ممنوع من الصرف"},{"id":"d","text":"لأنّه جمع تكسير"}]'::jsonb, 'b', '«القاضي» اسم منقوص (معرب آخره ياء لازمة قبلها كسر)، تُقدَّر عليه الضمّة والكسرة للثقل، وتظهر الفتحة لخفّتها. فهو فاعل مرفوع بضمّة مقدّرة على الياء منع من ظهورها الثقل.', 5),
  ('abb9556b-1be3-51c2-a675-f96041ced204', 'bc080ca8-d769-5478-8470-bdc6bc3e9583', 'في «المجتهدونَ ينجحونَ»، بِمَ رُفع «المجتهدونَ» وبِمَ رُفع «ينجحونَ»؟', '[{"id":"a","text":"كلاهما بالضمّة"},{"id":"b","text":"الأوّل بالواو (جمع مذكّر سالم) والثاني بثبوت النون (من الأفعال الخمسة)"},{"id":"c","text":"الأوّل بالألف والثاني بالواو"},{"id":"d","text":"الأوّل بثبوت النون والثاني بالواو"}]'::jsonb, 'b', '«المجتهدون» جمع مذكّر سالم مرفوع بالواو نيابة عن الضمّة. و«ينجحون» فعل مضارع من الأفعال الخمسة (يتّصل به واو الجماعة) مرفوع بثبوت النون نيابة عن الضمّة. فعلامتا الرفع مختلفتان لاختلاف نوع الكلمتين.', 6),
  ('2e1816a2-33b0-5688-acd6-236456dc4c61', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'ما عمل «كان» وأخواتها في الجملة الاسمية؟', '[{"id":"a","text":"ترفع المبتدأ (اسمها) وتنصب الخبر (خبرها)"},{"id":"b","text":"تنصب المبتدأ وترفع الخبر"},{"id":"c","text":"ترفع المبتدأ والخبر معًا"},{"id":"d","text":"تجرّ المبتدأ والخبر"}]'::jsonb, 'a', 'الأفعال الناسخة (كان وأخواتها) ترفع المبتدأ ويُسمّى اسمها، وتنصب الخبر ويُسمّى خبرها. أمّا الحروف الناسخة (إنّ وأخواتها) فهي التي تنصب الاسم وترفع الخبر، فلا يُخلط بينهما.', 1),
  ('7fe86a42-2eaf-5259-b771-24c8ff86cb8e', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'أيّ الجمل التالية تحتوي على فعل ناسخ؟', '[{"id":"a","text":"إنّ السماءَ صافيةٌ"},{"id":"b","text":"صار الجوُّ باردًا"},{"id":"c","text":"لعلّ الغائبَ حاضرٌ"},{"id":"d","text":"السماءُ صافيةٌ"}]'::jsonb, 'b', '«صار» فعل ناسخ من أخوات «كان» يدلّ على التحوّل، رفع «الجوُّ» اسمًا له ونصب «باردًا» خبرًا له. أمّا «إنّ» و«لعلّ» فحرفان ناسخان لا فعلان، والجملة الأخيرة جملة اسمية بلا ناسخ.', 2),
  ('6f5c592a-efb1-59d8-b290-39d81bbb50ec', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «إنّ المعلّمينَ مخلصونَ»، ما إعراب «المعلّمينَ»؟', '[{"id":"a","text":"اسم إنّ منصوب وعلامة نصبه الياء (جمع مذكّر سالم)"},{"id":"b","text":"خبر إنّ مرفوع بالواو"},{"id":"c","text":"مبتدأ مرفوع بالضمّة"},{"id":"d","text":"اسم إنّ منصوب وعلامة نصبه الفتحة"}]'::jsonb, 'a', '«إنّ» حرف ناسخ ينصب اسمه، و«المعلّمين» اسمها منصوب، وهو جمع مذكّر سالم فعلامة نصبه الياء نيابة عن الفتحة لا الفتحة الظاهرة.', 3),
  ('9d1d2571-8452-5bdf-817d-310cca9dcf83', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'أيٌّ من الحروف الناسخة يفيد التشبيه؟', '[{"id":"a","text":"ليت"},{"id":"b","text":"لعلّ"},{"id":"c","text":"كأنّ"},{"id":"d","text":"لكنّ"}]'::jsonb, 'c', '«كأنّ» تفيد التشبيه (كأنّ العلمَ نورٌ). أمّا «ليت» فللتمنّي، و«لعلّ» للترجّي، و«لكنّ» للاستدراك. فلكلّ حرف ناسخ معناه الخاصّ.', 4),
  ('efb5ba4b-c0cf-5bef-bf94-abe3bca30512', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «كان الجوُّ معتدلًا»، إذا حذفنا «كان» فما إعراب «الجوُّ» و«معتدل»؟', '[{"id":"a","text":"الجوُّ مبتدأ مرفوع و«معتدلٌ» خبر مرفوع"},{"id":"b","text":"الجوُّ اسم كان و«معتدلًا» خبرها منصوب"},{"id":"c","text":"الجوُّ فاعل و«معتدلًا» مفعول به"},{"id":"d","text":"الجوُّ خبر مقدّم و«معتدلًا» مبتدأ مؤخّر"}]'::jsonb, 'a', 'بحذف الناسخ تعود الجملة إلى أصلها الاسمي: «الجوُّ معتدلٌ»، فـ«الجوُّ» مبتدأ مرفوع و«معتدلٌ» خبر مرفوع. وهذا يُبرز أنّ عمل «كان» هو نصب الخبر فقط مع إبقاء رفع المبتدأ.', 5),
  ('3a330277-b986-55a7-834f-8b23af6c0f1e', 'e2612517-c58f-57ed-8aec-aea7ba7dbdf8', 'في «إنّ في الحديقةِ أزهارًا»، أين خبر «إنّ» وأين اسمها؟', '[{"id":"a","text":"«أزهارًا» اسمها مؤخّر منصوب، والخبر شبه الجملة «في الحديقة» مقدّم"},{"id":"b","text":"«الحديقة» اسمها و«أزهارًا» خبرها"},{"id":"c","text":"«أزهارًا» خبرها و«الحديقة» اسمها"},{"id":"d","text":"لا اسم لها ولا خبر"}]'::jsonb, 'a', 'تقدّم خبر «إنّ» (شبه الجملة «في الحديقة») على اسمها لأنّ الاسم نكرة «أزهارًا». فالخبر شبه جملة مقدّم في محلّ رفع، و«أزهارًا» اسم إنّ مؤخّر منصوب بالفتحة. ويجب التقديم هنا لئلّا يبدأ الكلام باسم نكرة.', 6),
  ('8dc09b7c-9e14-554c-b4e6-5b47264bf51a', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «شربتُ الماءَ»، ما إعراب «الماءَ»؟', '[{"id":"a","text":"مفعول به منصوب وعلامة نصبه الفتحة"},{"id":"b","text":"فاعل مرفوع بالضمّة"},{"id":"c","text":"حال منصوب"},{"id":"d","text":"تمييز منصوب"}]'::jsonb, 'a', '«الماءَ» وقع عليه فعل الشرب فهو مفعول به منصوب وعلامة نصبه الفتحة الظاهرة. وليس فاعلًا لأنّ الفاعل هو التاء في «شربتُ».', 1),
  ('fb0faa2d-c8aa-5ca1-a6fe-b354bcc1d763', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'أيّ الجمل التالية تحتوي على مفعول مطلق؟', '[{"id":"a","text":"سافرتُ صباحًا"},{"id":"b","text":"اجتهدتُ اجتهادًا"},{"id":"c","text":"قرأتُ كتابًا"},{"id":"d","text":"وقفتُ احترامًا"}]'::jsonb, 'b', '«اجتهادًا» مصدر من لفظ الفعل «اجتهدتُ» يؤكّده، فهو مفعول مطلق منصوب. أمّا «صباحًا» فظرف زمان، و«كتابًا» مفعول به، و«احترامًا» مفعول لأجله.', 2),
  ('4c8c7d81-1609-5213-8f33-d0a9e1af1ab0', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «عاد الجنودُ منتصرينَ»، ما نوع «منتصرينَ» وعلامة نصبه؟', '[{"id":"a","text":"مفعول به منصوب بالفتحة"},{"id":"b","text":"حال منصوب وعلامة نصبه الياء (جمع مذكّر سالم)"},{"id":"c","text":"تمييز منصوب بالفتحة"},{"id":"d","text":"نعت منصوب بالكسرة"}]'::jsonb, 'b', '«منتصرين» يبيّن هيئة الجنود وقت العودة فهو حال منصوب، وهو جمع مذكّر سالم فعلامة نصبه الياء نيابة عن الفتحة. وليس مفعولًا به لأنّه لم يقع عليه الفعل.', 3),
  ('29d79992-2c56-5b6f-9dea-93fdce7f22ef', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «جلستُ تحتَ الشجرةِ»، ما إعراب «تحتَ»؟', '[{"id":"a","text":"مفعول لأجله منصوب"},{"id":"b","text":"مفعول مطلق منصوب"},{"id":"c","text":"مفعول فيه (ظرف مكان) منصوب"},{"id":"d","text":"حال منصوب"}]'::jsonb, 'c', '«تحتَ» يدلّ على مكان وقوع الجلوس فهو مفعول فيه (ظرف مكان) منصوب بالفتحة، و«الشجرة» مضاف إليه مجرور. وليس مفعولًا لأجله لأنّه لا يبيّن سبب الفعل.', 4),
  ('90b712e4-7c3a-544d-9fc0-52c7c2b4f32e', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «حضر الطلابُ إلّا طالبًا»، ما إعراب «طالبًا» ولماذا؟', '[{"id":"a","text":"بدل من «الطلاب» مرفوع"},{"id":"b","text":"مستثنى بإلّا منصوب لأنّ الكلام تامّ مثبت"},{"id":"c","text":"فاعل مرفوع"},{"id":"d","text":"تمييز منصوب"}]'::jsonb, 'b', 'الكلام تامّ (ذُكر المستثنى منه «الطلاب») مثبت (لا نفي فيه)، فيجب نصب المستثنى بعد «إلّا»، فـ«طالبًا» مستثنى منصوب بالفتحة. ولو كان الكلام منفيًّا لجاز فيه النصب على الاستثناء أو الإتباع للبدليّة.', 5),
  ('20e1cd8f-7099-5a40-8f8a-d22091bf2d7f', '4bc94ff4-5fd0-5695-bb00-4256e3e9a8c1', 'في «امتلأ الإناءُ ماءً» و«اشتريتُ مترًا قماشًا»، ما القاسم المشترك بين «ماءً» و«قماشًا»؟', '[{"id":"a","text":"كلاهما مفعول به منصوب"},{"id":"b","text":"كلاهما تمييز منصوب يُزيل الإبهام (تمييز ذات/نسبة)"},{"id":"c","text":"كلاهما حال منصوب"},{"id":"d","text":"كلاهما مفعول مطلق"}]'::jsonb, 'b', '«ماءً» تمييز نسبة يُزيل إبهام النسبة (بماذا امتلأ؟)، و«قماشًا» تمييز ذات يُزيل إبهام المقدار (متر من ماذا؟)، وكلاهما اسم نكرة منصوب يُفسّر المبهم. فالقاسم المشترك أنّهما تمييز منصوب لا مفعول به ولا حال.', 6),
  ('feb27f89-41ca-5d2a-9cb3-41a25c52619d', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «يا طالبُ اجتهدْ»، ما نوع المنادى «طالبُ» وحكمه؟', '[{"id":"a","text":"نكرة مقصودة مبنيّ على الضمّ في محلّ نصب"},{"id":"b","text":"مضاف منصوب بالفتحة"},{"id":"c","text":"نكرة غير مقصودة منصوب"},{"id":"d","text":"شبيه بالمضاف منصوب"}]'::jsonb, 'a', '«طالبُ» نكرة مقصودة (يُنادى بها طالب معيّن حاضر)، وحكمها البناء على الضمّ في محلّ نصب مثل العلم المفرد. ولو كانت نكرة غير مقصودة لنُصبت بالتنوين.', 1),
  ('b98146d5-625e-5d11-8d29-b1d9033e283e', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'أيّ الجمل التالية تمثّل أسلوب استفهام؟', '[{"id":"a","text":"ما أروعَ المنظرَ!"},{"id":"b","text":"متى يبدأ الامتحانُ؟"},{"id":"c","text":"يا محمّدُ تعالَ"},{"id":"d","text":"الصدقَ يا أبنائي"}]'::jsonb, 'b', '«متى يبدأ الامتحان؟» أسلوب استفهام يطلب تعيين الزمن بأداة الاستفهام «متى». أمّا الأولى فتعجّب، والثالثة نداء، والرابعة إغراء.', 2),
  ('fce6128e-2dff-56e5-af0d-e84ec9ed43f5', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «إيّاكَ والكذبَ»، ما الأسلوب وما إعراب «الكذبَ»؟', '[{"id":"a","text":"إغراء، و«الكذب» منصوب بفعل محذوف تقديره الزم"},{"id":"b","text":"تحذير، و«الكذب» منصوب بفعل محذوف تقديره احذر"},{"id":"c","text":"اختصاص، و«الكذب» مفعول به"},{"id":"d","text":"نداء، و«الكذب» منادى"}]'::jsonb, 'b', '«إيّاكَ والكذبَ» أسلوب تحذير يُحذّر من أمر مكروه (الكذب)، و«الكذبَ» منصوب بفعل محذوف وجوبًا تقديره «احذر». ويختلف عن الإغراء الذي يحثّ على أمر محمود.', 3),
  ('00a0477d-0c72-5ad6-b989-2b2716b1154c', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «ما أجملَ السماءَ!»، ما إعراب «أجملَ»؟', '[{"id":"a","text":"اسم تفضيل"},{"id":"b","text":"فعل ماضٍ جامد للتعجّب مبنيّ على الفتح"},{"id":"c","text":"فعل أمر مبنيّ على السكون"},{"id":"d","text":"اسم مبنيّ على الفتح"}]'::jsonb, 'b', 'في صيغة «ما أفعلَ» التعجّبية، «أجملَ» فعل ماضٍ جامد للتعجّب مبنيّ على الفتح، و«ما» اسم تعجّب مبتدأ، و«السماءَ» مفعول به منصوب. وليس اسم تفضيل وإن تشابهت الصورة.', 4),
  ('30e3371a-46e4-5ccd-88b6-c90cc1d034e8', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'في «نحنُ — العربَ — نُكرمُ الضيفَ»، ما إعراب «العربَ»؟', '[{"id":"a","text":"منادى منصوب"},{"id":"b","text":"مفعول به منصوب"},{"id":"c","text":"اسم منصوب على الاختصاص بفعل محذوف تقديره أخصّ"},{"id":"d","text":"بدل من الضمير «نحن» مرفوع"}]'::jsonb, 'c', '«العربَ» اسم منصوب على الاختصاص يأتي بعد ضمير ليُخصّصه ويوضّحه، وهو منصوب بفعل محذوف وجوبًا تقديره «أخصّ» أو «أعني». ولا يُعرب بدلًا لأنّ المختصّ لا يتبع ما قبله في الإعراب بل يُنصب.', 5),
  ('0927fb33-92a2-5c54-abdc-9140e573a15e', '0200deb9-527b-54b0-bc4a-4d2cf50bfb05', 'أيّ الصيغتين تُمثّل التعجّب القياسي صياغةً صحيحة من الفعل «اجتهد»؟', '[{"id":"a","text":"ما أكثرَ اجتهادَه! / أكثِرْ باجتهادِه!"},{"id":"b","text":"ما أجتهدَه! / أجتهِدْ به!"},{"id":"c","text":"ما اجتهدَه! / اجتهدْ به!"},{"id":"d","text":"ما أجهدَه! / أجهِدْ به!"}]'::jsonb, 'a', '«اجتهد» فعل غير ثلاثي (خماسي)، ولا يُصاغ منه التعجّب مباشرة، فيُتوسَّل بمصدره مع فعل تعجّب مساعد من الثلاثي: «ما أكثرَ اجتهادَه!» و«أكثِرْ باجتهادِه!». فالصياغة المباشرة من الفعل الزائد على الثلاثي غير قياسية.', 6),
  ('a24ff209-0174-5ea7-a1f6-4edc6c4392bf', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «كَتَبَ»؟', '[{"id":"a","text":"فَعِلَ"},{"id":"b","text":"فَعَلَ"},{"id":"c","text":"فَعُلَ"},{"id":"d","text":"أَفعَلَ"}]'::jsonb, 'b', '«كَتَبَ» فعل ثلاثي مجرّد مفتوح العين: الكاف فاء والتاء عين والباء لام، وكلّها مفتوحة، فوزنه «فَعَلَ». ولو كُسرت العين لكان «فَعِلَ» ولو ضُمّت لكان «فَعُلَ».', 1),
  ('633f929b-cbb2-5d1b-bd2f-60dbcc92ee60', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما المعنى الصرفيّ الغالب لوزن «فاعَلَ» مثل «قاتلَ» و«شاركَ»؟', '[{"id":"a","text":"المطاوعة"},{"id":"b","text":"المشاركة بين اثنين فأكثر"},{"id":"c","text":"الطلب"},{"id":"d","text":"الصيرورة"}]'::jsonb, 'b', 'وزن «فاعَلَ» يدلّ غالبًا على المشاركة بين طرفين: «قاتلَ» (شارك في القتال) و«شاركَ» و«كاتبَ». ويختلف عن «انفعل» الدالّ على المطاوعة و«استفعل» الدالّ على الطلب.', 2),
  ('272ce132-39c4-5714-ba87-676120b21599', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «أَكرَمَ»، وما الحرف الزائد فيه؟', '[{"id":"a","text":"أَفعَلَ، والزائد الهمزة"},{"id":"b","text":"فَعَّلَ، والزائد تضعيف العين"},{"id":"c","text":"فَاعَلَ، والزائد الألف"},{"id":"d","text":"افتَعَلَ، والزائد التاء"}]'::jsonb, 'a', 'جذر «أكرم» هو (ك ر م)، زِيدت في أوّله همزة قطع. الكاف فاء والراء عين والميم لام، فوزنه «أَفعَلَ» والزائد فيه الهمزة. ووزن «أفعل» يفيد التعدية غالبًا.', 3),
  ('54959ee1-1a72-5103-8939-a6a6e7c4bb95', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'أيّ الأفعال التالية ثلاثيّ مجرّد؟', '[{"id":"a","text":"استغفرَ"},{"id":"b","text":"تعلّمَ"},{"id":"c","text":"نصرَ"},{"id":"d","text":"انطلقَ"}]'::jsonb, 'c', '«نصرَ» فعل ثلاثي مجرّد أحرفه كلّها أصليّة (ن ص ر) على وزن «فَعَلَ». أمّا «استغفر» و«تعلّم» و«انطلق» فأفعال مزيدة فيها حروف زائدة على الأصل.', 4),
  ('451540ac-5426-563a-a3a7-a1eed11c9ae7', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'ما وزن الفعل «اِنكَسَرَ»، وما الحرفان الزائدان فيه؟', '[{"id":"a","text":"افتَعَلَ، والزائدان الهمزة والتاء"},{"id":"b","text":"تَفَاعَلَ، والزائدان التاء والألف"},{"id":"c","text":"انفَعَلَ، والزائدان همزة الوصل والنون"},{"id":"d","text":"استَفعَلَ، والزائدات الهمزة والسين والتاء"}]'::jsonb, 'c', 'جذر «انكسر» هو (ك س ر). الكلمة: همزة وصل - نون - كاف - سين - راء. الكاف فاء والسين عين والراء لام، والزائدان هما همزة الوصل في الأوّل والنون بعدها، فوزنه «انفَعَلَ»، وهو يدلّ على المطاوعة.', 5),
  ('e2d129a7-d540-5300-a162-ea47462701be', '0c8ee4e5-4c7b-55ba-8fc4-58df935744e1', 'الفعل «حَوقَلَ» (بمعنى قال: لا حول ولا قوة إلّا بالله) أُلحق بالرباعي المجرّد، فما وزنه؟', '[{"id":"a","text":"فَعّلَ"},{"id":"b","text":"فَوعَلَ"},{"id":"c","text":"فاعَلَ"},{"id":"d","text":"أَفعَلَ"}]'::jsonb, 'b', '«حَوقَلَ» من الأفعال الملحقة بالرباعي (فَعلَلَ)، لكنّه يُوزن بإبقاء حروفه الأصليّة الزائدة في موضعها: الحاء فاء، والواو محسوبة في الميزان كما هي لأنّها زائدة للإلحاق، والقاف عين، واللام لام، فوزنه «فَوعَلَ». فالملحق بالرباعي يُوزن بحروفه لا بـ«فعللَ» مطلقًا.', 6),
  ('4fdf2d40-6c5f-54d7-9f80-33f78b29a966', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما الفرق بين الاسم المشتقّ والاسم الجامد؟', '[{"id":"a","text":"المشتقّ مأخوذ من غيره ويدلّ على ذات ومعنى، والجامد لا يُؤخذ من غيره"},{"id":"b","text":"المشتقّ معرب والجامد مبنيّ"},{"id":"c","text":"المشتقّ اسم والجامد فعل"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'الاسم المشتقّ يُؤخذ من المصدر/الفعل ويدلّ على ذات اقترن بها معنى (كاتب، مكتوب)، أمّا الجامد فلا يُشتقّ من غيره (رجل، حجر). والقول إنّ الفرق إعراب أو نوع كلمة خطأ.', 1),
  ('5e5312fb-4836-55eb-a1f9-50e3899be301', '9884a453-057b-5889-b6ea-db113219d2c2', 'أيّ الكلمات التالية صيغة مبالغة؟', '[{"id":"a","text":"عالِم"},{"id":"b","text":"علّامة"},{"id":"c","text":"معلوم"},{"id":"d","text":"مَعلَم"}]'::jsonb, 'b', '«علّامة» على وزن «فعّالة» وهي من صيغ المبالغة الدالّة على كثرة العلم وشدّته. أمّا «عالِم» فاسم فاعل، و«معلوم» اسم مفعول، و«معلَم» اسم مكان.', 2),
  ('97aaf915-8a3a-5dcb-b8fa-66cece45dd8a', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما اسم الفاعل من الفعل «نصرَ»؟', '[{"id":"a","text":"مَنصور"},{"id":"b","text":"ناصِر"},{"id":"c","text":"نَصير"},{"id":"d","text":"نَصّار"}]'::jsonb, 'b', 'اسم الفاعل من الثلاثي يُصاغ على وزن «فاعِل»، فمن «نصرَ» نقول «ناصِر» (من يقوم بالنصر). أمّا «منصور» فاسم مفعول، و«نصير» صفة مشبّهة، و«نصّار» صيغة مبالغة.', 3),
  ('56b18496-fce1-511f-9448-275b8ec60b71', '9884a453-057b-5889-b6ea-db113219d2c2', 'ما وزن اسم المفعول من الفعل الثلاثي «فهمَ»؟', '[{"id":"a","text":"فاهِم (فاعِل)"},{"id":"b","text":"مفهوم (مَفعول)"},{"id":"c","text":"فهيم (فعيل)"},{"id":"d","text":"مِفهام (مِفعال)"}]'::jsonb, 'b', 'اسم المفعول من الثلاثي يُصاغ على وزن «مَفعول»، فمن «فهمَ» نقول «مفهوم» (ما وقع عليه الفهم). أمّا «فاهم» فاسم فاعل، و«فهيم» صفة مشبّهة، و«مفهام» صيغة مبالغة.', 4),
  ('e581ff11-a60f-5345-8948-a8d609d16be8', '9884a453-057b-5889-b6ea-db113219d2c2', 'في «هذا الطريقُ مُعبَّدٌ»، ما نوع «مُعبَّد» والفارق بينه وبين «مُعبِّد»؟', '[{"id":"a","text":"اسم مفعول من «عبّدَ» بفتح ما قبل الآخر، و«مُعبِّد» اسم فاعل بكسره"},{"id":"b","text":"اسم فاعل بفتح ما قبل الآخر"},{"id":"c","text":"صفة مشبّهة لا فرق فيها"},{"id":"d","text":"صيغة مبالغة"}]'::jsonb, 'a', 'اسم المفعول من غير الثلاثي يُصاغ من المضارع بإبدال حرف المضارعة ميمًا مضمومة وفتح ما قبل الآخر: «يُعبِّد ← مُعبَّد» (ما وقع عليه التعبيد). ولو كُسر ما قبل الآخر «مُعبِّد» لصار اسم فاعل (من يُعبّد). فالفتحة والكسرة هما الفارق.', 5),
  ('2b95a7a3-b487-55c4-a8ac-ad7670ccd216', '9884a453-057b-5889-b6ea-db113219d2c2', 'في «مَوعِد» و«مِيزان» و«مَلعَب»، أيّ كلمة منها اسم آلة؟', '[{"id":"a","text":"مَوعِد (اسم زمان)"},{"id":"b","text":"مِيزان (اسم آلة على وزن مِفعال)"},{"id":"c","text":"مَلعَب (اسم مكان)"},{"id":"d","text":"جميعها أسماء آلة"}]'::jsonb, 'b', '«مِيزان» اسم آلة على وزن «مِفعال» (أصله مِوزان، أداة الوزن). أمّا «مَوعِد» فاسم زمان على «مَفعِل»، و«مَلعَب» اسم مكان على «مَفعَل»، فلا يدلّ أيّ منهما على آلة.', 6),
  ('0812b5d9-dfae-56c3-9c5a-f4c50824c145', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «العلمُ كالنورِ»، ما نوع الصورة البيانية وما أركانها الظاهرة؟', '[{"id":"a","text":"تشبيه؛ المشبّه «العلم» والأداة «الكاف» والمشبّه به «النور»"},{"id":"b","text":"استعارة تصريحية"},{"id":"c","text":"كناية"},{"id":"d","text":"مجاز مرسل"}]'::jsonb, 'a', '«العلمُ كالنورِ» تشبيه ظهرت فيه ثلاثة أركان: المشبّه (العلم) وأداة التشبيه (الكاف) والمشبّه به (النور)، وحُذف وجه الشبه. وليس استعارة لأنّ ركني التشبيه مذكوران معًا.', 1),
  ('e6135265-8fab-5fab-8d9f-dcc520ad7205', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'ما الذي يميّز الكناية عن التشبيه والاستعارة؟', '[{"id":"a","text":"في الكناية يجوز إرادة المعنى الحقيقي والمجازي معًا مع قرينة غير مانعة"},{"id":"b","text":"الكناية لا تحتمل إلا المعنى المجازي فقط"},{"id":"c","text":"الكناية تشبيه حُذفت أداته"},{"id":"d","text":"الكناية لا قرينة فيها أصلًا"}]'::jsonb, 'a', 'الكناية لفظ أُريد به لازم معناه مع جواز إرادة المعنى الأصلي، فقرينتها غير مانعة من إرادة الحقيقة. وهذا يميّزها عن الاستعارة والمجاز اللذين قرينتهما مانعة من إرادة المعنى الحقيقي.', 2),
  ('bd08d376-035b-52d3-a455-c15ff532c7b3', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «رأيتُ أسدًا يخطبُ في الناسِ» (يُقصد رجل شجاع)، ما نوع الصورة؟', '[{"id":"a","text":"تشبيه بليغ"},{"id":"b","text":"استعارة تصريحية (صُرّح بالمشبّه به «أسد» وحُذف المشبّه «الرجل»)"},{"id":"c","text":"استعارة مكنية"},{"id":"d","text":"مجاز مرسل علاقته الجزئية"}]'::jsonb, 'b', 'حُذف المشبّه (الرجل الشجاع) وصُرّح بالمشبّه به (أسد)، والقرينة «يخطب في الناس» تمنع إرادة الأسد الحقيقي، فهي استعارة تصريحية. ولو ذُكر المشبّه وحُذف المشبّه به وبقيت لازمته لكانت مكنية.', 3),
  ('b2f43973-aeb8-5406-9d81-64c3a1e15a7a', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «شربتُ ماءَ النهرِ» إذا أُريد أنّك شربت من ماء النهر، ما الذي يجعلها مجازًا مرسلًا لو قيل «شربتُ النهرَ»؟', '[{"id":"a","text":"علاقة المحلّية (ذُكر المحلّ «النهر» وأُريد الحالّ فيه «الماء»)"},{"id":"b","text":"علاقة السببية"},{"id":"c","text":"استعارة مكنية"},{"id":"d","text":"كناية عن العطش"}]'::jsonb, 'a', '«شربتُ النهرَ» مجاز مرسل علاقته المحلّية؛ ذُكر المحلّ (النهر) وأُريد الحالّ فيه (الماء)، إذ لا يُشرب النهر نفسه بل ما يحلّ فيه. والقرينة أنّ النهر لا يُشرب حقيقة.', 4),
  ('82551a4c-a153-5822-9cd7-68dbfaae0803', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «طارَ الخبرُ في المدينةِ»، ما نوع الصورة البيانية؟', '[{"id":"a","text":"تشبيه بليغ"},{"id":"b","text":"استعارة مكنية (شُبّه الخبر بطائر، حُذف المشبّه به وأُبقيت لازمته «طار»)"},{"id":"c","text":"استعارة تصريحية"},{"id":"d","text":"كناية عن سرعة الانتشار"}]'::jsonb, 'b', 'شُبّه الخبر بطائر يطير، فحُذف المشبّه به (الطائر) وأُبقيت إحدى لوازمه وهي فعل «طارَ»، فهي استعارة مكنية. ولو صُرّح بالمشبّه به لكانت تصريحية، ولو احتملت المعنيين لكانت كناية.', 5),
  ('2c1ba727-e2c9-5ba8-a00b-373de04836f3', 'aa501093-a4d6-59ad-b8b4-4c301729bee0', 'في «فلانٌ كثيرُ الرمادِ»، ما نوع الصورة والمعنى المقصود؟', '[{"id":"a","text":"كناية عن الكرم (كثرة الطبخ للضيوف فيكثر رماد الموقد)"},{"id":"b","text":"استعارة تصريحية عن البخل"},{"id":"c","text":"مجاز مرسل علاقته السببية"},{"id":"d","text":"تشبيه مفصّل"}]'::jsonb, 'a', '«كثير الرماد» كناية عن الكرم وكثرة الضيوف؛ فمن يُكثر إيقاد النار للطبخ والقِرى يكثر رماده، فالرماد لازمٌ يدلّ على الكرم. ويجوز إرادة المعنى الحقيقي (وجود رماد فعلًا) مع المجازي، وهذا ما يجعلها كناية لا استعارة.', 6),
  ('3970baac-fc14-5724-9717-2109015dfae5', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «يُحبّون الخيرَ ويكرهون الشرَّ»، ما المحسّن البديعي؟', '[{"id":"a","text":"طباق (بين يحبّون/يكرهون وبين الخير/الشرّ)"},{"id":"b","text":"جناس تامّ"},{"id":"c","text":"سجع"},{"id":"d","text":"تورية"}]'::jsonb, 'a', 'الطباق هو الجمع بين الضدّين في الكلام، وهنا تضادّ بين «يحبّون» و«يكرهون» وبين «الخير» و«الشرّ»، فهو طباق. وليس جناسًا لأنّ الجناس تشابه لفظَين لا تضادّ معنيَين.', 1),
  ('d5f9363b-b4fc-5722-8af1-0616f56c6519', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «الأرواحُ جنودٌ مجنّدةٌ»، ما نوع السجع المتحقّق إن وافقته فاصلة أخرى مثل «مؤلّفةٌ»؟', '[{"id":"a","text":"محسّن لفظيّ هو السجع (توافق الفاصلتين في الحرف الأخير)"},{"id":"b","text":"طباق معنوي"},{"id":"c","text":"تورية"},{"id":"d","text":"حسن تعليل"}]'::jsonb, 'a', 'السجع توافق الفاصلتين (آخر كلمتين في جملتين) في الحرف الأخير، مثل «مجنّدة» و«مؤلّفة»، وهو محسّن لفظيّ يُحدث إيقاعًا موسيقيًّا. وليس طباقًا (لا تضادّ) ولا تورية (لا معنى خفيّ).', 2),
  ('eb4e03f7-7616-5e15-932a-3a71c55f4cc8', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'ما الفرق بين المحسّنات المعنوية والمحسّنات اللفظية؟', '[{"id":"a","text":"المعنوية تُجمّل المعنى، واللفظية تُجمّل اللفظ والجرس الصوتي"},{"id":"b","text":"المعنوية في الشعر واللفظية في النثر"},{"id":"c","text":"المعنوية قديمة واللفظية حديثة"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'المحسّنات المعنوية (كالطباق والمقابلة والتورية) يكون التحسين فيها راجعًا إلى المعنى أوّلًا، أمّا اللفظية (كالجناس والسجع) فالتحسين فيها راجع إلى اللفظ والجرس الصوتي. وليس التقسيم على أساس الشعر والنثر.', 3),
  ('c215dbfb-fad8-5345-a87c-a51c0def0a4e', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «الصومُ جُنّةٌ»، إذا أُريد بـ«جُنّة» الوقاية والترس معًا، ما المحسّن؟', '[{"id":"a","text":"طباق"},{"id":"b","text":"تورية (لها معنى قريب وبعيد مقصود)"},{"id":"c","text":"سجع"},{"id":"d","text":"مقابلة"}]'::jsonb, 'b', 'التورية ذكر لفظ له معنيان: قريب ظاهر غير مراد وبعيد خفيّ مراد. «جُنّة» معناها القريب الترس/الدرع والبعيد المراد الوقاية من النار، فهي تورية. وليست طباقًا لانتفاء التضادّ.', 4),
  ('4eabcd80-07f2-5750-979b-c1f94d8667e9', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'في «ذهبتُ إلى البنكِ فجلستُ على البنكِ» (الأوّل: المصرف، الثاني: المقعد)، ما نوع الجناس؟', '[{"id":"a","text":"جناس ناقص لاختلاف الحركات"},{"id":"b","text":"جناس تامّ (اتّفاق اللفظين في كلّ شيء واختلاف المعنى)"},{"id":"c","text":"طباق"},{"id":"d","text":"تورية"}]'::jsonb, 'b', 'الجناس التامّ هو اتّفاق اللفظين في نوع الحروف وعددها وهيئتها وترتيبها مع اختلاف المعنى. «البنك» الأولى (المصرف) و«البنك» الثانية (المقعد) متّفقتان تمامًا في اللفظ مختلفتان في المعنى، فهو جناس تامّ لا ناقص.', 5),
  ('cd0765db-a6d0-5ab1-971c-9132ca6df5ed', '6bd805b6-4e0d-5090-8ee6-b404efda387e', 'قال الشاعر يصف سبب صفرة الذهب: «لم تصفرَّ الشمسُ عند الغروبِ إلّا لفراقِ النهارِ». ما المحسّن البديعي؟', '[{"id":"a","text":"حسن تعليل (علّة أدبيّة طريفة مخترعة بدل العلّة الحقيقيّة)"},{"id":"b","text":"طباق إيجاب"},{"id":"c","text":"جناس ناقص"},{"id":"d","text":"مقابلة"}]'::jsonb, 'a', 'حسن التعليل أن يُنكر الأديب العلّة الحقيقيّة لأمر ويخترع له علّة أدبيّة طريفة مناسبة لغرضه. فصفرة الشمس عند الغروب علّتها العلميّة معروفة، لكنّ الشاعر علّلها بالحزن لفراق النهار، وهذه علّة أدبيّة جميلة لا حقيقيّة.', 6),
  ('3792f490-0f40-5aa1-a384-774f23b81e7f', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «كان الصبيُّ يلعب في الحديقة، فسقط فجأةً وجرح ركبتَه، فأسرعت أمّه لإسعافه.» ما نمط هذا النصّ؟', '[{"id":"a","text":"وصفي"},{"id":"b","text":"سردي (يحكي أحداثًا متتابعة في الزمن)"},{"id":"c","text":"حجاجي"},{"id":"d","text":"تفسيري"}]'::jsonb, 'b', 'النصّ يحكي أحداثًا متتابعة (لعب فسقط فأسرعت) بأفعال ماضية وروابط زمنية (فجأةً)، وهذه مؤشّرات النمط السردي. وليس وصفيًّا لأنّه لا يرسم صورة ثابتة، ولا حجاجيًّا لأنّه لا يدافع عن رأي.', 1),
  ('15900e74-d067-5d1f-b45d-c06fa90dbfda', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «كانت الغرفةُ واسعةً، جدرانُها بيضاء، وفي وسطها طاولةٌ خشبيّةٌ تحيط بها أربعة كراسٍ.» ما نمط هذا النصّ؟', '[{"id":"a","text":"سردي"},{"id":"b","text":"وصفي (يرسم صورة حسّية ثابتة)"},{"id":"c","text":"حجاجي"},{"id":"d","text":"تفسيري إيعازي"}]'::jsonb, 'b', 'النصّ يرسم صورة حسّية ثابتة للغرفة بذكر الأبعاد والألوان والمواضع، وهذه مؤشّرات النمط الوصفي. وليس سرديًّا لخلوّه من تتابع الأحداث، ولا تفسيريًّا لأنّه لا يقدّم تعليمات.', 2),
  ('8c0bcabb-4e0f-57d3-a358-4c3d438871b8', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'في النصّ الحجاجي، ما وظيفة «الحجّة»؟', '[{"id":"a","text":"تقديم الشخصيات والزمان والمكان"},{"id":"b","text":"دعم الأطروحة وإقناع القارئ بصحّتها"},{"id":"c","text":"رسم صورة حسّية للمشهد"},{"id":"d","text":"سرد الأحداث بالترتيب"}]'::jsonb, 'b', 'الحجّة في النصّ الحجاجي هي الدليل أو البرهان الذي يُساق لدعم الأطروحة وإقناع القارئ بصحّتها. أمّا تقديم الشخصيات فمن السرد، ورسم الصورة من الوصف.', 3),
  ('452145e3-2edb-50cf-bc2c-f7bec9fe4f48', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'أيّ الروابط يناسب الدلالة على نتيجة في الفراغ: «درس الطالبُ بجدّ، ___ نجح بتفوّق.»', '[{"id":"a","text":"لكنْ"},{"id":"b","text":"فـ (لذلك)"},{"id":"c","text":"رغم أنّ"},{"id":"d","text":"بينما"}]'::jsonb, 'b', 'العلاقة بين الجملتين سبب (الدراسة بجدّ) ونتيجة (النجاح)، والرابط «فـ/لذلك» يفيد النتيجة. أمّا «لكنْ» و«رغم أنّ» فللاستدراك والتعارض، و«بينما» للتزامن، وكلّها لا تناسب علاقة السبب والنتيجة.', 4),
  ('b4ec7ae5-43cb-54ac-bbfd-4993026c736b', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'في بناء الفقرة الحجاجية، ما الترتيب المنطقي الأمثل لعناصرها؟', '[{"id":"a","text":"المثال ← الحجّة ← الأطروحة ← الخاتمة"},{"id":"b","text":"الأطروحة ← الحجّة ← المثال الداعم ← الاستنتاج"},{"id":"c","text":"الاستنتاج ← الأطروحة ← الحجّة ← المثال"},{"id":"d","text":"الحجّة ← المثال ← الأطروحة ← الاستنتاج"}]'::jsonb, 'b', 'تبدأ الفقرة الحجاجية بعرض الأطروحة (الرأي)، ثمّ تُساق الحجّة الداعمة لها، ثمّ يُضرب المثال الذي يجسّد الحجّة، وتُختم بالاستنتاج الذي يؤكّد الأطروحة. هذا الترتيب يضمن تماسك الإقناع ووضوحه.', 5),
  ('3057429d-27db-552a-a8c1-1b7af01317aa', '98d559bd-9f33-534c-89dd-a98ce3a9d74a', 'اقرأ: «ينبغي التقليل من استعمال السيّارات في المدن؛ فهي مصدرٌ رئيسٌ لتلوّث الهواء. وقد أثبتت دراساتٌ أنّ المدن الخالية من الازدحام أقلّ تلوّثًا.» ميّز الأطروحة من الحجّة.', '[{"id":"a","text":"الأطروحة: «ينبغي التقليل من استعمال السيّارات»، والحجّة: «فهي مصدر رئيس للتلوّث»"},{"id":"b","text":"الأطروحة: «أثبتت دراسات…»، والحجّة: «ينبغي التقليل…»"},{"id":"c","text":"لا توجد أطروحة في النصّ"},{"id":"d","text":"النصّ كلّه حجّة واحدة بلا أطروحة"}]'::jsonb, 'a', 'الأطروحة هي الرأي الذي يدافع عنه الكاتب: «ينبغي التقليل من استعمال السيّارات». والحجّة هي الدليل الداعم: «فهي مصدر رئيس للتلوّث» المعزَّز بالشاهد الإحصائي «أثبتت دراسات». فالشاهد ليس أطروحة بل تعزيز للحجّة.', 6),
  ('873faa1d-0154-5f54-8fd4-cf0adb64c0ae', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«ليس الذكاءُ وحده مفتاحَ النجاح، فكم من ذكيٍّ قعد به كسلُه، وكم من متواضعِ الذكاء بلغ القمّةَ بمثابرته. فالمثابرةُ هي السرّ الحقيقيّ.»

ما الفكرة العامة للنصّ؟', '[{"id":"a","text":"المثابرةُ أهمّ من الذكاء وحده في تحقيق النجاح"},{"id":"b","text":"الذكاءُ وحده كافٍ لبلوغ النجاح"},{"id":"c","text":"الكسلُ صفةٌ ملازمةٌ للأذكياء"},{"id":"d","text":"النجاحُ أمرٌ مستحيلٌ على الجميع"}]'::jsonb, 'a', 'يبني الكاتب فكرته على النفي والإثبات: «ليس الذكاء وحده… فالمثابرة هي السرّ»، فالفكرة العامة أنّ المثابرة أهمّ من الذكاء المجرّد (a). أمّا (b) فهو ما ينفيه النصّ صراحةً، و(c) تعميمٌ لم يقصده الكاتب، و(d) يناقض دعوة النصّ للنجاح بالمثابرة.', 1),
  ('eed55d8d-ef88-572c-bd0c-330279bfeb8a', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«كلّما ازداد الإنسانُ علمًا، ازداد تواضعًا؛ فالعالمُ الحقّ يدرك أنّ ما جهله أكثرُ ممّا علمه.»

ماذا نستنتج عن العلاقة بين العلم والتواضع؟', '[{"id":"a","text":"أنّ العلمَ الحقيقيّ يلازمه التواضعُ لا الغرور"},{"id":"b","text":"أنّ العلمَ يورث صاحبَه الكِبرَ والغرور"},{"id":"c","text":"أنّ التواضعَ صفةُ الجهلاء وحدهم"},{"id":"d","text":"أنّه لا علاقةَ بين العلم والأخلاق"}]'::jsonb, 'a', 'القرائن («كلّما ازداد علمًا ازداد تواضعًا»، «يدرك أنّ ما جهله أكثر») تستلزم بالاستنتاج أنّ العلم الحقّ يلازمه التواضع (a). فالخيار (b) يناقض النصّ صراحةً، و(c) عكسُ ما يقرّره، و(d) ينفي علاقةً يثبتها النصّ بوضوح.', 2),
  ('13b67a9f-04b6-55fa-a7ae-244c4f3cfbd7', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«أمّا البيئةُ فقد عانت طويلًا من جشع الإنسان، حتّى تلوّثت أنهارُها واسودّت سماؤها؛ بيدَ أنّ وعيًا جديدًا بدأ يلوح في الأفق.»

ما العلاقة المنطقية التي يحدثها الرابط «بيدَ أنّ»؟', '[{"id":"a","text":"استدراكٌ يُعارض ما قد يُتوقّع من اليأس بإبراز بارقة أمل"},{"id":"b","text":"تعليلٌ يُبيّن سبب تلوّث الأنهار"},{"id":"c","text":"نتيجةٌ مترتّبة على جشع الإنسان"},{"id":"d","text":"إضافةٌ لمعطًى في الاتّجاه نفسه"}]'::jsonb, 'a', '«بيدَ أنّ» أداة استدراك مرادفة لـ«لكنْ» و«غير أنّ»؛ فهي تُعارض ما قد يُفهم من الجملة الأولى (اليأس من حال البيئة) بإبراز معطًى مضادّ (الوعي الجديد). فليست تعليلًا (b) ولا نتيجة (c)، ولا إضافةً في الاتّجاه نفسه (d) بل تقابلٌ بين سلبٍ وإيجاب.', 3),
  ('b21430b6-8f91-5146-94fe-92e958a31485', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«يظنّ بعضُهم أنّ المالَ يصنع السعادة، أفرأيتَ غنيًّا تنعّم بالمال وحُرم راحةَ البال؟»

ما دلالة الاستفهام في «أفرأيتَ غنيًّا…؟»', '[{"id":"a","text":"استفهامٌ إنكاريّ يُفنّد زعم أنّ المال يصنع السعادة"},{"id":"b","text":"استفهامٌ حقيقيّ يطلب الكاتبُ به معلومةً يجهلها"},{"id":"c","text":"استفهامٌ للتمنّي"},{"id":"d","text":"استفهامٌ يدلّ على اقتناع الكاتب بأنّ المال يصنع السعادة"}]'::jsonb, 'a', 'الاستفهام هنا إنكاريّ خرج إلى معنى النفي والتفنيد: الكاتب لا يستفهم عن مجهول (b) بل يردّ على من يربط السعادة بالمال مستشهدًا بالغنيّ المحروم من راحة البال. فلا تمنّي فيه (c)، ولا اقتناع بنقيض موقفه (d)؛ والقرينة سياق الردّ على «بعضهم».', 4),
  ('931ce467-7f02-5fda-a7bb-835a5c71fa5b', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«وقف المعلّمُ بين تلاميذه كالأبِ الحاني، يبثّ فيهم العلمَ والقيمَ، ويغرس في نفوسهم حبَّ الوطن.»

ما النبرة المهيمنة على موقف الكاتب من المعلّم؟', '[{"id":"a","text":"نبرةٌ مفعمةٌ بالتقدير والإجلال"},{"id":"b","text":"نبرةٌ ساخرةٌ من دور المعلّم"},{"id":"c","text":"نبرةٌ حياديّةٌ خاليةٌ من العاطفة"},{"id":"d","text":"نبرةُ نقدٍ وإدانة"}]'::jsonb, 'a', 'الألفاظ الموحية («كالأب الحاني»، «يبثّ العلم والقيم»، «يغرس حبّ الوطن») تكشف عاطفة إعجابٍ وتقديرٍ للمعلّم، فالنبرة مفعمةٌ بالتقدير والإجلال (a). فلا سخرية (b)، ولا حياد عاطفيّ مع هذه الصور (c)، ولا نقدٌ ولا إدانة (d).', 5),
  ('f1eaa9c5-94d5-5c82-b3db-2e7cab9e4df3', '927a2f33-fd56-55ea-8670-ca52b5620cd4', 'اقرأ النصّ التالي:

«التطوّعُ ليس فضلًا يُتكرَّم به، بل واجبٌ إنسانيّ؛ فالمجتمعُ القويّ هو الذي يتكاتف أبناؤه. ألا ترى أنّ الأممَ المتقدّمة تُعلي من شأن العمل التطوّعيّ؟»

ما الأطروحة التي يدافع عنها الكاتب؟', '[{"id":"a","text":"التطوّعُ واجبٌ إنسانيّ يقوم عليه المجتمعُ القويّ المتكاتف"},{"id":"b","text":"التطوّعُ مجرّدُ فضلٍ يتكرّم به القادرون"},{"id":"c","text":"العملُ التطوّعيّ ظاهرةٌ غربيّةٌ لا تناسبنا"},{"id":"d","text":"الأممُ المتقدّمة لا تهتمّ بالتطوّع"}]'::jsonb, 'a', 'يصوغ الكاتب أطروحته بالنفي والإثبات: «ليس فضلًا… بل واجب إنسانيّ»، ويعزّزها بالحجّة (تكاتف المجتمع) والشاهد (الأمم المتقدّمة)، فالأطروحة (a). أمّا (b) فهو الرأي الذي يدحضه، و(c) ادّعاءٌ يناقض استشهاده الإيجابيّ، و(d) عكسُ ما ورد في النصّ.', 6),
  ('ac9ec4ef-98fb-5e7c-a214-7301abc706a6', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'أيّ المصادر التالية يُعدّ منبعًا ضوئيًّا أوّليًّا (يُنتج الضوء بنفسه)؟', '[{"id":"a","text":"القمر"},{"id":"b","text":"مرآة مستوية"},{"id":"c","text":"الشمس"},{"id":"d","text":"صفحة كتاب بيضاء"}]'::jsonb, 'c', 'المنبع الأوّلي يُنتج الضوء بنفسه (الشمس، اللمبة، الشمعة). أمّا القمر والمرآة والصفحة فهي أجسام مُضاءة تعكس الضوء فقط، لذا تُسمّى منابع ثانوية.', 1),
  ('24f62805-f78c-5520-b5bb-5d7cc5912bce', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'حتى نرى جسمًا غير مُضيء بذاته، يجب أن:', '[{"id":"a","text":"يكون الجسم ساخنًا"},{"id":"b","text":"يصل إلى العين ضوءٌ قادمٌ من ذلك الجسم"},{"id":"c","text":"يكون الجسم شفّافًا"},{"id":"d","text":"تُغلق العين قليلًا"}]'::jsonb, 'b', 'نرى جسمًا غير مُضيء عندما يضيئه منبعٌ ما فيعكس جزءًا من الضوء نحو أعيننا. الرؤية تتطلّب وصول الضوء من الجسم إلى العين، لذلك لا نرى شيئًا في الظلام التامّ.', 2),
  ('ecad3e23-8b4b-5d24-b6f8-db4be5a0cb02', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'ينتشر الضوء في الوسط الشفّاف المتجانس:', '[{"id":"a","text":"وفق خطوط منحنية"},{"id":"b","text":"وفق خطوط مستقيمة"},{"id":"c","text":"على شكل دوائر"},{"id":"d","text":"بسرعة متناقصة باستمرار"}]'::jsonb, 'b', 'مبدأ الانتشار المستقيمي للضوء: في وسط شفّاف ومتجانس (كالهواء النقي أو الزجاج) ينتشر الضوء على شكل خطوط مستقيمة، وهذا ما يفسّر تكوّن الظلّ والكسوف والخسوف.', 3),
  ('185051a9-b4d0-5d1d-992d-788e9733a5bc', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'نرسم حُزمة ضوئية تخرج من منبع نقطي وتتّسع كلّما ابتعدنا عنه. هذه الحُزمة:', '[{"id":"a","text":"متوازية"},{"id":"b","text":"متقاربة"},{"id":"c","text":"متباعدة"},{"id":"d","text":"أسطوانية"}]'::jsonb, 'c', 'الحزمة المتباعدة تنطلق من نقطة واحدة (المنبع النقطي) وتتّسع مع الابتعاد. أمّا المتقاربة فتضيق نحو نقطة، والمتوازية تحافظ على عرضها ثابتًا.', 4),
  ('942eb056-53f3-52d8-8628-e902335d9be2', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'عمود طوله 2 m يُلقي ظلًّا طوله 3 m تحت الشمس. شجرة بجواره ظلّها 12 m. ما ارتفاع الشجرة؟', '[{"id":"a","text":"8 m"},{"id":"b","text":"18 m"},{"id":"c","text":"6 m"},{"id":"d","text":"24 m"}]'::jsonb, 'a', 'لأنّ الأشعّة الشمسية متوازية، تتناسب الأطوال مع أطوال الظلال (مثلّثات متشابهة): الارتفاع/الظلّ ثابت = 2/3. ارتفاع الشجرة = (2/3) × 12 = 8 m.', 5),
  ('200390e1-5733-51b7-98d2-ec4b112f8f0d', 'bd64fa5c-a753-51e1-9e4a-64c9b38aec2e', 'في غرفة مظلمة ذات ثقب، عند تقريب الشاشة من الثقب فإنّ الصورة المتكوّنة:', '[{"id":"a","text":"تكبر وتبقى مقلوبة"},{"id":"b","text":"تصغر وتبقى مقلوبة"},{"id":"c","text":"تصبح معتدلة"},{"id":"d","text":"تختفي تمامًا"}]'::jsonb, 'b', 'نتيجة الانتشار المستقيمي عبر الثقب تكون الصورة مقلوبة دائمًا. كلّما اقتربت الشاشة من الثقب صغرت الصورة، وكلّما ابتعدت كبرت، لكنّها تبقى مقلوبة في الحالتين.', 6),
  ('9539d202-3573-5812-a69f-9338b100fc37', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'في ظاهرة الانعكاس، تُقاس زاوية الورود وزاوية الانعكاس بالنسبة إلى:', '[{"id":"a","text":"سطح المرآة"},{"id":"b","text":"الناظم (العمودي على المرآة في نقطة الورود)"},{"id":"c","text":"الشعاع المنعكس"},{"id":"d","text":"الأرض"}]'::jsonb, 'b', 'تُقاس الزاويتان دائمًا بين الشعاع (الوارد أو المنعكس) والناظم، وهو الخطّ العمودي على سطح المرآة في نقطة الورود، وليس بالنسبة إلى سطح المرآة نفسه.', 1),
  ('666b8805-1ec2-526f-80f6-6a7b58aa4246', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'ينصّ القانون الثاني للانعكاس على أنّ:', '[{"id":"a","text":"زاوية الانعكاس أكبر من زاوية الورود"},{"id":"b","text":"زاوية الانعكاس تساوي زاوية الورود"},{"id":"c","text":"زاوية الانعكاس أصغر من زاوية الورود"},{"id":"d","text":"مجموع الزاويتين 90°"}]'::jsonb, 'b', 'القانون الثاني للانعكاس: زاوية الانعكاس = زاوية الورود. أمّا القانون الأوّل فينصّ على أنّ الشعاع الوارد والمنعكس والناظم تقع في مستوٍ واحد.', 2),
  ('7450115a-942a-5498-95ed-2130056127e3', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'شعاع ضوئي يرد على مرآة مستوية بزاوية ورود 30°. ما زاوية الانعكاس؟', '[{"id":"a","text":"60°"},{"id":"b","text":"90°"},{"id":"c","text":"30°"},{"id":"d","text":"15°"}]'::jsonb, 'c', 'حسب القانون الثاني، زاوية الانعكاس = زاوية الورود = 30°. الخطأ الشائع 60° ناتج عن قياس الزاوية بالنسبة إلى سطح المرآة (90 − 30) بدل الناظم.', 3),
  ('0c5a87bd-2071-5540-9306-06bc9c7d0020', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'شعاع يرد عموديًّا تمامًا على مرآة مستوية (على امتداد الناظم). كيف ينعكس؟', '[{"id":"a","text":"ينعكس بزاوية 45°"},{"id":"b","text":"يرتدّ على نفس مساره عائدًا (زاوية الانعكاس 0°)"},{"id":"c","text":"ينزلق على سطح المرآة"},{"id":"d","text":"ينفذ خلال المرآة"}]'::jsonb, 'b', 'إذا ورد الشعاع على امتداد الناظم فزاوية الورود = 0°، فتكون زاوية الانعكاس = 0° أيضًا، أي يرتدّ الشعاع على نفسه عائدًا في الاتّجاه المعاكس.', 4),
  ('d2939e1a-198b-5006-b42d-216f92ec2e2b', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'صورة جسم في مرآة مستوية هي:', '[{"id":"a","text":"حقيقية ومقلوبة"},{"id":"b","text":"تخيّلية ومماثلة للجسم ومتناظرة معه بالنسبة إلى المرآة"},{"id":"c","text":"حقيقية ومكبّرة"},{"id":"d","text":"تخيّلية ومصغّرة"}]'::jsonb, 'b', 'صورة الجسم في المرآة المستوية تخيّلية (لا تُستقبل على شاشة)، بنفس حجم الجسم (مماثلة)، وتقع على بُعدٍ خلف المرآة يساوي بُعد الجسم أمامها (متناظرة بالنسبة إلى سطح المرآة).', 5),
  ('47a56900-6f8e-5ea8-8743-6189654ece6c', '1017affc-675d-5736-8633-6a06b0ebb7ce', 'يقف شخص على بُعد 1.5 m أمام مرآة مستوية. ما المسافة بينه وبين صورته؟', '[{"id":"a","text":"1.5 m"},{"id":"b","text":"0.75 m"},{"id":"c","text":"3 m"},{"id":"d","text":"4.5 m"}]'::jsonb, 'c', 'تقع الصورة خلف المرآة على نفس بُعد الجسم أمامها = 1.5 m. فالمسافة بين الشخص وصورته = 1.5 + 1.5 = 3 m. الخطأ الشائع 1.5 m يأتي من نسيان أنّ الصورة خلف المرآة.', 6),
  ('78f8ccc7-474b-5ad1-a4ff-09e3f48cc444', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'تحدث ظاهرة انكسار الضوء عندما:', '[{"id":"a","text":"يرتدّ الضوء عن سطح لامع"},{"id":"b","text":"ينتقل الضوء بميلٍ من وسط شفّاف إلى وسط شفّاف آخر مختلف"},{"id":"c","text":"يمرّ الضوء في وسط واحد متجانس"},{"id":"d","text":"ينطفئ المنبع الضوئي"}]'::jsonb, 'b', 'الانكسار هو انحراف الشعاع الضوئي عند عبوره بميلٍ من وسط شفّاف إلى آخر مختلف (مثل الهواء/الماء)، بسبب اختلاف سرعة الضوء في الوسطين. الارتداد عن السطح هو الانعكاس وليس الانكسار.', 1),
  ('2a7dad2e-662e-5c2e-af8b-684081aaa53e', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'العدسة المجمّعة (المحدّبة) تتميّز بأنّها:', '[{"id":"a","text":"أنحف في الوسط منها عند الحافّتين"},{"id":"b","text":"أسمك في الوسط منها عند الحافّتين وتجمع الأشعّة المتوازية في البؤرة"},{"id":"c","text":"تشتّت الأشعّة المتوازية"},{"id":"d","text":"لا تغيّر مسار الضوء"}]'::jsonb, 'b', 'العدسة المجمّعة محدّبة، أسمك في وسطها، وتجمع حزمة الأشعّة المتوازية الواردة في نقطة واحدة هي البؤرة الرئيسية. أمّا العدسة المفرّقة فهي أنحف في الوسط وتشتّت الأشعّة.', 2),
  ('5b8f0ec1-0758-5f0d-bca1-675ff14f3d22', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'عند مرور الضوء من الهواء إلى الماء بميل، فإنّ الشعاع المنكسر:', '[{"id":"a","text":"يبتعد عن الناظم"},{"id":"b","text":"يقترب من الناظم"},{"id":"c","text":"يبقى على نفس استقامة الشعاع الوارد"},{"id":"d","text":"يرتدّ إلى الهواء"}]'::jsonb, 'b', 'عند الانتقال من وسط أقلّ كثافة ضوئية (الهواء) إلى وسط أكثر كثافة (الماء) يقترب الشعاع المنكسر من الناظم (زاوية الانكسار أصغر من زاوية الورود). والعكس صحيح عند الخروج من الماء إلى الهواء.', 3),
  ('c48af3e8-0227-57ef-8492-5b5da0cdd753', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'البُعد البؤري لعدسة مجمّعة هو المسافة بين:', '[{"id":"a","text":"حافّتي العدسة"},{"id":"b","text":"مركز العدسة والبؤرة الرئيسية"},{"id":"c","text":"الجسم والعدسة"},{"id":"d","text":"البؤرتين معًا"}]'::jsonb, 'b', 'البُعد البؤري f هو المسافة بين المركز البصري للعدسة وبؤرتها الرئيسية. كلّما صغر البُعد البؤري كانت العدسة أكثر تقاربًا (أكبر قدرة).', 4),
  ('8a48aeb6-e94a-5713-b2fc-345b1aa451c4', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'قدرة العدسة المجمّعة C تُحسب بالعلاقة C = 1/f (وحدتها الديوبتر، وf بالمتر). إذا كان f = 0.5 m فما القدرة؟', '[{"id":"a","text":"0.5 ديوبتر"},{"id":"b","text":"5 ديوبتر"},{"id":"c","text":"2 ديوبتر"},{"id":"d","text":"50 ديوبتر"}]'::jsonb, 'c', 'C = 1/f = 1/0.5 = 2 ديوبتر. يجب التعبير عن f بالمتر قبل القسمة. الخطأ الشائع 0.5 يأتي من حساب f بدل 1/f.', 5),
  ('fc282b9e-2a29-57e0-8daf-2e9a482d82c1', 'a5969ea5-9f68-5e1b-80a6-31c44805a777', 'جسم موضوع على بُعد أكبر من ضِعف البُعد البؤري (أبعد من 2f) أمام عدسة مجمّعة. صورته تكون:', '[{"id":"a","text":"تخيّلية ومعتدلة ومكبّرة"},{"id":"b","text":"حقيقية ومقلوبة ومصغّرة"},{"id":"c","text":"حقيقية ومعتدلة ومماثلة"},{"id":"d","text":"غير موجودة"}]'::jsonb, 'b', 'عندما يكون الجسم أبعد من 2f عن عدسة مجمّعة، تتكوّن صورة حقيقية (تُستقبل على شاشة) مقلوبة ومصغّرة، تقع بين البؤرة و2f من الجهة الأخرى. هذا مبدأ عمل آلة التصوير والعين.', 6),
  ('2cf38af4-b1e6-53f3-b571-1c5a066374eb', '3607d567-0e65-55d2-be84-36da8bee0154', 'تتكوّن الذرّة من:', '[{"id":"a","text":"نواة فقط"},{"id":"b","text":"إلكترونات فقط"},{"id":"c","text":"نواة مركزية موجبة تدور حولها إلكترونات سالبة"},{"id":"d","text":"نواة سالبة وإلكترونات موجبة"}]'::jsonb, 'c', 'تتكوّن الذرّة من نواة مركزية صغيرة موجبة الشحنة، تدور حولها إلكترونات سالبة الشحنة. الذرّة في مجملها متعادلة كهربائيًّا لأنّ عدد الشحنات الموجبة يساوي عدد الإلكترونات.', 1),
  ('e9112d6f-b475-5fc5-9bfe-53fc941cc39c', '3607d567-0e65-55d2-be84-36da8bee0154', 'رمز عنصر الأكسجين هو:', '[{"id":"a","text":"O"},{"id":"b","text":"Ox"},{"id":"c","text":"Au"},{"id":"d","text":"H"}]'::jsonb, 'a', 'رمز الأكسجين هو الحرف O. أمّا Au فرمز الذهب، وH رمز الهيدروجين. تُكتب رموز العناصر بحرف كبير واحد أو حرف كبير يتبعه حرف صغير.', 2),
  ('d1743703-1908-5e15-bc4c-26e1af720a68', '3607d567-0e65-55d2-be84-36da8bee0154', 'الفرق الأساسي بين الذرّة والجزيء هو أنّ الجزيء:', '[{"id":"a","text":"أصغر من الذرّة دائمًا"},{"id":"b","text":"مجموعة من ذرّتين أو أكثر مترابطة معًا"},{"id":"c","text":"هو نفسه الذرّة بتسمية أخرى"},{"id":"d","text":"لا يحتوي على ذرّات"}]'::jsonb, 'b', 'الجزيء هو تجمّع لذرّتين أو أكثر مترابطة فيما بينها (قد تكون من نفس العنصر مثل O₂، أو من عناصر مختلفة مثل H₂O). أمّا الذرّة فهي أصغر وحدة بنائية للعنصر.', 3),
  ('4491c581-b572-54e5-9394-a88842a92207', '3607d567-0e65-55d2-be84-36da8bee0154', 'كم عدد الذرّات الكلّي في جزيء حمض الكبريتيك H₂SO₄؟', '[{"id":"a","text":"3 ذرّات"},{"id":"b","text":"6 ذرّات"},{"id":"c","text":"7 ذرّات"},{"id":"d","text":"4 ذرّات"}]'::jsonb, 'c', 'نجمع الأرقام السفلية لكلّ عنصر: هيدروجين H₂ = 2، كبريت S = 1، أكسجين O₄ = 4. المجموع = 2 + 1 + 4 = 7 ذرّات. الرقم 3 خطأ شائع من عدّ أنواع العناصر بدل الذرّات.', 4),
  ('658fd900-dfb8-516e-8bff-51650f27fe16', '3607d567-0e65-55d2-be84-36da8bee0154', 'الصيغة 3 H₂O تعني:', '[{"id":"a","text":"جزيء ماء واحد فيه 3 ذرّات أكسجين"},{"id":"b","text":"ثلاثة جزيئات ماء، أي 6 ذرّات هيدروجين و3 ذرّات أكسجين"},{"id":"c","text":"3 ذرّات هيدروجين فقط"},{"id":"d","text":"جزيء واحد فيه 32 ذرّة"}]'::jsonb, 'b', 'المُعامِل 3 أمام الصيغة يدلّ على عدد الجزيئات: 3 جزيئات ماء. كلّ جزيء H₂O فيه 2 هيدروجين و1 أكسجين، فالمجموع: 3×2 = 6 ذرّات هيدروجين و3×1 = 3 ذرّات أكسجين.', 5),
  ('ef1a6381-2aaa-50dc-89a0-bc8ea056f2f9', '3607d567-0e65-55d2-be84-36da8bee0154', 'أيّ مما يلي يمثّل جسمًا بسيطًا (مكوّنًا من نوع واحد من الذرّات)؟', '[{"id":"a","text":"الماء H₂O"},{"id":"b","text":"ثنائي أكسيد الكربون CO₂"},{"id":"c","text":"غاز ثنائي الأكسجين O₂"},{"id":"d","text":"كلور الصوديوم NaCl"}]'::jsonb, 'c', 'الجسم البسيط يتكوّن من نوع واحد فقط من العناصر؛ غاز ثنائي الأكسجين O₂ مكوّن من ذرّتي أكسجين من نفس النوع. أمّا H₂O وCO₂ وNaCl فأجسام مركّبة لاحتوائها على عناصر مختلفة.', 6),
  ('da0e4132-a709-5103-a2a2-616b6cbf3d8f', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'في تفاعل كيميائي، تُسمّى المواد الموجودة قبل التفاعل:', '[{"id":"a","text":"النواتج"},{"id":"b","text":"المتفاعلات"},{"id":"c","text":"الرواسب"},{"id":"d","text":"المحفّزات"}]'::jsonb, 'b', 'المتفاعلات هي المواد الابتدائية الموجودة قبل التفاعل (يسار المعادلة)، وتتحوّل أثناء التفاعل إلى نواتج (يمين المعادلة). السهم يفصل بينهما ويتّجه من المتفاعلات إلى النواتج.', 1),
  ('1852ee76-c415-5e62-8d5b-ad4aec32c0e3', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'ينصّ قانون انحفاظ الكتلة (لافوازييه) على أنّ كتلة المتفاعلات:', '[{"id":"a","text":"أكبر من كتلة النواتج"},{"id":"b","text":"أصغر من كتلة النواتج"},{"id":"c","text":"تساوي كتلة النواتج"},{"id":"d","text":"تختفي تمامًا بعد التفاعل"}]'::jsonb, 'c', 'أثناء التفاعل الكيميائي تُحفظ الكتلة: مجموع كتل المتفاعلات = مجموع كتل النواتج، لأنّ الذرّات لا تُستحدث ولا تُفنى بل يُعاد ترتيبها فقط. لذلك يجب أن تُوازن المعادلة.', 2),
  ('42fdbcbf-b3fc-5657-8bb9-cce796f0f4ef', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'تفاعَل 8 g من الكبريت مع كمّية من الحديد فتشكّل 22 g من كبريتور الحديد دون فائض. ما كتلة الحديد المتفاعل؟', '[{"id":"a","text":"30 g"},{"id":"b","text":"14 g"},{"id":"c","text":"22 g"},{"id":"d","text":"8 g"}]'::jsonb, 'b', 'بتطبيق انحفاظ الكتلة: كتلة الحديد + كتلة الكبريت = كتلة الناتج، أي m(Fe) + 8 = 22، إذن m(Fe) = 22 − 8 = 14 g. الخطأ 30 g ناتج عن الجمع بدل الطرح.', 3),
  ('5fefc337-05c5-5e42-aae6-4e89380875d1', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'أيّ مما يلي دليلٌ على حدوث تفاعل كيميائي وليس مجرّد تغيّر فيزيائي؟', '[{"id":"a","text":"ذوبان الجليد إلى ماء"},{"id":"b","text":"تكوّن غاز جديد وتغيّر اللون وانطلاق حرارة"},{"id":"c","text":"تبخّر الماء بالتسخين"},{"id":"d","text":"تكسير قطعة طبشور"}]'::jsonb, 'b', 'التفاعل الكيميائي يصاحبه ظهور مواد جديدة بخصائص مختلفة (انطلاق غاز، تغيّر لون، تكوّن راسب، انطلاق أو امتصاص حرارة). أمّا الذوبان والتبخّر والتكسير فتغيّرات فيزيائية لا تنشأ عنها مادّة جديدة.', 4),
  ('e7a0882e-4530-56b6-92c1-c41e43f7ec12', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'ما المعامل الصحيح الذي يُوازن معادلة احتراق غاز الهيدروجين: ... H₂ + O₂ → 2 H₂O ؟ (المطلوب المعامل أمام H₂)', '[{"id":"a","text":"1"},{"id":"b","text":"3"},{"id":"c","text":"2"},{"id":"d","text":"4"}]'::jsonb, 'c', 'المعادلة الموزونة: 2 H₂ + O₂ → 2 H₂O. على اليمين 4 ذرّات H و2 ذرّة O، فنحتاج 2 H₂ (=4 H) و O₂ (=2 O) على اليسار. إذن المعامل أمام H₂ هو 2.', 5),
  ('b1770b50-0636-5e1a-8362-994a9bd40cd8', '39a24d45-61d7-5aaf-b4c2-7ac9958ff4cd', 'في المعادلة الموزونة C + O₂ → CO₂، إذا تفاعل 12 g من الكربون مع 32 g من ثنائي الأكسجين، فما كتلة ثنائي أكسيد الكربون الناتج؟', '[{"id":"a","text":"20 g"},{"id":"b","text":"44 g"},{"id":"c","text":"32 g"},{"id":"d","text":"12 g"}]'::jsonb, 'b', 'حسب انحفاظ الكتلة: كتلة CO₂ = كتلة C + كتلة O₂ = 12 + 32 = 44 g. الكتلة لا تضيع، بل كلّ ذرّات الكربون والأكسجين انتقلت إلى الناتج.', 6),
  ('8d8c0764-9ce6-596a-b337-25dcf65922c5', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'محلول متعادل (كالماء النقي) عند 25°C يكون pH-ه يساوي:', '[{"id":"a","text":"0"},{"id":"b","text":"7"},{"id":"c","text":"14"},{"id":"d","text":"10"}]'::jsonb, 'b', 'مقياس pH يمتدّ من 0 إلى 14. المحلول المتعادل pH = 7 (كالماء النقي). إذا كان pH < 7 فالمحلول حمضي، وإذا كان pH > 7 فالمحلول قاعدي.', 1),
  ('ad674329-1e03-517a-a28c-5dac91f6afbe', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'محلول pH-ه يساوي 3. هذا المحلول:', '[{"id":"a","text":"قاعدي"},{"id":"b","text":"متعادل"},{"id":"c","text":"حمضي"},{"id":"d","text":"نقيّ من الشوارد"}]'::jsonb, 'c', 'كلّ محلول pH-ه أصغر من 7 يكون حمضيًّا، وكلّما اقترب pH من 0 ازدادت الحموضة. إذن pH = 3 يدلّ على محلول حمضي.', 2),
  ('97ee2bda-54f6-5494-bcfc-e8e216cd70c0', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'أيّ المحاليل التالية الأكثر حمضيّة؟', '[{"id":"a","text":"محلول pH = 5"},{"id":"b","text":"محلول pH = 2"},{"id":"c","text":"محلول pH = 7"},{"id":"d","text":"محلول pH = 12"}]'::jsonb, 'b', 'كلّما صغرت قيمة pH ازدادت الحموضة. القيمة الأصغر هي 2، إذن المحلول pH = 2 هو الأكثر حمضيّة. والمحلول pH = 12 هو الأكثر قاعديّة.', 3),
  ('2f49df40-1047-5eae-90ac-b65c493994c7', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'عند إضافة قطرات من الفينول فتالين إلى محلول قاعدي، يتلوّن المحلول باللون:', '[{"id":"a","text":"الأحمر"},{"id":"b","text":"الأصفر"},{"id":"c","text":"الوردي (الأرجواني)"},{"id":"d","text":"عديم اللون"}]'::jsonb, 'c', 'الفينول فتالين كاشف ملوّن يبقى عديم اللون في الأوساط الحمضية والمتعادلة، ويتلوّن باللون الوردي/الأرجواني في الوسط القاعدي. لذلك يُستعمل للكشف عن القواعد.', 4),
  ('15e08919-a6f1-533f-b787-ad5f36b5bb4a', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'عند تخفيف محلول حمضي pH = 3 بإضافة كمّية كبيرة من الماء النقي، فإنّ قيمة pH:', '[{"id":"a","text":"تنقص فيزداد الحمض قوّة"},{"id":"b","text":"تزداد مقتربة من 7 فتقلّ الحموضة"},{"id":"c","text":"تبقى ثابتة عند 3"},{"id":"d","text":"تصبح فوق 14"}]'::jsonb, 'b', 'تخفيف محلول حمضي بالماء يجعل pH يزداد مقتربًا من 7 (المتعادل)، أي تقلّ الحموضة لأنّ تركيز الحمض ينخفض. وبالعكس، تخفيف محلول قاعدي يجعل pH ينقص مقتربًا من 7.', 5),
  ('6b13a25d-d596-5bf3-9d74-104e67b3c295', '819e1619-3c42-5488-a48c-db4f8c0a092a', 'رتّب من الأكثر حمضيّة إلى الأكثر قاعديّة: عصير ليمون (pH≈2)، ماء نقي (pH=7)، ماء صابون (pH≈9).', '[{"id":"a","text":"ماء صابون ← ماء نقي ← عصير ليمون"},{"id":"b","text":"عصير ليمون ← ماء نقي ← ماء صابون"},{"id":"c","text":"ماء نقي ← عصير ليمون ← ماء صابون"},{"id":"d","text":"ماء صابون ← عصير ليمون ← ماء نقي"}]'::jsonb, 'b', 'الأكثر حمضيّة هو الأصغر pH: عصير الليمون (2) ثمّ الماء النقي المتعادل (7) ثمّ ماء الصابون القاعدي (9). فالترتيب من الأكثر حمضيّة إلى الأكثر قاعديّة: عصير ليمون ← ماء نقي ← ماء صابون.', 6),
  ('85f46ae6-9044-553b-8363-0fe65dc1d33b', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'الشاردة (الأيون) هي:', '[{"id":"a","text":"ذرّة أو مجموعة ذرّات اكتسبت أو فقدت إلكترونات فأصبحت مشحونة"},{"id":"b","text":"ذرّة متعادلة كهربائيًّا"},{"id":"c","text":"جزيء لا يحمل أيّ شحنة"},{"id":"d","text":"نواة بدون إلكترونات"}]'::jsonb, 'a', 'الشاردة ذرّة أو مجموعة ذرّات فقدت إلكترونات (فأصبحت موجبة = كاتيون) أو اكتسبت إلكترونات (فأصبحت سالبة = أنيون). أمّا الذرّة المتعادلة فعدد إلكتروناتها يساوي عدد شحنات نواتها.', 1),
  ('3ee0c644-5450-5bf8-abe5-7f7ca485336e', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'الشاردة الموجبة تُسمّى كاتيونًا، فأيّ مما يلي كاتيون؟', '[{"id":"a","text":"شاردة الكلور Cl⁻"},{"id":"b","text":"شاردة الصوديوم Na⁺"},{"id":"c","text":"شاردة الكبريتات SO₄²⁻"},{"id":"d","text":"شاردة الهيدروكسيد OH⁻"}]'::jsonb, 'b', 'الكاتيون شاردة موجبة (إشارة + أعلى الرمز). Na⁺ كاتيون لأنّه موجب. أمّا Cl⁻ وSO₄²⁻ وOH⁻ فأنيونات (سالبة).', 2),
  ('f3cd7ae0-2701-5931-91b4-035081d52e3b', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'لماذا يكون محلول ملح الطعام (كلور الصوديوم) في الماء ناقلًا للتيار الكهربائي؟', '[{"id":"a","text":"لأنّه يحتوي على جزيئات ماء فقط"},{"id":"b","text":"لأنّه يحتوي على شوارد حرّة الحركة (Na⁺ و Cl⁻)"},{"id":"c","text":"لأنّ الماء وحده ناقل ممتاز"},{"id":"d","text":"لأنّ السكّر موجود فيه"}]'::jsonb, 'b', 'ناقلية المحلول تعود إلى وجود شوارد حرّة الحركة. ينحلّ كلور الصوديوم إلى Na⁺ وCl⁻ تتحرّك نحو القطبين فتنقل التيار. الماء النقي وحده ناقل ضعيف جدًّا، ومحلول السكّر غير ناقل لأنّه لا يعطي شوارد.', 3),
  ('05825851-7a5b-5761-a954-efe703a01cfa', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'أيّ المحاليل التالية غير ناقل للتيار الكهربائي؟', '[{"id":"a","text":"محلول كلور الصوديوم"},{"id":"b","text":"محلول حمض الكلور"},{"id":"c","text":"محلول السكّر"},{"id":"d","text":"محلول هيدروكسيد الصوديوم"}]'::jsonb, 'c', 'محلول السكّر غير ناقل لأنّ السكّر ينحلّ على شكل جزيئات متعادلة لا تعطي شوارد. أمّا الأملاح والأحماض والقواعد فتعطي شوارد حرّة فتجعل المحلول ناقلًا (محاليل شاردية).', 4),
  ('2c551ce0-10b8-5072-9761-8d4fba83b0e4', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'عند زيادة تركيز محلول شاردي (إذابة كمّية أكبر من الملح في نفس حجم الماء)، فإنّ ناقليته الكهربائية:', '[{"id":"a","text":"تنقص"},{"id":"b","text":"تزداد لزيادة عدد الشوارد الناقلة"},{"id":"c","text":"تبقى ثابتة"},{"id":"d","text":"تنعدم"}]'::jsonb, 'b', 'كلّما زاد التركيز زاد عدد الشوارد الحرّة في وحدة الحجم، فتزداد ناقلية المحلول (إلى حدّ التشبّع). فالناقلية تتناسب طرديًّا مع تركيز الشوارد.', 5),
  ('2231fe26-ab77-5ff2-80a6-01402facf2da', 'ba7718f3-4caf-57bf-81b4-59c3644ce233', 'في تجربة ناقلية تستعمل مصباحًا في الدارة: عند غمر القطبين في محلول شاردي مركّز يضيء المصباح بشدّة، وفي محلول مخفّف يضيء بخفوت. ماذا نستنتج؟', '[{"id":"a","text":"شدّة الإضاءة لا علاقة لها بالتركيز"},{"id":"b","text":"شدّة الإضاءة تدلّ على شدّة التيار، وهي تزداد بزيادة الناقلية (التركيز)"},{"id":"c","text":"المحلول المخفّف أكثر ناقلية"},{"id":"d","text":"المصباح يضيء بسبب الماء وحده"}]'::jsonb, 'b', 'إضاءة المصباح مؤشّر على شدّة التيار المار، وهي تكبر كلّما زادت ناقلية المحلول. المحلول المركّز (شوارد أكثر) أكثر ناقلية فيمرّ تيار أكبر ويضيء المصباح بشدّة، عكس المحلول المخفّف.', 6),
  ('fdfb7fbc-af49-5ab6-8b0f-21d6ac3f374f', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'تُقاس شدّة التيار الكهربائي I بوحدة:', '[{"id":"a","text":"الفولط (V)"},{"id":"b","text":"الأمبير (A)"},{"id":"c","text":"الأوم (Ω)"},{"id":"d","text":"الواط (W)"}]'::jsonb, 'b', 'شدّة التيار I تُقاس بالأمبير (A) بواسطة الأمبيرمتر الموصول على التسلسل. الفولط وحدة التوتر، والأوم وحدة المقاومة.', 1),
  ('1602e63c-6e4e-5f89-a8f3-53a1e5bb74d5', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'ينصّ قانون أوم على العلاقة:', '[{"id":"a","text":"U = R + I"},{"id":"b","text":"U = R / I"},{"id":"c","text":"U = R × I"},{"id":"d","text":"R = U × I"}]'::jsonb, 'c', 'قانون أوم: U = R × I، حيث U التوتر بالفولط، R المقاومة بالأوم، I شدّة التيار بالأمبير. ومنه يمكن استنتاج I = U / R و R = U / I.', 2),
  ('bc810d27-1ab2-5224-9cca-c92d88c7a88f', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'مقاومة R = 220 Ω يمرّ بها تيار I = 0.1 A. ما التوتر U عبرها؟', '[{"id":"a","text":"2200 V"},{"id":"b","text":"22 V"},{"id":"c","text":"220.1 V"},{"id":"d","text":"2.2 V"}]'::jsonb, 'b', 'بقانون أوم: U = R × I = 220 × 0.1 = 22 V. الخطأ 2200 V يأتي من القسمة على 0.1 بدل الضرب.', 3),
  ('4e6fa418-65d3-55c1-9e29-04caa8be4ac9', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'لمبة توترها U = 6 V وتمرّ بها شدّة تيار I = 0.5 A. ما مقاومتها؟', '[{"id":"a","text":"3 Ω"},{"id":"b","text":"12 Ω"},{"id":"c","text":"6.5 Ω"},{"id":"d","text":"0.083 Ω"}]'::jsonb, 'b', 'من قانون أوم: R = U / I = 6 / 0.5 = 12 Ω. الخطأ 3 Ω ناتج عن ضرب U × I بدل قسمته.', 4),
  ('80f19d9c-dbf6-5b42-9d3f-1b965dd1fa1d', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'في دائرة تسلسلية: مصدر U = 12 V ومقاومتان R₁ = 30 Ω و R₂ = 60 Ω. ما شدّة التيار المار في الدائرة؟', '[{"id":"a","text":"0.4 A"},{"id":"b","text":"0.13 A"},{"id":"c","text":"1.5 A"},{"id":"d","text":"90 A"}]'::jsonb, 'b', 'في التسلسل: R_total = R₁ + R₂ = 30 + 60 = 90 Ω. ثمّ I = U / R_total = 12 / 90 ≈ 0.13 A. وهذا التيار نفسه يمرّ في كلّ مكوّنات الدائرة التسلسلية.', 5),
  ('9d87eea3-29a8-5554-95e5-6d658f6fd6e7', '20104077-d1f6-503d-84fc-5b7efb1e330d', 'في دائرة توازي بها فرعان، التوتر الكلّي U = 12 V. الفرع الأوّل R₁ = 4 Ω والثاني R₂ = 6 Ω. ما شدّة التيار في الفرع الثاني؟', '[{"id":"a","text":"3 A"},{"id":"b","text":"2 A"},{"id":"c","text":"1.2 A"},{"id":"d","text":"72 A"}]'::jsonb, 'b', 'في التوازي يكون التوتر على كلّ فرع مساويًا للتوتر الكلّي = 12 V. ففي الفرع الثاني: I₂ = U / R₂ = 12 / 6 = 2 A. (والفرع الأوّل I₁ = 12 / 4 = 3 A).', 6),
  ('d14c0f60-6da2-55c5-8785-7bf3766936e3', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Complete: "My brother usually ___ to school by bus."', '[{"id":"a","text":"go"},{"id":"b","text":"goes"},{"id":"c","text":"is going"},{"id":"d","text":"going"}]'::jsonb, 'b', '"usually" marks a habit, so we use the present simple; with the third-person singular subject "my brother" the verb takes -s: goes. "go" forgets the -s; "is going" is the present continuous (action now), which clashes with "usually"; "going" alone is not a finite verb.', 1),
  ('8407502b-fddc-5cd3-8d49-57b73532d39b', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Choose the correct sentence:', '[{"id":"a","text":"I am knowing the answer."},{"id":"b","text":"I knows the answer."},{"id":"c","text":"I know the answer."},{"id":"d","text":"I am know the answer."}]'::jsonb, 'c', '"know" is a stative verb (a mental state), so it is not used in the continuous: I know the answer. "am knowing" wrongly makes a stative verb continuous; "I knows" adds -s to a first-person subject; "am know" mixes "be" with a base verb.', 2),
  ('52851484-7889-5e36-b119-90b1e3d6811a', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Complete: "Look! It ___ outside, so take an umbrella."', '[{"id":"a","text":"rains"},{"id":"b","text":"rain"},{"id":"c","text":"is raining"},{"id":"d","text":"raining"}]'::jsonb, 'c', '"Look!" shows the action is happening at this moment, so we use the present continuous: it is raining. "rains" is present simple (a habit or general truth); "rain" lacks the -s and the continuous form; "raining" alone has no auxiliary "is".', 3),
  ('ff900417-defa-574f-b8c7-08e0b3fa1c5f', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Choose the correct question: "___ your sister speak English?"', '[{"id":"a","text":"Do"},{"id":"b","text":"Does"},{"id":"c","text":"Is"},{"id":"d","text":"Are"}]'::jsonb, 'b', 'Present simple questions with he/she/it use the auxiliary "does" + base verb: Does your sister speak...? "Do" is for I/you/we/they; "Is"/"Are" would introduce the present continuous (Is your sister speaking...?), not the present simple.', 4),
  ('31b2179a-b120-5b3e-aa93-1c722607e47b', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Choose the correct sentence:', '[{"id":"a","text":"He don''t understand the lesson."},{"id":"b","text":"He doesn''t understands the lesson."},{"id":"c","text":"He isn''t understand the lesson."},{"id":"d","text":"He doesn''t understand the lesson."}]'::jsonb, 'd', 'In the present simple negative with he, the auxiliary "does" carries the -s and the main verb stays in its base form: he doesn''t understand. "don''t" is the wrong auxiliary for "he"; "doesn''t understands" double-marks the -s; "isn''t understand" mixes "be" with a base verb.', 5),
  ('fa3867c5-204b-545f-8d8a-6a7d0bf12ca1', '350e9c30-be36-5bb3-b3e9-719d9f142839', 'Complete: "These days, more and more people ___ remotely from home."', '[{"id":"a","text":"are working"},{"id":"b","text":"works"},{"id":"c","text":"is working"},{"id":"d","text":"work"}]'::jsonb, 'a', '"These days" describes a temporary trend in progress around now, so we use the present continuous; the plural subject "people" takes "are": are working. "works" wrongly adds -s to a plural subject; "is working" uses the singular "is" with a plural subject; "work" (present simple) would suggest a fixed permanent habit, not a current trend.', 6),
  ('d022e990-1237-5d6b-b0bf-33f2369aeac4', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Complete: "Yesterday I ___ my grandparents in Sfax."', '[{"id":"a","text":"visit"},{"id":"b","text":"visited"},{"id":"c","text":"have visited"},{"id":"d","text":"was visiting"}]'::jsonb, 'b', '"Yesterday" is a finished past time marker, so we use the past simple: visited. "visit" is present; "have visited" (present perfect) cannot go with a finished time like yesterday; "was visiting" (past continuous) would need a longer background action, not a simple completed event.', 1),
  ('2dcbfba5-5976-5cf4-bd1c-49a3a8391813', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Complete: "While I ___ TV, the phone rang."', '[{"id":"a","text":"watched"},{"id":"b","text":"was watching"},{"id":"c","text":"have watched"},{"id":"d","text":"watch"}]'::jsonb, 'b', 'A longer background action interrupted by a sudden one uses the past continuous: I was watching TV when the phone rang. "watched" (past simple) loses the "in-progress" idea; "have watched" is present perfect; "watch" is present.', 2),
  ('267cb805-3c50-5e96-bbde-23956195cd16', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Choose the correct sentence:', '[{"id":"a","text":"I have seen this film last week."},{"id":"b","text":"I saw this film last week."},{"id":"c","text":"I see this film last week."},{"id":"d","text":"I was seeing this film last week."}]'::jsonb, 'b', '"last week" is a finished time, so we use the past simple: I saw this film last week. The present perfect (a) cannot combine with a finished time expression; (c) is present; (d) uses the continuous for a single completed action, which is wrong, and "see" is also stative.', 3),
  ('920e5c43-24eb-5f48-a671-d828a09799d4', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Choose the correct negative: "They ___ the homework on time."', '[{"id":"a","text":"didn''t finished"},{"id":"b","text":"don''t finish"},{"id":"c","text":"didn''t finish"},{"id":"d","text":"wasn''t finish"}]'::jsonb, 'c', 'In the past simple negative, "did" carries the tense and the main verb returns to its base form: didn''t finish. "didn''t finished" double-marks the past; "don''t finish" is present; "wasn''t finish" mixes "be" with a base verb (and the wrong number for "they").', 4),
  ('fdbb01a0-84ce-5e3a-8df0-75fbbf44dbe3', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Complete: "___ you ever ___ to London?"', '[{"id":"a","text":"Did / go"},{"id":"b","text":"Have / been"},{"id":"c","text":"Have / went"},{"id":"d","text":"Did / went"}]'::jsonb, 'b', '"ever" with no finished time asks about a life experience up to now, so we use the present perfect: Have you ever been to London? (a) past simple suits a specific past time, not an open experience; (c) uses the wrong past participle ("went" instead of "been/gone"); (d) mixes "did" with a past form.', 5),
  ('3b891d10-ca35-57e9-bf7f-ba16e93395bb', '6061e935-aa81-57d8-9e07-6940a9d538c9', 'Complete: "She ___ already ___ when the guests arrived."', '[{"id":"a","text":"has / left"},{"id":"b","text":"was / leaving"},{"id":"c","text":"had / left"},{"id":"d","text":"did / leave"}]'::jsonb, 'c', 'An action completed before another past action takes the past perfect: she had already left when the guests arrived. "has left" (present perfect) refers to now, not to a point in the past; "was leaving" describes an interrupted action, not one already finished; "did leave" cannot follow "already" in this earlier-than-the-past sense.', 6),
  ('120cfca7-61da-5532-94c1-0790a1ceffeb', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Choose the correct sentence:', '[{"id":"a","text":"Maybe it will snow tonight."},{"id":"b","text":"Maybe it is snowing tonight."},{"id":"c","text":"Maybe it snows tonight."},{"id":"d","text":"Maybe it going to snow tonight."}]'::jsonb, 'a', 'An uncertain prediction (signalled by "maybe") naturally uses "will": maybe it will snow tonight. The present continuous (b) implies a fixed arrangement, which is odd for weather; the present simple (c) suggests a habit/timetable; (d) drops "is" before "going to".', 1),
  ('5eab5c5f-9ed1-5310-9572-af91d04eb918', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Complete: "Look at those dark clouds! It ___ rain."', '[{"id":"a","text":"will"},{"id":"b","text":"is going to"},{"id":"c","text":"is"},{"id":"d","text":"goes to"}]'::jsonb, 'b', 'A prediction based on present evidence (dark clouds) uses "be going to": it is going to rain. "will" is used for predictions without visible evidence or for instant decisions; "is" alone has no main verb; "goes to" is not a future form.', 2),
  ('9b74588e-0387-5055-98fa-79d2e542499f', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Complete: "The phone is ringing. Don''t worry, I ___ answer it."', '[{"id":"a","text":"will"},{"id":"b","text":"am going to"},{"id":"c","text":"am"},{"id":"d","text":"answer"}]'::jsonb, 'a', 'An instant decision made at the moment of speaking uses "will": I''ll answer it. "am going to" suggests a plan made earlier, which contradicts the spontaneous decision; "am" needs the -ing form; "answer" alone has no future marker.', 3),
  ('0aff5ebb-d9a2-5842-9ac5-ae78c4e62fb7', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Complete: "The train ___ at 8:45 every morning."', '[{"id":"a","text":"will leave"},{"id":"b","text":"is leaving"},{"id":"c","text":"leaves"},{"id":"d","text":"is going to leave"}]'::jsonb, 'c', 'Timetables and schedules use the present simple, even for the future: the train leaves at 8:45. "will leave" and "is going to leave" treat a fixed timetable like a prediction; "is leaving" suits a one-off arrangement, not a regular schedule.', 4),
  ('54b86e72-424b-5e9d-903e-fcfd68cae6b3', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Choose the correct sentence about a fixed arrangement:', '[{"id":"a","text":"I will meet the dentist at 5 tomorrow."},{"id":"b","text":"I am meeting the dentist at 5 tomorrow."},{"id":"c","text":"I meet the dentist at 5 tomorrow."},{"id":"d","text":"I going to meet the dentist at 5 tomorrow."}]'::jsonb, 'b', 'A fixed, arranged plan with another person and a definite time uses the present continuous for the future: I am meeting the dentist at 5 tomorrow. "will" sounds like a prediction or instant decision, not a firm appointment; the present simple (c) is for timetables, not personal arrangements; (d) drops "am" before "going to".', 5),
  ('14f5f97c-9c0f-5ede-9836-067638a273fc', 'fe6fdcea-afaf-5ac7-a0fb-744699f5ffc1', 'Complete: "I''ll call you when I ___ home."', '[{"id":"a","text":"will get"},{"id":"b","text":"get"},{"id":"c","text":"am going to get"},{"id":"d","text":"will be getting"}]'::jsonb, 'b', 'After time words like "when" we use the present simple, not a future form, even for future meaning: when I get home. "will get", "am going to get" and "will be getting" all wrongly place a future form inside the time clause.', 6),
  ('5db5a8d8-fab9-5969-9c94-e595ed9267aa', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Complete: "You look tired. You ___ go to bed early."', '[{"id":"a","text":"must"},{"id":"b","text":"should"},{"id":"c","text":"can"},{"id":"d","text":"have to"}]'::jsonb, 'b', 'Friendly advice uses "should": you should go to bed early. "must" and "have to" express strong obligation, which is too forceful for a suggestion; "can" expresses ability or permission, not advice.', 1),
  ('6fd3fc33-e3db-595a-a973-7967c0469ca6', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Complete: "You ___ smoke here; it''s a hospital."', '[{"id":"a","text":"mustn''t"},{"id":"b","text":"don''t have to"},{"id":"c","text":"shouldn''t to"},{"id":"d","text":"mustn''t to"}]'::jsonb, 'a', '"mustn''t" expresses prohibition (it is forbidden): you mustn''t smoke here. "don''t have to" means it is not necessary (no obligation), which is the opposite meaning; modals are followed by a bare infinitive, so "shouldn''t to" and "mustn''t to" wrongly add "to".', 2),
  ('f53f9f28-16bb-5349-a7d9-a3b69c334298', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Choose the correct sentence:', '[{"id":"a","text":"She can to swim very well."},{"id":"b","text":"She cans swim very well."},{"id":"c","text":"She can swim very well."},{"id":"d","text":"She can swims very well."}]'::jsonb, 'c', 'A modal is followed by the bare infinitive and never changes for the third person: she can swim. "can to" wrongly adds "to"; "cans" wrongly adds -s to the modal; "can swims" wrongly adds -s to the main verb.', 3),
  ('48f3e5a8-8ced-57a6-9b00-4d5794ed4dd4', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Complete: "___ I open the window? It''s very hot."', '[{"id":"a","text":"May"},{"id":"b","text":"Must"},{"id":"c","text":"Should I to"},{"id":"d","text":"Am I"}]'::jsonb, 'a', '"May I...?" is the polite way to ask for permission: May I open the window? "Must I" asks about obligation, not permission; "Should I to" wrongly adds "to" after the modal; "Am I" is not a modal and leaves "open" without a correct form.', 4),
  ('1ea96d32-61f6-596f-8ba3-de15278076bc', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Complete: "It''s a public school, so students ___ pay any fees."', '[{"id":"a","text":"mustn''t"},{"id":"b","text":"don''t have to"},{"id":"c","text":"shouldn''t"},{"id":"d","text":"can''t"}]'::jsonb, 'b', '"don''t have to" means there is no obligation: the fees are simply not required. "mustn''t" would mean paying is forbidden, which is not the idea; "shouldn''t" gives advice against it; "can''t" expresses impossibility or refusal.', 5),
  ('ad16f401-eb6f-593c-a90c-07f819cc0d58', '1b58ef84-e8ff-5908-85ae-b13cda972800', 'Complete: "The lights are off, so they ___ be asleep."', '[{"id":"a","text":"can"},{"id":"b","text":"must"},{"id":"c","text":"should"},{"id":"d","text":"have to"}]'::jsonb, 'b', '"must" expresses a logical deduction from evidence: the lights are off, so they must be asleep. "can" here would suggest ability, not certainty; "should" expresses advice or expectation, weaker than a deduction; "have to" expresses obligation, not a conclusion.', 6),
  ('2557f68b-d1fe-54ce-89df-1820a60e498f', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Complete: "If you heat ice, it ___."', '[{"id":"a","text":"will melt"},{"id":"b","text":"melts"},{"id":"c","text":"would melt"},{"id":"d","text":"melted"}]'::jsonb, 'b', 'A general truth uses the zero conditional: if + present simple, present simple. If you heat ice, it melts. "will melt" belongs to the first conditional (a specific future result), not a permanent fact; "would melt" and "melted" belong to the second conditional (imaginary situations).', 1),
  ('78bec8e7-42c1-5dda-80fd-20ba4136196d', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Complete: "If it rains tomorrow, we ___ at home."', '[{"id":"a","text":"stay"},{"id":"b","text":"will stay"},{"id":"c","text":"would stay"},{"id":"d","text":"stayed"}]'::jsonb, 'b', 'A likely future condition uses the first conditional: if + present simple, will + base verb. If it rains tomorrow, we will stay at home. "stay" alone misses "will"; "would stay"/"stayed" are second-conditional forms for unreal situations.', 2),
  ('9829779a-863f-5a57-88b7-21254e3d8e69', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Complete: "If I ___ rich, I would travel the world."', '[{"id":"a","text":"am"},{"id":"b","text":"will be"},{"id":"c","text":"were"},{"id":"d","text":"would be"}]'::jsonb, 'c', 'An unreal or imaginary present situation uses the second conditional: if + past simple, would + base verb (and "were" is used for all persons). If I were rich, I would travel. "am"/"will be" suit real conditions; "would be" cannot appear in the if-clause.', 3),
  ('fc04747b-aebe-5c37-a221-d25b5c3dcc39', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Choose the correctly punctuated sentence:', '[{"id":"a","text":"If you study hard you will pass."},{"id":"b","text":"If you study hard, you will pass."},{"id":"c","text":"You will pass, if you study hard."},{"id":"d","text":"If, you study hard you will pass."}]'::jsonb, 'b', 'When the if-clause comes first, it is followed by a comma: If you study hard, you will pass. (a) omits that comma; in (c) there is no comma when the if-clause comes second; (d) wrongly places the comma straight after "If".', 4),
  ('c226d66f-23d6-5e65-ba82-2229c946b41c', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Complete: "___ you hurry, you will miss the bus."', '[{"id":"a","text":"If"},{"id":"b","text":"Unless"},{"id":"c","text":"When"},{"id":"d","text":"Because"}]'::jsonb, 'b', '"Unless" means "if... not": Unless you hurry (= if you do not hurry), you will miss the bus. "If" would reverse the meaning (hurrying would cause you to miss the bus); "When" loses the conditional idea; "Because" introduces a reason, not a condition.', 5),
  ('9f2d069b-fa0b-5f5c-9903-f395c6ade85b', 'a0cec752-fdcc-52c6-8f78-9fa392d7b638', 'Complete: "If she ___ harder last year, she would have better marks now."', '[{"id":"a","text":"works"},{"id":"b","text":"will work"},{"id":"c","text":"worked"},{"id":"d","text":"would work"}]'::jsonb, 'c', 'This is a second conditional describing an unreal/imagined situation, so the if-clause takes the past simple: If she worked harder... she would have better marks. "works"/"will work" are for real conditions; "would work" cannot go in the if-clause — "would" belongs in the result clause.', 6),
  ('9f51a9e2-ac5e-5418-9bce-61475a0c46c0', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Complete: "English ___ in many countries around the world."', '[{"id":"a","text":"speaks"},{"id":"b","text":"is spoken"},{"id":"c","text":"is speaking"},{"id":"d","text":"speak"}]'::jsonb, 'b', 'The subject "English" receives the action, so we use the present simple passive: be + past participle = is spoken. "speaks"/"speak" are active; "is speaking" is the active present continuous, which makes English the doer rather than the thing spoken.', 1),
  ('f5610d0d-6e08-5683-8742-12e78f2babaf', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Choose the passive form of: "They built this bridge in 1990."', '[{"id":"a","text":"This bridge was built in 1990."},{"id":"b","text":"This bridge is built in 1990."},{"id":"c","text":"This bridge built in 1990."},{"id":"d","text":"This bridge was build in 1990."}]'::jsonb, 'a', 'The past simple passive is was/were + past participle: this bridge was built in 1990. (b) uses the present "is" with a finished past time; (c) has no auxiliary, so it is not passive; (d) uses the base form "build" instead of the past participle "built".', 2),
  ('7996acd6-f402-5397-b872-795a696c4bb7', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Complete: "The letters ___ yesterday by the postman."', '[{"id":"a","text":"was delivered"},{"id":"b","text":"were delivered"},{"id":"c","text":"are delivered"},{"id":"d","text":"delivered"}]'::jsonb, 'b', 'The plural subject "the letters" and the past time "yesterday" require were + past participle: were delivered. "was delivered" uses the singular "was" with a plural subject; "are delivered" is present, not past; "delivered" alone (active) makes the letters the doer.', 3),
  ('1dd1def4-86e5-5073-9b3f-49d80a876b39', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Choose the passive form of: "Someone cleans the offices every morning."', '[{"id":"a","text":"The offices are cleaned every morning."},{"id":"b","text":"The offices is cleaned every morning."},{"id":"c","text":"The offices were cleaned every morning."},{"id":"d","text":"The offices are cleaning every morning."}]'::jsonb, 'a', 'The present simple passive with a plural subject is are + past participle: the offices are cleaned. "is cleaned" uses the singular auxiliary with a plural subject; "were cleaned" is past, but "every morning" is present; "are cleaning" is the active continuous, making the offices the doer.', 4),
  ('a3576e59-8351-52db-963a-e23eb337b92f', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Choose the correct sentence. The agent is unknown.', '[{"id":"a","text":"My bike was stolen last night."},{"id":"b","text":"My bike was stolen by someone last night."},{"id":"c","text":"Someone was stolen my bike last night."},{"id":"d","text":"My bike stole last night."}]'::jsonb, 'a', 'When the doer is unknown or unimportant, we use the passive and simply leave out the "by" phrase: my bike was stolen last night. (b) adds an empty "by someone", exactly the kind of useless agent the passive lets us drop; (c) is muddled (the bike, not someone, was stolen); (d) is active and uses the wrong form.', 5),
  ('89ca831c-9475-5039-bc24-33bc96445b41', '91cddb44-e94f-5907-a8ba-7ce1683c3e42', 'Complete: "This song ___ by millions of people every day."', '[{"id":"a","text":"listens"},{"id":"b","text":"is listening"},{"id":"c","text":"is listened to"},{"id":"d","text":"is listened"}]'::jsonb, 'c', '"listen" needs the preposition "to", which stays in the passive: this song is listened to. "listens"/"is listening" are active; "is listened" drops the required "to", leaving the verb incomplete.', 6),
  ('20c26877-8f50-5441-a3b2-64b75b441c2e', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this: He said, "I am tired."', '[{"id":"a","text":"He said that he is tired."},{"id":"b","text":"He said that he was tired."},{"id":"c","text":"He said that I was tired."},{"id":"d","text":"He said that he were tired."}]'::jsonb, 'b', 'In reported speech the present simple backshifts to the past simple, and "I" becomes "he": he said that he was tired. (a) keeps the present without backshift; (c) keeps the wrong pronoun "I"; (d) uses "were" with a singular subject.', 1),
  ('c62b1670-17ff-5d0e-b684-935a306288ac', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this: She said, "I will call you tomorrow."', '[{"id":"a","text":"She said she will call me the next day."},{"id":"b","text":"She said she would call me the next day."},{"id":"c","text":"She said she would call you tomorrow."},{"id":"d","text":"She said she would called me the next day."}]'::jsonb, 'b', '"will" backshifts to "would", "you" becomes "me", and "tomorrow" becomes "the next day": she said she would call me the next day. (a) keeps "will"; (c) keeps "you"/"tomorrow" unchanged; (d) adds -ed after "would".', 2),
  ('ba8523d7-f226-5903-93dd-45435cff9844', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this command: "Open the window," the teacher told us.', '[{"id":"a","text":"The teacher told us open the window."},{"id":"b","text":"The teacher told us to open the window."},{"id":"c","text":"The teacher told us that open the window."},{"id":"d","text":"The teacher told us opening the window."}]'::jsonb, 'b', 'Commands are reported with "tell + object + to + infinitive": the teacher told us to open the window. (a) drops the "to"; (c) wrongly uses "that" for a command; (d) uses the -ing form instead of the to-infinitive.', 3),
  ('fe1d97ca-88d0-5ee4-8fec-4f0ee037391e', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this yes/no question: "Are you coming to the party?" he asked.', '[{"id":"a","text":"He asked if I was coming to the party."},{"id":"b","text":"He asked if I am coming to the party."},{"id":"c","text":"He asked was I coming to the party."},{"id":"d","text":"He asked if you were coming to the party."}]'::jsonb, 'a', 'A reported yes/no question uses "if/whether", statement word order and backshift: he asked if I was coming. (b) fails to backshift "am" to "was"; (c) keeps question word order with no "if"; (d) keeps the wrong pronoun "you".', 4),
  ('b023da2d-36db-500b-ad6f-ce9794159a3f', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this: "I bought a new phone yesterday," he said.', '[{"id":"a","text":"He said he bought a new phone yesterday."},{"id":"b","text":"He said he had bought a new phone the day before."},{"id":"c","text":"He said he has bought a new phone the day before."},{"id":"d","text":"He said he buys a new phone the previous day."}]'::jsonb, 'b', 'The past simple backshifts to the past perfect, and "yesterday" becomes "the day before": he had bought a new phone the day before. (a) keeps the past simple and "yesterday"; (c) uses the present perfect, not the past perfect; (d) wrongly uses the present "buys".', 5),
  ('2aae1e21-eb52-5560-987a-f08b84c1c0ec', 'daa12303-1d75-5589-ab74-37dac1270cf7', 'Report this question: "Where do you live?" she asked.', '[{"id":"a","text":"She asked where do I live."},{"id":"b","text":"She asked where did I live."},{"id":"c","text":"She asked where I lived."},{"id":"d","text":"She asked where I live?"}]'::jsonb, 'c', 'A reported wh-question uses statement word order (no auxiliary "do", no question mark) and backshifts the tense: she asked where I lived. (a) and (b) keep the auxiliary "do/did" and question order; (d) keeps the question mark and present tense.', 6),
  ('6dd765f8-f95a-54ac-9410-d82ad64ccace', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "The man ___ lives next door is a doctor."', '[{"id":"a","text":"which"},{"id":"b","text":"who"},{"id":"c","text":"whose"},{"id":"d","text":"where"}]'::jsonb, 'b', '"who" is the relative pronoun for people acting as the subject: the man who lives next door. "which" is for things; "whose" shows possession; "where" refers to places.', 1),
  ('731275d6-6544-592f-a0bb-fd317ea9e825', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "That''s the girl ___ bag was stolen."', '[{"id":"a","text":"who"},{"id":"b","text":"which"},{"id":"c","text":"whose"},{"id":"d","text":"that"}]'::jsonb, 'c', '"whose" shows possession (the girl''s bag): the girl whose bag was stolen. "who"/"that" replace the person but cannot show possession; "which" is for things.', 2),
  ('d6e08b0d-d37d-534e-b7a3-fbc2929aa0bd', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "This is the restaurant ___ we had dinner last night."', '[{"id":"a","text":"which"},{"id":"b","text":"who"},{"id":"c","text":"where"},{"id":"d","text":"whose"}]'::jsonb, 'c', '"where" refers to a place and means "in which": the restaurant where we had dinner. "which" would need a preposition (in which); "who" is for people; "whose" shows possession.', 3),
  ('de922d60-b93c-52b8-9755-7ab94294ffd5', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "This book is ___ than the last one I read."', '[{"id":"a","text":"more interesting"},{"id":"b","text":"interestinger"},{"id":"c","text":"most interesting"},{"id":"d","text":"more interestinger"}]'::jsonb, 'a', 'Long adjectives form the comparative with "more": more interesting. "interestinger" wrongly adds -er to a long adjective; "most interesting" is the superlative; "more interestinger" double-marks the comparative.', 4),
  ('3c2a16fe-94a8-5a71-beb6-413d5b472af7', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "Everest is ___ mountain in the world."', '[{"id":"a","text":"the highest"},{"id":"b","text":"the higher"},{"id":"c","text":"highest"},{"id":"d","text":"the most high"}]'::jsonb, 'a', 'Comparing one thing with all others needs the superlative with "the": the highest mountain. "the higher" is a comparative (two things); "highest" needs "the"; "the most high" wrongly uses "most" with a short adjective that takes -est.', 5),
  ('99bb5c63-3dc9-5203-88e2-3d6ecca98e13', '1db52ab9-d385-5a85-9cd2-6d84b31ac29c', 'Complete: "My new phone is not ___ my old one; they cost the same."', '[{"id":"a","text":"as expensive as"},{"id":"b","text":"more expensive than"},{"id":"c","text":"as expensive than"},{"id":"d","text":"so expensive than"}]'::jsonb, 'a', 'To say two things are equal (or, with "not", to compare them) we use "as + adjective + as": not as expensive as. "more expensive than" states a difference, which contradicts "they cost the same"; (c) and (d) mix "as/so" with "than", which is incorrect.', 6),
  ('36414703-691f-5aaf-85e9-9f664293de54', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Read this paragraph about exercise:

"Regular exercise keeps the body healthy. It strengthens the heart and improves sleep. My cousin recently bought a red sports car. Above all, it lifts the mood and reduces stress."

Which sentence breaks the unity of the paragraph and should be removed?', '[{"id":"a","text":"\"It strengthens the heart and improves sleep.\""},{"id":"b","text":"\"My cousin recently bought a red sports car.\""},{"id":"c","text":"\"Above all, it lifts the mood and reduces stress.\""},{"id":"d","text":"\"Regular exercise keeps the body healthy.\""}]'::jsonb, 'b', 'The paragraph develops a single idea — the benefits of exercise — with supporting points and a closing sentence (''Above all…''). ''My cousin recently bought a red sports car'' has nothing to do with exercise, so it breaks the unity and should be removed.', 1),
  ('80de5c70-358d-5f68-a4fe-c16457e56b24', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Read this passage:

"For years, the small village had no library. Then a retired teacher began lending books from her own home. Word spread, neighbours donated more books, and soon a single shelf grew into three full rooms."

What is the main idea of this passage?', '[{"id":"a","text":"Retired teachers should not lend their books to others."},{"id":"b","text":"One person''s small action grew into a village library."},{"id":"c","text":"The village already had three libraries."},{"id":"d","text":"Books are too expensive for small villages."}]'::jsonb, 'b', 'The passage traces how one teacher''s lending grew, step by step, into a real library — that is the main idea. (a) contradicts the positive story; (c) is false, as the rooms appeared only later; (d) is never mentioned in the text.', 2),
  ('b0d22343-a40f-5803-a63a-2d20027a1008', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Read this passage:

"Karim glanced at the clock, grabbed his bag without zipping it, and ran out of the house, leaving his breakfast untouched on the table."

What can we infer about Karim?', '[{"id":"a","text":"He was late and in a hurry."},{"id":"b","text":"He was not hungry that morning."},{"id":"c","text":"He had nothing to do that day."},{"id":"d","text":"He had forgotten where his bag was."}]'::jsonb, 'a', 'Glancing at the clock, not zipping the bag, running out and skipping breakfast are all clues that Karim was rushing because he was late. The text does not say this directly, but the details prove it. (b) ignores the rush as the cause; (c) contradicts his hurry; (d) is not suggested.', 3),
  ('9577d052-f65b-5fbb-9340-6341c231d3e2', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Read this passage:

"Many tourists visit the old medina for its narrow streets and lively markets. However, few of them realise how fragile these ancient walls have become."

In the second sentence, what does "them" refer to?', '[{"id":"a","text":"the narrow streets"},{"id":"b","text":"the ancient walls"},{"id":"c","text":"the tourists"},{"id":"d","text":"the lively markets"}]'::jsonb, 'c', '"them" replaces the people who do the realising — the tourists mentioned in the first sentence. Pronouns point back to a noun already named. The streets (a), walls (b) and markets (d) are things that cannot "realise" anything.', 4),
  ('62cc893d-b490-5003-99db-a0a33132fb14', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Read this passage:

"The new recycling scheme was a complete fiasco: bins were delivered late, instructions were unclear, and within a month most residents had simply given up."

What does the word "fiasco" most probably mean?', '[{"id":"a","text":"a great success"},{"id":"b","text":"a complete failure"},{"id":"c","text":"an expensive project"},{"id":"d","text":"a long delay"}]'::jsonb, 'b', 'The context — late bins, unclear instructions, residents giving up — all describes things going wrong, so "fiasco" means a complete failure. (a) is the opposite; (c) cost is not the focus; (d) a delay is only one of several problems, not the whole meaning.', 5),
  ('cda6ae4e-68e6-5e12-ae28-ae797997cbb7', '72e8b533-b69b-5f4e-95db-09d94ad60365', 'Put these sentences in the correct order to form a well-organised paragraph:

1. "As a result, the team finished the project a whole week early."
2. "Working as a team brings many benefits."
3. "First, members can share the workload instead of struggling alone."
4. "They also encourage one another when difficulties appear."

What is the best order?', '[{"id":"a","text":"2 – 3 – 4 – 1"},{"id":"b","text":"1 – 2 – 3 – 4"},{"id":"c","text":"3 – 2 – 4 – 1"},{"id":"d","text":"2 – 1 – 3 – 4"}]'::jsonb, 'a', 'Sentence 2 is the general topic sentence and comes first. Then 3 (''First'') and 4 (''also'') give two supporting points, and 1 (''As a result'') states the outcome and closes the paragraph: 2 – 3 – 4 – 1. The connectors only make sense in this order.', 6),
  ('476aa55c-605b-544b-89ef-280d038a1bc9', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ce passage :

« On vante volontiers la patience de ceux qui attendent leur heure. J''y vois plus souvent la résignation de ceux qui n''osent plus la provoquer. La patience, cette vertu si commode pour qui se contente de durer. »

Quelle attitude l''auteur adopte-t-il à l''égard de la patience ?', '[{"id":"a","text":"Il en fait l''éloge sans réserve comme d''une vertu cardinale."},{"id":"b","text":"Il la démystifie en la requalifiant ironiquement de passivité déguisée."},{"id":"c","text":"Il l''analyse de façon neutre et purement descriptive."},{"id":"d","text":"Il la recommande aux seuls esprits ambitieux et déterminés."}]'::jsonb, 'b', 'L''auteur prend ses distances avec l''éloge convenu : il oppose à « la patience » louée par autrui sa propre lecture (« J''y vois plus souvent la résignation »), puis la disqualifie par l''ironie (« cette vertu si commode pour qui se contente de durer »). Il démystifie donc une valeur reçue en y débusquant une passivité. L''option (a) prend le premier énoncé pour la thèse de l''auteur alors qu''il s''en démarque. L''option (c) ignore la charge critique du « si commode » ironique. L''option (d) invente une recommandation absente : l''auteur dénonce, il ne conseille pas.', 1),
  ('f802b339-cc4c-57f0-84ac-500b0d1673f7', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ce passage :

« Le progrès technique, dit-on, libère l''homme des tâches pénibles. Soit. Mais à mesure qu''il nous décharge de l''effort, ne nous décharge-t-il pas aussi, insensiblement, de la compétence — et avec elle, d''une certaine fierté d''être capable ? »

Que suggère la question finale posée par l''auteur ?', '[{"id":"a","text":"Que le progrès technique doit être interdit pour préserver les savoir-faire."},{"id":"b","text":"Que l''allègement de l''effort pourrait s''accompagner d''une perte de compétence et d''estime de soi."},{"id":"c","text":"Que les tâches pénibles procurent toujours plus de fierté que les loisirs."},{"id":"d","text":"Que la technique n''a aucun effet mesurable sur les capacités humaines."}]'::jsonb, 'b', 'La question rhétorique « ne nous décharge-t-il pas aussi… de la compétence — et… d''une certaine fierté ? » est une affirmation déguisée : l''auteur suggère que l''avantage (moins d''effort) a une contrepartie cachée (perte de compétence et d''estime). L''option (b) restitue cette nuance. L''option (a) radicalise en une interdiction que le texte ne formule pas (le « Soit » concède même la libération). L''option (c) déforme : il n''est question ni de loisirs ni d''une comparaison de fiertés. L''option (d) contredit le texte, qui pose précisément un effet (la décharge progressive de la compétence).', 2),
  ('a3240a58-68e4-57d8-8c21-5387b1d1d597', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ce passage :

« Elle relut la lettre une dernière fois, sourit, puis la plia avec soin avant de la déchirer en menus morceaux qu''elle laissa filer par la fenêtre. »

Que révèle l''enchaînement des gestes du personnage ?', '[{"id":"a","text":"Une colère brutale et incontrôlée contre l''expéditeur de la lettre."},{"id":"b","text":"Une indifférence totale à l''égard du contenu de la lettre."},{"id":"c","text":"Un renoncement apaisé et délibéré, accompli sans amertume."},{"id":"d","text":"Une hésitation anxieuse quant à la décision à prendre."}]'::jsonb, 'c', 'Le détail des gestes oriente l''interprétation : elle « sourit », plie « avec soin », et le déchirement n''est ni rageur ni précipité mais maîtrisé (« en menus morceaux qu''elle laissa filer »). L''ensemble dessine un renoncement consenti et serein. L''option (a) contredit le « sourit » et le « avec soin » qui excluent la fureur. L''option (b) est démentie par la relecture attentive : elle n''est pas indifférente. L''option (d) prête une hésitation que l''achèvement net du geste et le sourire écartent.', 3),
  ('30feca9c-e19b-56a1-85c6-4c28c20fa411', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ces deux phrases d''un même texte :

« (1) Certes, les réseaux sociaux donnent la parole à des voix longtemps inaudibles. (2) Encore faut-il que cette parole, noyée dans le flot, parvienne à se faire entendre. »

Quel rôle joue la locution « Encore faut-il que » en tête de la phrase (2) ?', '[{"id":"a","text":"Elle ajoute un argument allant dans le même sens que (1), pour le renforcer."},{"id":"b","text":"Elle introduit une restriction qui limite la portée de la concession faite en (1)."},{"id":"c","text":"Elle reformule l''idée de (1) sans en modifier la portée."},{"id":"d","text":"Elle pose la conséquence logique et inévitable de l''idée énoncée en (1)."}]'::jsonb, 'b', '« Encore faut-il que » pose une condition restrictive : elle accorde le point précédent (« Certes… ») tout en signalant qu''il ne suffit pas — donner la parole ne vaut que si cette parole peut effectivement être entendue. C''est une restriction qui nuance la concession. L''option (a) confond ajout et limitation : la phrase (2) ne renforce pas (1), elle en borne la portée. L''option (c) néglige cette inflexion : la portée est précisément modifiée. L''option (d) y voit une conséquence (« donc »), alors qu''il s''agit d''une condition non garantie.', 4),
  ('c1ed7e8d-0e91-5728-9003-b5fd12a3c7ee', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ce passage :

« Il ne mentait jamais. Il se contentait de choisir, parmi les vérités, celles qui le servaient — et de taire les autres. »

Quel portrait moral du personnage se dégage de ces lignes ?', '[{"id":"a","text":"Un homme d''une honnêteté irréprochable et d''une transparence exemplaire."},{"id":"b","text":"Un homme qui, sans mentir au sens strict, manipule par sélection et omission."},{"id":"c","text":"Un homme incapable de dissimuler quoi que ce soit à son entourage."},{"id":"d","text":"Un homme naïf qui ignore l''effet de ses paroles sur autrui."}]'::jsonb, 'b', 'Le texte joue sur l''écart entre la lettre et l''esprit : « Il ne mentait jamais » est immédiatement retourné par ce qui suit (il trie les vérités utiles et tait le reste). Le procédé révèle une manipulation par sélection et omission, plus retorse que le mensonge franc. L''option (a) s''arrête à la première phrase et ignore le démenti ironique. L''option (c) est contredite par le « taire les autres », qui est précisément une dissimulation. L''option (d) prête une naïveté incompatible avec le calcul (« celles qui le servaient »).', 5),
  ('d327a865-d514-51e3-98f3-378dbd03cb3d', 'f54249c2-0582-5cab-bb49-93e5d3d2bd35', 'Lisez ce passage :

« Les statistiques sont formelles : depuis dix ans, la délinquance recule. Pourtant, jamais le sentiment d''insécurité n''a été aussi vif. Faut-il en conclure que les chiffres mentent — ou que la peur, elle, ne se nourrit pas de chiffres ? »

Quelle est l''intention principale de l''auteur dans ce passage ?', '[{"id":"a","text":"Prouver, données à l''appui, que la délinquance est en réalité en hausse."},{"id":"b","text":"Inviter le lecteur à distinguer la réalité mesurée et la perception subjective qui ne s''y réduit pas."},{"id":"c","text":"Démontrer que les statistiques officielles sont systématiquement falsifiées."},{"id":"d","text":"Rassurer le lecteur en affirmant que toute peur est dénuée de fondement."}]'::jsonb, 'b', 'L''alternative finale (« les chiffres mentent — ou… la peur ne se nourrit pas de chiffres ») oriente clairement vers la seconde branche : l''auteur amène à dissocier la réalité objective (baisse mesurée) du ressenti subjectif (insécurité vive), qui obéit à d''autres ressorts. L''option (a) contredit la prémisse acceptée (« Les statistiques sont formelles… recule »). L''option (c) retient l''hypothèse que la question rhétorique écarte au profit de l''autre. L''option (d) durcit le propos en un déni de toute peur, alors que l''auteur en explique le mécanisme sans la disqualifier.', 6),
  ('ccd840c4-cc50-5339-a540-b4994840b711', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Dans la phrase « Quiconque a lu ce roman en mesure la portée », quelle est la fonction de « Quiconque a lu ce roman » ?', '[{"id":"a","text":"Complément d''objet direct du verbe « mesure »"},{"id":"b","text":"Sujet du verbe « mesure »"},{"id":"c","text":"Complément circonstanciel de condition"},{"id":"d","text":"Apposition au pronom « en »"}]'::jsonb, 'b', '« Quiconque » est un pronom relatif indéfini sans antécédent qui forme, avec la subordonnée qu''il introduit, un groupe nominalisé occupant la fonction de sujet : « Qui est-ce qui en mesure la portée ? » → « Quiconque a lu ce roman ». L''option (a) confond avec le COD, qui est ici « la portée » (repris par « en » pour le complément du nom). L''option (c) plaque une valeur de condition que « quiconque » n''a pas : il généralise un sujet, il ne pose pas d''hypothèse comme « si ». L''option (d) est fautive : « en » est complément du nom « portée », non un terme appelant une apposition.', 1),
  ('8a6da883-7ec6-5058-a646-8f94b34de605', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Quelle phrase met correctement en relief le complément « à ses parents » au moyen d''un présentatif ?', '[{"id":"a","text":"À ses parents, c''est à eux qu''il doit tout."},{"id":"b","text":"C''est à ses parents qu''il doit tout."},{"id":"c","text":"C''est ses parents dont il doit tout."},{"id":"d","text":"Ce sont à ses parents qu''il doit tout."}]'::jsonb, 'b', 'L''extraction par présentatif « c''est… que » conserve la préposition régie par le verbe (« devoir qqch. à qqn ») : « C''est à ses parents qu''il doit tout. » L''option (a) cumule une dislocation (« À ses parents ») et une extraction redondante (« c''est à eux que »), ce qui est pléonastique et fautif. L''option (c) emploie « dont » (mis pour « de qui »), incompatible avec la construction en « à ». L''option (d) accorde à tort le présentatif au pluriel (« Ce sont ») devant un groupe prépositionnel : on dit « C''est à… ».', 2),
  ('81f2daf0-3330-50e4-a637-bfdb518b1811', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Laquelle de ces phrases comporte une concordance des temps fautive ?', '[{"id":"a","text":"Je craignais qu''il ne fût trop tard."},{"id":"b","text":"Il voulait que nous partions sur-le-champ."},{"id":"c","text":"Elle souhaitait que tu réussisses ton examen."},{"id":"d","text":"Nous pensions qu''il vienne le lendemain."}]'::jsonb, 'd', '« Penser que », à la forme affirmative, exprime une opinion posée comme réelle et appelle l''indicatif : il faut « qu''il viendrait le lendemain » (futur du passé), non le subjonctif « qu''il vienne ». L''option (d) est donc fautive. Les options (a), (b) et (c) reposent sur des verbes de crainte ou de volonté (« craindre », « vouloir », « souhaiter ») qui régissent légitimement le subjonctif ; les temps y sont cohérents avec le contexte passé (subjonctif imparfait en a, présent admis dans l''usage en b et c).', 3),
  ('c7a0b57b-63ba-5ad0-a56b-dc6c373c39ff', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Choisissez la phrase qui corrige la zeugme syntaxique de « *Il sortit son mouchoir et ses excuses ».', '[{"id":"a","text":"Il sortit son mouchoir et présenta ses excuses."},{"id":"b","text":"Il sortit son mouchoir et ses excuses ensemble."},{"id":"c","text":"Il sortit son mouchoir, ses excuses aussi."},{"id":"d","text":"Il sortit et son mouchoir et ses excuses."}]'::jsonb, 'a', 'La phrase de départ coordonne sous un seul verbe deux compléments qui n''en admettent pas le même sens : on « sort » un mouchoir (sens concret) mais on ne « sort » pas des excuses (il faut « présenter / faire » des excuses). La correction consiste à doter chaque complément du verbe approprié : « Il sortit son mouchoir et présenta ses excuses. » Les options (b), (c) et (d) maintiennent l''unique verbe « sortir » pour les deux compléments et laissent donc subsister l''attelage fautif.', 4),
  ('c8e9fba5-743a-54f0-bc2b-4450a9501479', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Quel verbe complète correctement la phrase « Il ___ à ce que tout soit vérifié avant la publication » en respectant le régime du verbe ?', '[{"id":"a","text":"exigea"},{"id":"b","text":"veilla"},{"id":"c","text":"réclama"},{"id":"d","text":"ordonna"}]'::jsonb, 'b', 'Seul « veiller » se construit avec « à ce que » + subjonctif : « veiller à ce que tout soit vérifié » est la tournure attendue, le verbe régissant la préposition « à ». Les options (a), (c) et (d) régissent une complétive directe sans préposition : on dit « exiger que », « réclamer que », « ordonner que » (et non « *exiger à ce que », « *réclamer à ce que », « *ordonner à ce que »). Le « à ce que » déjà présent dans l''énoncé impose donc « veilla ».', 5),
  ('3c1dcfe8-09c4-5c3c-9e0b-540698241c5c', '534a0c72-b1fc-5531-9dcc-162b0488cc61', 'Dans laquelle de ces phrases la proposition subordonnée est-elle une relative (et non une complétive conjonctive) ?', '[{"id":"a","text":"Je sais que tu as raison."},{"id":"b","text":"L''argument que tu avances me convainc."},{"id":"c","text":"Il faut que tu reviennes."},{"id":"d","text":"Je doute que cela suffise."}]'::jsonb, 'b', 'Dans l''option (b), « que » est un pronom relatif COD reprenant l''antécédent « l''argument » : la subordonnée « que tu avances » complète un nom et peut se gloser par « lequel tu avances » → c''est une relative. Dans (a), (c) et (d), « que » est une conjonction de subordination introduisant une complétive complément du verbe (« savoir que », « il faut que », « douter que ») : il n''y a aucun antécédent nominal repris, et « que » n''y a pas de fonction grammaticale dans la subordonnée.', 6),
  ('3e19d9f5-874c-541e-90b5-54c54fdb2f00', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Quelle phrase respecte l''accord du participe passé avec « avoir » et COD antéposé ?', '[{"id":"a","text":"Les efforts qu''il a fournis ont payé."},{"id":"b","text":"Les efforts qu''il a fourni ont payé."},{"id":"c","text":"Les efforts qu''il a fournit ont payé."},{"id":"d","text":"Les efforts qu''il a fournies ont payé."}]'::jsonb, 'a', 'Avec l''auxiliaire « avoir », le participe passé s''accorde avec le COD lorsque celui-ci précède le verbe. Ici le COD est « les efforts » (masculin pluriel), repris par le relatif « que » placé avant « a fourni » : le participe prend donc la marque du masculin pluriel → « fournis ». L''option (b) laisse le participe invariable, en oubliant l''accord avec le COD antéposé. L''option (c) écrit une forme verbale conjuguée (« fournit ») au lieu du participe. L''option (d) accorde au féminin, ce qui ne correspond pas au genre de « efforts ».', 1),
  ('dd97f75f-40ae-58fb-8bfb-a16b0fb1795b', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Dans la phrase « Il n''est pas certain qu''elle ___ à temps », quelle forme verbale est correcte ?', '[{"id":"a","text":"arrivera"},{"id":"b","text":"arrive"},{"id":"c","text":"arriverait"},{"id":"d","text":"arrivait"}]'::jsonb, 'b', 'La forme négative « il n''est pas certain que » exprime un doute et appelle le subjonctif → « qu''elle arrive ». C''est le pendant inverse de « il est certain que » (certitude) qui, lui, régit l''indicatif (« qu''elle arrivera »). L''option (a) emploie l''indicatif futur, valable seulement à la forme affirmative. Les options (c) et (d) proposent un conditionnel et un imparfait que la construction n''autorise pas ici.', 2),
  ('7356941c-ecb1-5fb9-a2e2-c00236ed4d85', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Dans la phrase « Les dix euros que ce livre m''a ___ valaient la dépense », quelle forme du participe « coûter » convient ?', '[{"id":"a","text":"coûtés"},{"id":"b","text":"coûté"},{"id":"c","text":"coûtée"},{"id":"d","text":"coûtées"}]'::jsonb, 'b', 'Employé au sens propre (un prix, une somme), « coûter » est intransitif : « les dix euros » n''est pas un COD mais un complément circonstanciel de prix (« combien ce livre a-t-il coûté ? »). Le participe reste donc invariable → « coûté ». Le piège est l''antéposition de « que », qui simule un COD : mais on n''accorde pas, car il n''y a pas de COD. (Au sens figuré — « les efforts que ce projet m''a coûtés » — l''accord redeviendrait possible.) Les options (a), (c) et (d) appliquent à tort la règle de l''accord avec un faux COD.', 3),
  ('b8d3d3ef-4629-5188-9bea-79e3c147eab8', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Repérez la phrase où TOUS les homophones grammaticaux sont correctement orthographiés.', '[{"id":"a","text":"Quand bien même il s''entêterait, on ne changerait pas d''avis quant à lui."},{"id":"b","text":"Quant bien même il s''entêterait, on ne changerait pas d''avis quand à lui."},{"id":"c","text":"Quand bien même il s''entêterait, on ne changerait pas d''avis quand à lui."},{"id":"d","text":"Quant bien même il s''entêterait, on ne changerait pas d''avis quant à lui."}]'::jsonb, 'a', 'Deux homophones sont en jeu. « Quand bien même » (locution concessive, équivalant à « même si ») s''écrit avec « quand ». « Quant à » (au sens de « en ce qui concerne ») s''écrit avec « quant ». Seule l''option (a) combine les deux graphies correctes. L''option (b) inverse les deux ; les options (c) et (d) se trompent chacune sur l''un des deux termes.', 4),
  ('c3a39f38-5cbe-5ea3-9a60-9f96ce2b69ca', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Quelle phrase contient un emploi correct de « leur », « se » et « ces / ses » sans aucune faute ?', '[{"id":"a","text":"Les enfants ont rangé leurs jouets, puis se sont mis à lire ces livres qu''ils aiment."},{"id":"b","text":"Les enfants ont rangé leur jouets, puis ce sont mis à lire ses livres qu''ils aiment."},{"id":"c","text":"Les enfants ont rangé leurs jouets, puis ce sont mis à lire ces livres qu''ils aiment."},{"id":"d","text":"Les enfants ont rangé leur jouets, puis se sont mis à lire ces livres qu''ils aiment."}]'::jsonb, 'a', 'Trois points sont testés. « Leurs jouets » : déterminant possessif au pluriel car chaque enfant a plusieurs jouets et le nom est au pluriel → « leurs ». « Se sont mis » : pronom réfléchi « se » du verbe pronominal « se mettre » (et non « ce », démonstratif). « Ces livres » : déterminant démonstratif désignant des livres présents (et non « ses », possessif). Seule l''option (a) réunit les trois graphies correctes. (b) cumule « leur » singulier fautif, « ce » au lieu de « se » et « ses » au lieu de « ces » ; (c) garde le « ce » fautif ; (d) garde le « leur » singulier fautif.', 5),
  ('a19551e0-c43b-50a9-8765-e100dd0276e8', 'c22e7d7c-648d-58ad-9221-65c0523458d7', 'Dans la phrase « ___ que soient les obstacles, elle persévérera », quelle forme convient ?', '[{"id":"a","text":"Quels"},{"id":"b","text":"Quelque"},{"id":"c","text":"Quel"},{"id":"d","text":"Quelques"}]'::jsonb, 'a', 'La locution concessive « quel que » (en deux mots) s''emploie devant le verbe « être » au subjonctif et s''accorde avec le sujet qui suit. Ici le sujet est « les obstacles » (masculin pluriel), donc « Quels que soient les obstacles ». L''option (b) « quelque » (en un mot) est un adverbe ou un déterminant qui ne s''emploie pas devant « que soient ». L''option (c) ne fait pas l''accord en nombre. L''option (d) « quelques » est un déterminant indéfini, étranger à cette tournure concessive.', 6),
  ('1229b917-95ca-56e5-9bb9-9642304181eb', '1a82c875-7519-569f-b160-f4a24344656f', 'Choisissez le paronyme juste : « Le ministre a tenu des propos ___ qui ont apaisé les tensions. » Le mot attendu signifie « propre à concilier, à réconcilier ».', '[{"id":"a","text":"conciliants"},{"id":"b","text":"concis"},{"id":"c","text":"consensuels"},{"id":"d","text":"conciliables"}]'::jsonb, 'a', '« Conciliant » qualifie ce qui — ou celui qui — cherche à concilier, à apaiser : des « propos conciliants » désamorcent un conflit, ce qui correspond exactement au contexte (« ont apaisé les tensions »). Le piège est « conciliable », qui signifie « qui peut s''accorder avec autre chose » (deux thèses conciliables) et ne se dit pas de propos apaisants. « Concis » signifie « bref, ramassé », sans rapport avec l''apaisement. « Consensuel » conviendrait par le sens mais s''écarte de la définition donnée, centrée sur l''action de concilier propre à « conciliant ».', 1),
  ('1b7380a4-60eb-578f-90d3-657d5b22e971', '1a82c875-7519-569f-b160-f4a24344656f', 'Quel mot complète justement : « Cette mesure ___ le problème au lieu de le résoudre, en le repoussant à plus tard. » Le terme attendu signifie « différer, retarder ».', '[{"id":"a","text":"élude"},{"id":"b","text":"ajourne"},{"id":"c","text":"résout"},{"id":"d","text":"exacerbe"}]'::jsonb, 'b', '« Ajourner » signifie renvoyer à une date ultérieure, différer — c''est exactement « repousser à plus tard » l''énoncé. « Éluder » signifie esquiver, contourner une question sans la traiter : proche, mais l''idée n''est pas le report dans le temps mais l''évitement, et la suite (« en le repoussant à plus tard ») désigne bien le report. « Résoudre » est l''antonyme de ce que dit la phrase (« au lieu de le résoudre »). « Exacerber » signifie aggraver, intensifier, ce qui ne correspond ni à la définition donnée ni au contexte.', 2),
  ('0f353fd6-63bf-5c48-b0fe-5d952a0c3025', '1a82c875-7519-569f-b160-f4a24344656f', 'Choisissez le mot de registre soutenu signifiant « qui parle peu, avare de paroles ».', '[{"id":"a","text":"taiseux"},{"id":"b","text":"taciturne"},{"id":"c","text":"muet"},{"id":"d","text":"discret"}]'::jsonb, 'b', '« Taciturne » désigne, en registre soutenu, une personne d''humeur silencieuse, peu encline à parler — c''est l''équivalent exact de la définition. « Taiseux » a le même sens mais relève d''un usage régional ou familier. « Muet » signifie privé de l''usage de la parole (une incapacité), et non le simple fait de parler peu. « Discret » porte sur la réserve, la retenue dans la conduite ou la confidence, non spécifiquement sur la rareté des paroles.', 3),
  ('1c8d65ce-dbd3-555d-bf40-1318ebba46f8', '1a82c875-7519-569f-b160-f4a24344656f', 'Dans « Son discours était truffé de ___ : il répétait sans cesse les mêmes idées sous des formes différentes », quel mot convient ? Le terme désigne la répétition inutile d''une même idée.', '[{"id":"a","text":"pléonasmes"},{"id":"b","text":"redondances"},{"id":"c","text":"digressions"},{"id":"d","text":"périphrases"}]'::jsonb, 'b', '« Redondance » désigne la répétition superflue d''une même idée, énoncée plusieurs fois sous des formulations différentes — ce que décrit précisément la phrase. Le « pléonasme » est plus étroit : il répète une notion à l''intérieur d''une même expression (« monter en haut »), ce qui ne couvre pas la répétition d''idées d''une phrase à l''autre. La « digression » est un écart par rapport au sujet, non une répétition. La « périphrase » est un détour pour désigner une chose en plusieurs mots (« l''astre du jour » pour le soleil), sans idée de redite.', 4),
  ('403c7dc2-aaeb-5c2c-973f-c5203c8be46c', '1a82c875-7519-569f-b160-f4a24344656f', 'Identifiez l''emploi correct de « émigrer » par opposition à « immigrer ».', '[{"id":"a","text":"Au XIXe siècle, des milliers d''Irlandais émigrèrent vers les États-Unis pour fuir la famine."},{"id":"b","text":"Au XIXe siècle, des milliers d''Irlandais émigrèrent aux États-Unis, où ils s''installèrent durablement."},{"id":"c","text":"Beaucoup d''Italiens émigrèrent en France, ce qui enrichit la population française d''arrivants."},{"id":"d","text":"Le pays a accueilli ceux qui émigraient sur son territoire."}]'::jsonb, 'a', '« Émigrer », c''est quitter son pays d''origine ; le verbe se construit avec un point de départ et la destination introduite par « vers / pour ». L''option (a) est exemplaire : « émigrèrent vers les États-Unis pour fuir la famine » envisage le départ depuis l''Irlande. Les options (b), (c) et (d) adoptent le point de vue de l''arrivée et du séjour dans le pays d''accueil (« s''installèrent », « enrichit la population française », « sur son territoire »), ce qui relève d''« immigrer ». Le verbe doit être choisi selon le point de vue : départ → émigrer ; arrivée → immigrer.', 5),
  ('d9721052-6326-5cdc-b9b1-ff7546955bca', '1a82c875-7519-569f-b160-f4a24344656f', 'Quel mot complète justement : « Devant l''ampleur de la catastrophe, l''aide internationale s''est révélée ___ : quelques tentes pour des milliers de sinistrés. » Le terme attendu signifie « insuffisant au point d''être dérisoire ».', '[{"id":"a","text":"parcimonieuse"},{"id":"b","text":"frugale"},{"id":"c","text":"indigente"},{"id":"d","text":"ascétique"}]'::jsonb, 'c', '« Indigent » signifie, au sens figuré, d''une pauvreté criante, dérisoirement insuffisant : une aide « indigente » est si maigre qu''elle en devient dérisoire, ce qu''illustre « quelques tentes pour des milliers de sinistrés ». « Parcimonieux » qualifie celui qui donne avec une économie mesurée, intentionnelle — une retenue, non une insuffisance accablante. « Frugal » se dit d''un repas ou d''une vie simple et sobre, par choix, sans nuance péjorative d''insuffisance. « Ascétique » renvoie à une privation volontaire et austère, étrangère à l''idée d''une aide défaillante subie.', 6),
  ('4ec0849b-98db-538d-8d52-74d6512bb941', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'أين تُنتَج النطاف وأين تُنتَج البويضات؟', '[{"id":"a","text":"النطاف في الخصيتين والبويضات في المبيضين"},{"id":"b","text":"النطاف في البروستاتا والبويضات في الرحم"},{"id":"c","text":"النطاف في المبيضين والبويضات في الخصيتين"},{"id":"d","text":"كلاهما يُنتَج في الغدد الملحقة"}]'::jsonb, 'a', 'الخصيتان هما الغدّتان التناسليتان عند الرجل وتنتجان النطاف، والمبيضان هما الغدّتان التناسليتان عند المرأة وينتجان البويضات. البروستاتا غدّة ملحقة تفرز جزءًا من السائل المنوي ولا تنتج مشيجًا، والرحم مكان التعشيش والحمل لا إنتاج البويضات، والغدد الملحقة لا تنتج مشيجًا أصلًا.', 1),
  ('3d76dd20-0515-5e18-b768-f0193ecaf8f1', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ما الحدث الذي يميّز بداية البلوغ عند الفتاة؟', '[{"id":"a","text":"ظهور أوّل طمث (الحيض)"},{"id":"b","text":"نزول الخصيتين"},{"id":"c","text":"توقّف نموّ العظام نهائيًّا"},{"id":"d","text":"اختفاء العلامات الجنسية الثانوية"}]'::jsonb, 'a', 'أوّل طمث علامة دالّة على بدء نشاط المبيضين ودخول الفتاة مرحلة البلوغ والقدرة على الإنجاب. نزول الخصيتين شأن ذكوري لا أنثوي، والبلوغ يُرافقه ظهور العلامات الجنسية الثانوية لا اختفاؤها، ونموّ العظام يستمرّ خلال هذه المرحلة لا يتوقّف فجأةً.', 2),
  ('b8cfb1f9-52b7-5fb5-ab41-dea79ac151c3', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ماذا نقصد بـ«الإباضة» في الدورة الجنسية عند المرأة؟', '[{"id":"a","text":"تساقط بطانة الرحم خارج الجسم"},{"id":"b","text":"تحرير المبيض لبويضة ناضجة حول منتصف الدورة"},{"id":"c","text":"اندماج النطفة بالبويضة"},{"id":"d","text":"انغراس البيضة المخصّبة في الرحم"}]'::jsonb, 'b', 'الإباضة هي تحرير المبيض لبويضة ناضجة، وتحدث عادةً حول اليوم 14 من دورة طولها 28 يومًا. تساقط بطانة الرحم هو الطمث، واندماج النطفة بالبويضة هو الإلقاح، وانغراس البيضة المخصّبة هو التعشيش؛ وكلّها أحداث مختلفة عن الإباضة.', 3),
  ('71d59e4d-2af1-53c4-a747-8ea29a033b7d', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'ما الفرق الأساسي بين الإلقاح والتعشيش؟', '[{"id":"a","text":"الإلقاح اندماج النطفة بالبويضة، والتعشيش انغراس البيضة المخصّبة في بطانة الرحم"},{"id":"b","text":"هما اسمان لحدث واحد"},{"id":"c","text":"الإلقاح يحدث في الرحم والتعشيش في البوق"},{"id":"d","text":"التعشيش يسبق الإلقاح دائمًا"}]'::jsonb, 'a', 'الإلقاح هو اندماج النطفة بالبويضة (يحدث عادةً في البوق) فتتكوّن البيضة المخصّبة، أمّا التعشيش فهو انغراس هذه البيضة بعد انقسامها وتنقّلها في بطانة الرحم. فهما حدثان مختلفان، والإلقاح يسبق التعشيش لا العكس، والإلقاح يقع في البوق لا في الرحم.', 4),
  ('c2a87dd0-6ed6-5a5c-ac71-77c72a3709a4', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'أمّ مرضع لاحظت غياب الطمث طوال أشهر الحمل ثمّ عودته بعده. ما التفسير الصحيح لانقطاعه أثناء الحمل؟', '[{"id":"a","text":"لأنّ المبيضين تعطّلا نهائيًّا"},{"id":"b","text":"لأنّ بطانة الرحم تبقى محفوظةً لاحتضان الجنين فلا تتساقط"},{"id":"c","text":"لأنّ الإلقاح يتكرّر كلّ شهر"},{"id":"d","text":"لأنّ النطاف تواصل تجديد البطانة"}]'::jsonb, 'b', 'أثناء الحمل تُحفظ بطانة الرحم لاحتضان الجنين ولا تتساقط، فينقطع الطمث ثمّ يعود بعد الولادة. المبيضان لم يتعطّلا نهائيًّا بدليل عودة الدورة، ولا يتكرّر الإلقاح خلال الحمل، والنطاف لا دور لها في تجديد بطانة الرحم.', 5),
  ('4996b22f-3a8c-5b1f-90c9-c14f0bc94953', 'a3806169-7a5a-5797-b569-752b5dd04edb', 'لماذا يحمل الطفل صفاتٍ من أبيه وأمّه معًا؟', '[{"id":"a","text":"لأنّ المعلومة الوراثية تأتي كلّها من الأمّ"},{"id":"b","text":"لأنّ النطفة والبويضة يحمل كلّ منهما نصف المعلومة الوراثية فتجتمعان في البيضة المخصّبة"},{"id":"c","text":"لأنّ الطفل يكتسب الصفات بعد الولادة من البيئة فقط"},{"id":"d","text":"لأنّ السائل المنوي يحمل صفات الأبوين"}]'::jsonb, 'b', 'يحمل كلّ مشيج (النطفة والبويضة) نصف المعلومة الوراثية، فعند الإلقاح تجتمع المعلومتان في البيضة المخصّبة فيرث الطفل من الأبوين معًا. المعلومة لا تأتي من الأمّ وحدها، والصفات الوراثية تُورَّث عند الإلقاح لا تُكتسب من البيئة وحدها بعد الولادة، والسائل المنوي يغذّي النطاف ويحملها ولا يحمل المعلومة بنفسه.', 6),
  ('7bec2444-166c-5816-b3d9-ecd9e08def33', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'ما المقصود بالمستضدّ (l''antigène)؟', '[{"id":"a","text":"جسم غريب يدخل الجسم فيستثير ردّ فعل مناعيًّا"},{"id":"b","text":"جسم مضادّ ينتجه الجسم للدفاع"},{"id":"c","text":"دواء يقتل البكتيريا مباشرةً"},{"id":"d","text":"خليّة دم حمراء"}]'::jsonb, 'a', 'المستضدّ جسم غريب (ميكروب أو سُمّ…) يدخل الجسم فيستثير المناعة لإنتاج أجسام مضادّة ضدّه. الجسم المضادّ هو ردّ الجسم على المستضدّ لا المستضدّ نفسه، والدواء القاتل للبكتيريا هو المضادّ الحيوي، وكريّة الدم الحمراء تنقل الأكسجين ولا علاقة لها بتعريف المستضدّ.', 1),
  ('69a3daf3-d1a8-5d46-83ac-f0db66d268c8', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'أيّ خطّ دفاعي يمثّل الحاجز الأوّل الذي يمنع دخول الميكروبات إلى الجسم؟', '[{"id":"a","text":"الجلد والأغشية المخاطية السليمة"},{"id":"b","text":"اللمفاويات T فقط"},{"id":"c","text":"الأجسام المضادّة في الدم"},{"id":"d","text":"خلايا الذاكرة المناعية"}]'::jsonb, 'a', 'الجلد والأغشية المخاطية السليمة حواجز طبيعية أولى تمنع دخول الميكروبات. أمّا اللمفاويات والأجسام المضادّة وخلايا الذاكرة فتنتمي إلى الدفاع النوعي الداخلي الذي يتدخّل بعد اختراق الميكروب للحواجز الأولى، فلا تكون هي الحاجز الأوّل.', 2),
  ('3522af16-158b-527b-af8c-6c7874578b9c', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'ما الذي يميّز المناعة النوعية عن المناعة الطبيعية (غير النوعية)؟', '[{"id":"a","text":"النوعية موجّهة ضدّ ميكروب محدّد وتترك ذاكرة، أمّا غير النوعية فعامّة وسريعة"},{"id":"b","text":"النوعية عامّة ضدّ كلّ الميكروبات بلا تمييز"},{"id":"c","text":"غير النوعية تترك ذاكرة مناعية طويلة الأمد"},{"id":"d","text":"لا فرق بينهما"}]'::jsonb, 'a', 'المناعة النوعية موجّهة ضدّ مستضدّ محدّد (بأجسام مضادّة ولمفاويات مختصّة) وتترك ذاكرة مناعية، بينما المناعة الطبيعية ردّ سريع عامّ ضدّ أيّ دخيل بلا تمييز ولا ذاكرة. لذلك العبارتان (ب) و(ج) معكوستان، والقول بعدم وجود فرق خاطئ.', 3),
  ('24f7201a-0436-5b0f-94f5-d41e71342f6c', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'صديق يخاف من زميل مصاب بفيروس السيدا (VIH) ويتجنّب مصافحته. ما التصحيح العلمي السليم؟', '[{"id":"a","text":"الخوف مبرَّر لأنّ المصافحة تنقل الفيروس"},{"id":"b","text":"المصافحة والاحتكاك اليومي العادي لا ينقلان الفيروس فلا مبرّر للإقصاء"},{"id":"c","text":"العطس ومشاركة الطعام ينقلان الفيروس بسرعة"},{"id":"d","text":"الفيروس ينتقل عبر الهواء فقط"}]'::jsonb, 'b', 'ينتقل VIH عبر الدم الملوّث وأدوات الحقن المشتركة والعلاقة الجنسية غير المحميّة ومن الأمّ إلى جنينها، أمّا المصافحة والاحتكاك العادي ومشاركة الطعام والعطس فلا تنقله، فلا مبرّر للخوف أو الإقصاء الاجتماعي. القول إنّه ينتقل بالمصافحة أو العطس أو عبر الهواء خاطئ علميًّا.', 4),
  ('a8f1275f-176b-51d2-b051-c3e72afd3988', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'طبيب أراد منح طفل سليم حمايةً وقائيةً طويلة الأمد ضدّ مرض مُعدٍ. أيّ إجراء يختار؟', '[{"id":"a","text":"التلقيح لأنّه يكسب الجسم ذاكرة مناعية تدوم طويلًا"},{"id":"b","text":"المصل لأنّه يعطي حماية دائمة"},{"id":"c","text":"المضادّ الحيوي للوقاية المستمرّة"},{"id":"d","text":"لا حاجة لأيّ إجراء وقائي"}]'::jsonb, 'a', 'الوقاية طويلة الأمد للسليم تتحقّق بالتلقيح، لأنّه يستثير الجسم ليصنع أجسامه المضادّة وخلايا ذاكرته فتدوم الحماية. المصل حماية علاجية فورية لكنّها قصيرة بلا ذاكرة، والمضادّ الحيوي علاج للعدوى البكتيرية لا وسيلة وقاية مناعية، والامتناع يترك الطفل دون حماية.', 5),
  ('f546e528-792b-5710-a28d-a7d752f30871', 'e5a638c8-433f-5c0c-9ac5-f23b7ad7c070', 'لماذا تكون الاستجابة المناعية أسرع وأقوى عند التعرّض الثاني لنفس الميكروب؟', '[{"id":"a","text":"لأنّ الميكروب يصبح أضعف من تلقاء نفسه"},{"id":"b","text":"بفضل خلايا الذاكرة المتكوّنة من التعرّض الأوّل"},{"id":"c","text":"لأنّ الجلد يصبح أكثر سمكًا"},{"id":"d","text":"لأنّ الجسم يفقد كلّ مناعته بين المرّتين"}]'::jsonb, 'b', 'خلايا الذاكرة المتكوّنة بعد التعرّض الأوّل تتعرّف على الميكروب بسرعة عند عودته فتكون الاستجابة الثانية أسرع وأقوى، وهذا أساس فعل التلقيح. الميكروب لا يضعف من تلقاء نفسه، وسُمك الجلد لا علاقة له بالأمر، والجسم لا يفقد مناعته بل يحتفظ بذاكرتها.', 6),
  ('dd8bdce6-a544-5205-aac1-ae6960b51d97', 'a990f679-0980-511b-b5ed-402261f682ee', 'أين توجد الصبغيّات (الكروموزومات) داخل الخليّة؟', '[{"id":"a","text":"في النواة"},{"id":"b","text":"في الغشاء الخلوي"},{"id":"c","text":"في السيتوبلازم خارج النواة"},{"id":"d","text":"لا توجد إلّا في خلايا الدم"}]'::jsonb, 'a', 'تحمل النواة الصبغيّات المكوّنة من الـADN الذي يحمل البرنامج الوراثي. الغشاء الخلوي يحيط بالخليّة ولا يخزّن الصبغيّات، والسيتوبلازم محيط النواة لا مقرّ الصبغيّات، والصبغيّات موجودة في كلّ الخلايا الجسمية لا في خلايا الدم وحدها.', 1),
  ('9d55b2c5-05d2-5179-a78e-b1375e9cfc25', 'a990f679-0980-511b-b5ed-402261f682ee', 'كم عدد الصبغيّات في الخليّة الجسمية الطبيعية عند الإنسان؟', '[{"id":"a","text":"23 صبغيًّا"},{"id":"b","text":"46 صبغيًّا (23 زوجًا)"},{"id":"c","text":"92 صبغيًّا"},{"id":"d","text":"عدد متغيّر من خليّة لأخرى"}]'::jsonb, 'b', 'تحتوي الخليّة الجسمية على 46 صبغيًّا مرتّبة في 23 زوجًا. أمّا 23 صبغيًّا فهو عدد المشيج (النطفة أو البويضة) أي نصف العدد، و92 ضعف العدد الطبيعي وهو غير صحيح، والعدد ثابت في الخلايا الجسمية لا متغيّر.', 2),
  ('baefc9a9-a115-5310-ae35-8b71a02b0ab9', 'a990f679-0980-511b-b5ed-402261f682ee', 'ما الذي يحدّد جنس المولود (ذكر أم أنثى)؟', '[{"id":"a","text":"نوع الصبغي الجنسي الذي تحمله النطفة (X أو Y)"},{"id":"b","text":"البويضة التي تحمل دائمًا الصبغي Y"},{"id":"c","text":"تغذية الأمّ أثناء الحمل"},{"id":"d","text":"عدد البويضات في المبيض"}]'::jsonb, 'a', 'البويضة تحمل دائمًا الصبغي X، بينما النطفة قد تحمل X (فيكون المولود أنثى XX) أو Y (فيكون ذكرًا XY)، فالنطفة هي التي تحدّد الجنس. البويضة لا تحمل Y، وتغذية الأمّ وعدد البويضات لا علاقة لهما بتحديد الجنس.', 3),
  ('38fd9564-327c-5f1b-8405-288fda1cb27f', 'a990f679-0980-511b-b5ed-402261f682ee', 'إذا كان أليل العيون البنّية (B) سائدًا وأليل العيون الزرقاء (b) متنحّيًا، فأيّ تركيب وراثي يُعطي عيونًا زرقاء؟', '[{"id":"a","text":"B//B"},{"id":"b","text":"B//b"},{"id":"c","text":"b//b"},{"id":"d","text":"أيّ تركيب يحتوي B"}]'::jsonb, 'c', 'لا تظهر الصفة المتنحّية (العيون الزرقاء) إلّا عندما يكون التركيب نقيًّا متنحّيًا b//b، لأنّ وجود أليل سائد واحد B يُظهر الصفة السائدة. لذلك B//B وB//b يعطيان عيونًا بنّية، وأيّ تركيب فيه B لا يُظهر اللون الأزرق.', 4),
  ('c9750b6b-d923-54c1-9c68-dcf226412d75', 'a990f679-0980-511b-b5ed-402261f682ee', 'أبوان عيونهما بنّية أنجبا طفلًا أزرق العينين (صفة متنحّية). ماذا نستنتج عن تركيب الأبوين؟', '[{"id":"a","text":"أنّهما نقيّان B//B"},{"id":"b","text":"أنّ كلًّا منهما هجين B//b يحمل الأليل المتنحّي"},{"id":"c","text":"أنّ أحدهما فقط يحمل الأليل المتنحّي"},{"id":"d","text":"أنّ الطفل لا ينتمي إليهما"}]'::jsonb, 'b', 'بما أنّ الطفل أزرق العينين فتركيبه b//b، فقد ورث أليلًا متنحّيًا b من كلّ من أبويه؛ ولأنّ الأبوين بنّيا العينين فلا بدّ أنّ كلًّا منهما هجين B//b يحمل الأليل المتنحّي خفيًّا. لو كانا نقيّين B//B لما ظهر الطفل أزرق، ولا يكفي أن يحمله أحدهما فقط، والاستنتاج لا يطعن في نسب الطفل.', 5),
  ('447a71f3-39ea-50cb-90e8-87208e9b2496', 'a990f679-0980-511b-b5ed-402261f682ee', 'لماذا يُعدّ الـADN «حاملًا للبرنامج الوراثي»؟', '[{"id":"a","text":"لأنّه يخزّن المعلومات التي تحدّد الصفات وتنتقل عبر المورّثات إلى الأبناء"},{"id":"b","text":"لأنّه يمدّ الخليّة بالطاقة"},{"id":"c","text":"لأنّه يكتسب الصفات من البيئة بعد الولادة"},{"id":"d","text":"لأنّه موجود في خلايا الدم فقط"}]'::jsonb, 'a', 'الـADN يحمل في تتابعه المورّثات (الجينات) التي تشفّر صفات الكائن وتنتقل من الأبوين إلى الأبناء عبر المشيجين، فهو حامل البرنامج الوراثي. تزويد الخليّة بالطاقة دور آخر لا يخصّ الـADN، والصفات الوراثية تُورَّث لا تُكتسب من البيئة وحدها، والـADN موجود في نوى كلّ الخلايا لا في خلايا الدم فقط.', 6),
  ('0054721d-54a6-5958-a1f5-ea942da944ed', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما البؤرة الزلزالية (le foyer / l''hypocentre)؟', '[{"id":"a","text":"النقطة في باطن الأرض التي ينطلق منها الزلزال"},{"id":"b","text":"النقطة على سطح الأرض فوق منشأ الزلزال مباشرةً"},{"id":"c","text":"الجهاز الذي يسجّل الموجات الزلزالية"},{"id":"d","text":"رقم على سلّم ريشتر"}]'::jsonb, 'a', 'البؤرة هي النقطة في عمق الأرض التي ينطلق منها الزلزال وتتحرّر فيها الطاقة. النقطة السطحية فوقها مباشرةً هي المركز السطحي (l''épicentre)، والجهاز المسجّل هو المرصاد الزلزالي، ورقم ريشتر يعبّر عن المقدار لا عن مكان المنشأ.', 1),
  ('2f577e55-d80e-5e93-aeba-f8bbfff45e93', '6a153e25-c76a-52ac-8403-bfee61662c58', 'بأيّ جهاز تُسجَّل الموجات الزلزالية؟', '[{"id":"a","text":"المرصاد الزلزالي (le sismographe)"},{"id":"b","text":"الميزان الحراري"},{"id":"c","text":"البوصلة"},{"id":"d","text":"المجهر"}]'::jsonb, 'a', 'المرصاد الزلزالي جهاز يكشف الموجات الزلزالية ويسجّلها في مخطّط زلزالي. الميزان الحراري يقيس درجة الحرارة، والبوصلة تحدّد الاتّجاهات، والمجهر يكبّر الأجسام الصغيرة، فلا علاقة لها بتسجيل الزلازل.', 2),
  ('fcadd697-8bdd-5a97-beb4-7a553538f9bf', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما الفرق بين شدّة الزلزال ومقداره (سلّم ريشتر)؟', '[{"id":"a","text":"المقدار يعبّر عن الطاقة المحرَّرة عند البؤرة، والشدّة تعبّر عن آثار الزلزال على المكان"},{"id":"b","text":"هما الشيء نفسه بأسماء مختلفة"},{"id":"c","text":"الشدّة تقاس بسلّم ريشتر دائمًا"},{"id":"d","text":"المقدار يصف الأضرار على المباني فقط"}]'::jsonb, 'a', 'المقدار (سلّم ريشتر) يقيس الطاقة التي يحرّرها الزلزال عند البؤرة وهو قيمة واحدة للزلزال، أمّا الشدّة فتصف آثاره ودرجة الأضرار التي تختلف من مكان لآخر. فهما ليسا الشيء نفسه، والشدّة لا تقاس بريشتر، والمقدار لا يقتصر على وصف الأضرار.', 3),
  ('0e3660a8-ac34-53ae-aa60-54f36ea39b16', '6a153e25-c76a-52ac-8403-bfee61662c58', 'ما السبب الرئيسي للزلازل التكتونية؟', '[{"id":"a","text":"تحرّك الصفائح التكتونية وتراكم الإجهادات في الصخور ثمّ تكسّرها فجأةً"},{"id":"b","text":"هطول الأمطار الغزيرة"},{"id":"c","text":"دوران الأرض حول الشمس"},{"id":"d","text":"تغيّر درجة حرارة الهواء"}]'::jsonb, 'a', 'تنشأ الزلازل التكتونية من حركة الصفائح التي تراكم إجهادات في الصخور حتّى تتجاوز مقاومتها فتنكسر فجأةً (على مستوى الفوالق) مُحرِّرةً طاقةً على شكل موجات. الأمطار ودوران الأرض حول الشمس وحرارة الهواء عوامل مناخية أو فلكية لا تسبّب الزلازل التكتونية.', 4),
  ('9b9356cd-32de-5de1-87d9-8e6b4079c178', '6a153e25-c76a-52ac-8403-bfee61662c58', 'أيّ سلوك يُعدّ من إجراءات الوقاية الصحيحة أثناء وقوع زلزال داخل قاعة الدرس؟', '[{"id":"a","text":"الاحتماء تحت طاولة متينة بعيدًا عن النوافذ والابتعاد عن الأشياء التي قد تسقط"},{"id":"b","text":"الركض بسرعة عبر الدَّرَج والتدافع نحو المخرج"},{"id":"c","text":"الوقوف قرب النوافذ الزجاجية لمراقبة ما يحدث"},{"id":"d","text":"استعمال المصعد للنزول بسرعة"}]'::jsonb, 'a', 'أثناء الزلزال يُنصح بالاحتماء تحت طاولة متينة بعيدًا عن النوافذ والأشياء التي قد تسقط حتّى تهدأ الهزّة. الركض والتدافع يسبّبان الإصابات، والوقوف قرب الزجاج خطر لتكسّره، واستعمال المصعد ممنوع لاحتمال انقطاع الكهرباء واحتجاز الأشخاص فيه.', 5),
  ('a8bc2920-578f-5b48-a48c-03d18585a81e', '6a153e25-c76a-52ac-8403-bfee61662c58', 'زلزالان لهما المقدار نفسه على سلّم ريشتر، لكنّ أحدهما خلّف أضرارًا أكبر بكثير. ما التفسير الأرجح؟', '[{"id":"a","text":"أنّ المقدار خاطئ بالضرورة في أحدهما"},{"id":"b","text":"اختلاف عمق البؤرة وقرب المركز السطحي من العمران ونوع المباني والتربة"},{"id":"c","text":"أنّ الأرض تدور بسرعة مختلفة في الموقعين"},{"id":"d","text":"أنّ الزلزال الأقوى لا يصدر موجات زلزالية"}]'::jsonb, 'b', 'بنفس المقدار قد تختلف الأضرار (الشدّة) باختلاف عمق البؤرة وقرب المركز السطحي من المناطق المأهولة ونوع التربة وجودة البناء. فاختلاف الأضرار طبيعي ولا يدلّ على خطأ في المقدار، ولا علاقة له بسرعة دوران الأرض، وكلّ زلزال يصدر موجات زلزالية.', 6),
  ('19de6d1c-e98c-5f0d-a4aa-3cab98f0e1f2', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'ما الفرق الصحيح بين الصهارة (le magma) واللابة (la lave)؟', '[{"id":"a","text":"الصهارة صخر منصهر داخل الأرض، واللابة هي الصهارة بعد خروجها إلى السطح"},{"id":"b","text":"اللابة داخل الخزّان والصهارة على السطح"},{"id":"c","text":"هما اسمان لغازات بركانية"},{"id":"d","text":"الصهارة صلبة دائمًا واللابة سائلة دائمًا داخل الأرض"}]'::jsonb, 'a', 'الصهارة صخر منصهر يوجد في باطن الأرض (في الخزّان الصهاري)، وعندما تخرج إلى السطح عبر الفوّهة تُسمّى لابة. فالعبارة (ب) معكوسة، وهما ليستا غازات، والصهارة ليست صلبة بل منصهرة في الباطن.', 1),
  ('6d8dd85a-44f3-5d4f-a156-e2b44dba1e89', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'أيّ هذه المكوّنات يمثّل جزءًا من بنية البركان؟', '[{"id":"a","text":"الخزّان الصهاري والمدخنة والفوّهة"},{"id":"b","text":"البؤرة والمركز السطحي"},{"id":"c","text":"الليثوسفير والأسثينوسفير فقط"},{"id":"d","text":"النواة والوشاح فقط"}]'::jsonb, 'a', 'يتكوّن البركان من خزّان صهاري في العمق تصعد منه الصهارة عبر مدخنة لتخرج من فوّهة في القمّة. البؤرة والمركز السطحي مصطلحان خاصّان بالزلازل، والليثوسفير والوشاح والنواة طبقات الأرض لا أجزاء بنية البركان نفسه.', 2),
  ('b40d85ce-4f72-5e76-ad6a-66a431625b5c', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'بركان صهارته لزجة جدًّا وغنيّة بالغازات. ما نوع ثورانه المتوقّع؟', '[{"id":"a","text":"ثوران انفجاري عنيف لأنّ الغازات تُحتجَز في صهارة لزجة ثمّ تنطلق فجأةً"},{"id":"b","text":"ثوران انسيابي هادئ تسيل فيه اللابة ببطء"},{"id":"c","text":"لا يثور أبدًا"},{"id":"d","text":"يخرج ماءً فقط دون لابة"}]'::jsonb, 'a', 'اللزوجة العالية تحبس الغازات داخل الصهارة فيرتفع الضغط حتّى تنفجر فجأةً (ثوران انفجاري) مع قذف رماد ومواد صلبة. أمّا الثوران الانسيابي الهادئ فيخصّ الصهارة السيّالة قليلة الغازات، والقول إنّه لا يثور أو يخرج ماءً فقط غير صحيح.', 3),
  ('fd260756-dd88-59d3-b13e-8124a4a396df', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'ما المقذوفات التي يطرحها البركان أثناء الثوران؟', '[{"id":"a","text":"لابة وغازات ومواد صلبة (رماد وقذائف صخرية)"},{"id":"b","text":"ماء عذب فقط"},{"id":"c","text":"هواء بارد فقط"},{"id":"d","text":"صخور رسوبية مترسّبة من البحر"}]'::jsonb, 'a', 'تشمل المقذوفات البركانية اللابة السائلة والغازات والمواد الصلبة من رماد وقذائف صخرية. البركان لا يطرح ماءً عذبًا أو هواءً باردًا، والصخور الرسوبية تتكوّن بالترسّب لا بالثوران البركاني.', 4),
  ('87a5769e-52d0-5d9f-8c58-7dc27461d63b', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'لماذا تتراصف معظم البراكين والزلازل في الأحزمة نفسها على الكرة الأرضية؟', '[{"id":"a","text":"لأنّها ترتبط معًا بحدود الصفائح التكتونية حيث يكثر النشاط الباطني"},{"id":"b","text":"بمحض الصدفة دون سبب"},{"id":"c","text":"لأنّ الأمطار تتركّز في تلك المناطق"},{"id":"d","text":"لأنّها تتبع خطوط الطول والعرض"}]'::jsonb, 'a', 'تتركّز البراكين والزلازل عند حدود الصفائح التكتونية لأنّ حركة الصفائح هناك تتيح صعود الصهارة وتراكم الإجهادات، فيتراصفان في الأحزمة نفسها (مثل حزام النار). فليس الأمر صدفةً ولا مرتبطًا بالأمطار أو بخطوط الطول والعرض.', 5),
  ('19c75169-488f-5a87-baef-d5527ce47843', '4b02b0fb-e1da-5f9c-b8f5-b734cbfc6801', 'وُجد في إقليم تربة بركانية خصبة وينابيع ماء ساخنة ومحطّة طاقة جيوحرارية. ما العلاقة الصحيحة؟', '[{"id":"a","text":"أنّها فوائد مرتبطة بالنشاط البركاني والحرارة الباطنية"},{"id":"b","text":"أنّها أدلّة على غياب أيّ نشاط بركاني"},{"id":"c","text":"أنّها مجرّد صدف لا علاقة بينها"},{"id":"d","text":"أنّها مخاطر فقط دون أيّ فائدة"}]'::jsonb, 'a', 'للنشاط البركاني فوائد: التربة البركانية خصبة للزراعة، والحرارة الباطنية تسخّن المياه فتنشأ ينابيع ساخنة وتُستغلّ في الطاقة الجيوحرارية. فهذه المعطيات مترابطة بالنشاط البركاني لا دليل غيابه ولا صدفة، وللبراكين فوائد إلى جانب مخاطرها.', 6),
  ('295cbe5d-8677-5de4-b81a-0047e0f7b765', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما الترتيب الصحيح لطبقات الكرة الأرضية من السطح إلى المركز؟', '[{"id":"a","text":"القشرة ثمّ الوشاح ثمّ النواة"},{"id":"b","text":"النواة ثمّ القشرة ثمّ الوشاح"},{"id":"c","text":"الوشاح ثمّ النواة ثمّ القشرة"},{"id":"d","text":"القشرة ثمّ النواة ثمّ الوشاح"}]'::jsonb, 'a', 'تتكوّن الأرض من السطح إلى المركز من القشرة (الطبقة الخارجية الرقيقة) ثمّ الوشاح (الأسمك) ثمّ النواة في المركز. باقي الترتيبات تخلط بين مواقع الطبقات؛ فالنواة في المركز لا في الأعلى، والوشاح بين القشرة والنواة.', 1),
  ('4216a8ee-e2c9-5bb9-854e-d4560c74f331', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما الليثوسفير (la lithosphère)؟', '[{"id":"a","text":"الطبقة الصلبة الخارجية المجزّأة إلى صفائح تكتونية"},{"id":"b","text":"نواة الأرض السائلة"},{"id":"c","text":"طبقة الغازات المحيطة بالأرض"},{"id":"d","text":"المحيطات وحدها"}]'::jsonb, 'a', 'الليثوسفير هو الغلاف الصلب الخارجي للأرض (القشرة وأعلى الوشاح) المجزّأ إلى صفائح تكتونية تطفو فوق الأسثينوسفير اللدن. وهو ليس النواة السائلة، ولا الغلاف الجوّي الغازي، ولا المحيطات وحدها.', 2),
  ('87cd9971-1945-5aca-9bc6-1bb6319f6c92', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ماذا يحدث عند الظهرات المحيطية (les dorsales)؟', '[{"id":"a","text":"تصعد الصهارة وتتكوّن قشرة محيطية جديدة فيتوسّع المحيط"},{"id":"b","text":"تُدمَّر القشرة المحيطية وتغوص في الوشاح"},{"id":"c","text":"تتوقّف الصفائح عن الحركة تمامًا"},{"id":"d","text":"تتكوّن الجبال القارّية فقط"}]'::jsonb, 'a', 'عند الظهرات المحيطية تصعد الصهارة وتبرد فتتكوّن قشرة محيطية جديدة تدفع الصفائح جانبًا فيتوسّع قعر المحيط. أمّا تدمير القشرة وغوصها فيحدث في مناطق الطمر (الاندساس) لا عند الظهرات، والصفائح هناك تتباعد لا تتوقّف.', 3),
  ('437ac1a1-b49e-5e32-bf73-75081e9bb4b5', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'صفيحة تحمل قشرة محيطية اقتربت من صفيحة تحمل قشرة قارّية. ماذا يحدث عند الحدّ بينهما؟', '[{"id":"a","text":"تغوص القشرة المحيطية الأثقل تحت القارّية في منطقة طمر (اندساس)"},{"id":"b","text":"تغوص القشرة القارّية الأخفّ تحت المحيطية"},{"id":"c","text":"تتباعدان وتتكوّن ظهرة جديدة"},{"id":"d","text":"لا يحدث أيّ تفاعل بينهما"}]'::jsonb, 'a', 'القشرة المحيطية أكثف وأثقل من القارّية، فعند تقاربهما تغوص المحيطية تحت القارّية في منطقة طمر (اندساس) مصحوبة بزلازل وبراكين. فلا تغوص القارّية الأخفّ، وهذا حدّ متقارب لا متباعد، والتفاعل واضح لا منعدم.', 4),
  ('c6005ff6-2e9b-57a8-b869-4ee7ec9899fb', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'وُجدت متحجّرات لكائن واحد على سواحل إفريقيا وأمريكا الجنوبية معًا. ما أفضل تفسير لذلك؟', '[{"id":"a","text":"أنّ القارّتين كانتا متّصلتين سابقًا ثمّ تباعدتا بانجراف القارّات"},{"id":"b","text":"أنّ الكائن كان يطير ويعبر المحيط الأطلسي"},{"id":"c","text":"أنّها صدفة لا دلالة لها"},{"id":"d","text":"أنّ القارّتين ثابتتان تمامًا منذ نشأة الأرض"}]'::jsonb, 'a', 'وجود متحجّرات الكائن نفسه على ضفّتي المحيط دليل قدّمه فاجنر على أنّ القارّتين كانتا متّصلتين ثمّ تباعدتا بانجراف القارّات (حركة الصفائح). تفسير الطيران أو الصدفة لا يصمد، والقارّات ليست ثابتة بل تتحرّك مع صفائحها.', 5),
  ('b0398a51-656f-5a9a-963b-f07a8c0c947d', 'cb1b85d9-22fb-5894-9543-b68c3ba9aa54', 'ما العلاقة بين حركة الصفائح والزلازل والبراكين؟', '[{"id":"a","text":"تتركّز الزلازل والبراكين غالبًا عند حدود الصفائح حيث يكثر النشاط الباطني"},{"id":"b","text":"لا علاقة بين حركة الصفائح والزلازل والبراكين"},{"id":"c","text":"تتركّز الزلازل والبراكين في مراكز الصفائح بعيدًا عن حدودها"},{"id":"d","text":"تحدث الزلازل فقط حيث لا توجد براكين أبدًا"}]'::jsonb, 'a', 'تتركّز الزلازل والبراكين عند حدود الصفائح (تباعد أو تقارب أو انزلاق) لأنّ حركتها هناك تحرّر طاقةً وتتيح صعود الصهارة، ولذلك يتراصفان في الأحزمة نفسها مثل حزام النار. فالعلاقة وثيقة، والنشاط يكثر عند الحدود لا في مراكز الصفائح، والزلازل والبراكين كثيرًا ما يجتمعان في المنطقة نفسها.', 6)
ON CONFLICT (id) DO UPDATE SET
  exercise_id = EXCLUDED.exercise_id,
  prompt = EXCLUDED.prompt,
  options = EXCLUDED.options,
  correct_option = EXCLUDED.correct_option,
  explanation = EXCLUDED.explanation,
  display_order = EXCLUDED.display_order;

